"use client";

export type TimeRange = "LIVE" | "1H" | "4H" | "24H" | "7D" | "30D";

const ALL: TimeRange[] = ["LIVE", "1H", "4H", "24H", "7D", "30D"];

export function RangeSelector({
  value,
  onChange,
  /** Pi UI only exposes short-range windows — long history lives on cloud. */
  options = ALL,
}: {
  value: TimeRange;
  onChange?: (next: TimeRange) => void;
  options?: TimeRange[];
}) {
  return (
    <div className="v-time-ranges" role="tablist" aria-label="time range">
      {options.map((r) => {
        const active = r === value;
        return (
          <a
            key={r}
            href={`#${r.toLowerCase()}`}
            className={active ? "active" : ""}
            role="tab"
            aria-selected={active}
            onClick={(e) => {
              e.preventDefault();
              onChange?.(r);
            }}
          >
            {r}
          </a>
        );
      })}
    </div>
  );
}
