"use client";

import type { AlertItem } from "../data/types";

const SEV_CLS = { info: "a", warn: "w", err: "e" } as const;
const SEV_LABEL: Record<AlertItem["severity"], string> = {
  info: "info",
  warn: "warn",
  err: "crit",
};

export function AlertList({
  alerts,
  onTap,
}: {
  alerts: AlertItem[];
  onTap?: (alert: AlertItem) => void;
}) {
  return (
    <div className="alerts-list" role="list">
      {alerts.map((a) => (
        <button
          type="button"
          key={a.id}
          className="alert-row"
          onClick={() => onTap?.(a)}
          role="listitem"
          style={{ appearance: "none", background: "var(--bg-1)", border: "none", textAlign: "left", cursor: "pointer", color: "inherit" }}
        >
          <span className="ts">{a.ts}</span>
          <span className={`sev ${SEV_CLS[a.severity]}`}>{SEV_LABEL[a.severity]}</span>
          <span className="msg">{a.message}</span>
          <span className="ch mono">{a.chamberId}</span>
        </button>
      ))}
    </div>
  );
}
