import { useMemo, useRef, useState } from "react";
import {
  CloudSyncIndicator,
  CONTAMINATIONS,
  CONTAMINANT_REFERENCE,
  PageHeader,
  PI_HEALTH,
  type ContaminationStub,
} from "@sporeprint/design";

const OUTCOME_TONE: Record<ContaminationStub["outcome"], "signal" | "warn" | "err" | "accent"> = {
  treated: "signal",
  quarantined: "warn",
  lost: "err",
  open: "accent",
};

interface CheckEntry {
  ts: string;
  origin: "drop" | "manual";
  fileLabel: string;
  status: "pending" | "complete" | "failed";
  result?: { type: string; confidence: number };
}

export function ContaminationPage() {
  const [dragging, setDragging] = useState(false);
  const [checks, setChecks] = useState<CheckEntry[]>([
    { ts: "14:09:08", origin: "manual", fileLabel: "ch-021_corner_1845.jpg", status: "complete", result: { type: "Trichoderma viride", confidence: 0.94 } },
    { ts: "13:42:21", origin: "drop", fileLabel: "ch-009_film_0914.jpg", status: "complete", result: { type: "Cobweb (Cladobotryum)", confidence: 0.81 } },
    { ts: "12:11:55", origin: "drop", fileLabel: "ch-014_caps_1102.jpg", status: "complete", result: { type: "Bacterial blotch", confidence: 0.72 } },
  ]);
  const [rcaChamber, setRcaChamber] = useState<string>(CONTAMINATIONS[0]?.chamberId ?? "");
  const [rcaSubstrate, setRcaSubstrate] = useState("");
  const [rcaCycle, setRcaCycle] = useState("");
  const [rcaWindow, setRcaWindow] = useState("");
  const [rcaSummary, setRcaSummary] = useState("");
  const fileRef = useRef<HTMLInputElement>(null);

  const running = useMemo(() => checks.filter((c) => c.status === "pending").length, [checks]);

  function pushCheck(label: string, origin: CheckEntry["origin"]) {
    const ts = new Date().toLocaleTimeString("en-GB", { hour12: false });
    const entry: CheckEntry = { ts, origin, fileLabel: label, status: "pending" };
    setChecks((prev) => [entry, ...prev].slice(0, 12));
    // Simulate async response.
    setTimeout(() => {
      const types = ["Trichoderma viride", "Cobweb", "Penicillium", "Aspergillus"];
      const type = types[Math.floor(Math.random() * types.length)] ?? types[0]!;
      setChecks((prev) =>
        prev.map((c) =>
          c.ts === ts
            ? { ...c, status: "complete", result: { type, confidence: 0.6 + Math.random() * 0.35 } }
            : c,
        ),
      );
    }, 850);
  }

  function handleDrop(e: React.DragEvent) {
    e.preventDefault();
    setDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file) pushCheck(file.name, "drop");
  }

  function handlePick(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (file) pushCheck(file.name, "manual");
    if (fileRef.current) fileRef.current.value = "";
  }

  function submitRca() {
    // Local-only stub — would post to /contamination/{id}/root-cause.
    setRcaSubstrate("");
    setRcaCycle("");
    setRcaWindow("");
    setRcaSummary("");
  }

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>track</span>
          <span className="sep">/</span>
          <b className="accent">contamination</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Track"
        title="Contamination"
        italic={false}
        meta={
          <span>
            local-first event log · {CONTAMINATIONS.length} events · {running} BYOK Claude check{running === 1 ? "" : "s"} in flight
          </span>
        }
        right={<button className="t-btn-primary" type="button" onClick={() => fileRef.current?.click()}>capture + identify →</button>}
      />

      <div className="shell-body pi">
        <main className="stack-14">
          <section
            className={`side-panel${dragging ? " tone-accent" : ""}`}
            onDragOver={(e) => { e.preventDefault(); setDragging(true); }}
            onDragLeave={() => setDragging(false)}
            onDrop={handleDrop}
            style={{
              background: dragging ? "var(--accent-soft)" : undefined,
            }}
          >
            <div className="head">Drag-drop · BYOK Claude check</div>
            <div
              className="stack-8"
              style={{
                border: "1px dashed var(--border)",
                borderRadius: "var(--r-md)",
                padding: 28,
                textAlign: "center",
              }}
            >
              <span className="t-display-sm" style={{ fontStyle: "normal" }}>
                {dragging ? "release to upload" : "drop a frame to identify"}
              </span>
              <span className="t-mono-sm">
                runs against the on-Pi BYOK Claude key when set · falls back to local CNN otherwise
              </span>
              <input
                ref={fileRef}
                type="file"
                accept="image/*"
                onChange={handlePick}
                style={{ display: "none" }}
              />
              <div className="row-10" style={{ justifyContent: "center", marginTop: 4 }}>
                <button type="button" className="t-back-btn" onClick={() => fileRef.current?.click()}>browse files</button>
                <button type="button" className="t-back-btn" onClick={() => pushCheck("(camera grab)", "manual")}>grab from camera</button>
              </div>
            </div>
          </section>

          <section className="side-panel">
            <div className="head">Response log · last {checks.length}</div>
            <table className="data-table">
              <thead>
                <tr>
                  <th scope="col">Time</th>
                  <th scope="col">Source</th>
                  <th scope="col">File</th>
                  <th scope="col">Result</th>
                  <th scope="col" className="num">Confidence</th>
                  <th scope="col">Status</th>
                </tr>
              </thead>
              <tbody>
                {checks.map((c) => (
                  <tr key={c.ts}>
                    <td className="mono-cell">{c.ts}</td>
                    <td>
                      <span className={`status-pill ${c.origin === "drop" ? "signal" : "accent"}`}>{c.origin}</span>
                    </td>
                    <td className="mono-cell">{c.fileLabel}</td>
                    <td>{c.result ? c.result.type : "—"}</td>
                    <td className="num mono-cell">
                      {c.result ? `${(c.result.confidence * 100).toFixed(0)}%` : "—"}
                    </td>
                    <td>
                      <span
                        className={`status-pill ${
                          c.status === "complete" ? "accent" : c.status === "pending" ? "warn" : "err"
                        }`}
                      >
                        {c.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </section>

          <div className="gallery">
            {CONTAMINATIONS.map((c) => (
              <article key={c.id} className="frame">
                <div className="preview">
                  <span style={{ position: "relative", zIndex: 1 }}>[snapshot · {c.chamberId}]</span>
                </div>
                <div className="meta">
                  <div className="row-between-baseline">
                    <span className="id">{c.chamberId}</span>
                    <span className={`status-pill ${OUTCOME_TONE[c.outcome]}`}>{c.outcome}</span>
                  </div>
                  <span className="species">{c.type}</span>
                  <span className="ts">{c.ts} · confidence {(c.confidence * 100).toFixed(0)}%</span>
                </div>
              </article>
            ))}
          </div>
        </main>

        <aside className="stack-14">
          <section className="side-panel">
            <div className="head">Root-cause analysis</div>
            <p className="t-body-sm">
              Capture every contam event with substrate, sterilisation, and env window so the next batch
              has a hypothesis to push back against.
            </p>
            <label className="form-field">
              <span className="form-label">chamber</span>
              <select
                className="t-input"
                value={rcaChamber}
                onChange={(e) => setRcaChamber(e.target.value)}
              >
                {CONTAMINATIONS.map((c) => (
                  <option key={c.id} value={c.chamberId}>{c.chamberId} · {c.type}</option>
                ))}
              </select>
            </label>
            <label className="form-field">
              <span className="form-label">substrate batch</span>
              <input
                className="t-input"
                placeholder="MM-2026-04-A · oak pellets · 1.2 lb"
                value={rcaSubstrate}
                onChange={(e) => setRcaSubstrate(e.target.value)}
              />
            </label>
            <label className="form-field">
              <span className="form-label">sterilisation cycle</span>
              <input
                className="t-input"
                placeholder="Pressure cooker 90 min @ 15 psi"
                value={rcaCycle}
                onChange={(e) => setRcaCycle(e.target.value)}
              />
            </label>
            <label className="form-field">
              <span className="form-label">env window</span>
              <input
                className="t-input"
                placeholder="RH 96% sustained 36h · CO2 700ppm · 70°F"
                value={rcaWindow}
                onChange={(e) => setRcaWindow(e.target.value)}
              />
            </label>
            <label className="form-field">
              <span className="form-label">summary</span>
              <textarea
                className="t-input"
                rows={3}
                placeholder="Likely under-sterilised batch (psi sag) + high RH gave the foothold."
                value={rcaSummary}
                onChange={(e) => setRcaSummary(e.target.value)}
                style={{ resize: "vertical" }}
              />
            </label>
            <button
              type="button"
              className="t-btn-primary"
              style={{ alignSelf: "flex-start" }}
              onClick={submitRca}
              disabled={!rcaChamber || !rcaSummary.trim()}
            >
              record analysis →
            </button>
          </section>

          <section className="side-panel">
            <div className="head">Reference library</div>
            {CONTAMINANT_REFERENCE.slice(0, 3).map((r) => (
              <div
                key={r.key}
                className="stack-4"
                style={{ background: "var(--bg-2)", border: "1px solid var(--border-soft)", borderRadius: "var(--r-sm)", padding: 12 }}
              >
                <div className="row-between-baseline">
                  <span className="t-mono">{r.name}</span>
                  <span className={`status-pill ${r.severity}`}>{r.severity === "err" ? "critical" : "warn"}</span>
                </div>
                <span className="t-mono-sm t-muted">{r.tagline}</span>
                <span className="t-body-sm">{r.identify}</span>
              </div>
            ))}
          </section>
        </aside>
      </div>
    </>
  );
}
