function YieldEstimator({
  s,
  grams,
  onGrams,
}: {
  s: SpeciesEntry;
  grams: string;
  onGrams: (v: string) => void;
}) {
  const blockGrams = Math.max(0, parseInt(grams, 10) || 0);
  // Use cultivationNotes + difficulty to derive a yield range.
  const beRange: [number, number] =
    s.difficulty === "beginner" ? [0.9, 1.2] :
    s.difficulty === "intermediate" ? [0.6, 0.9] :
    [0.4, 0.7];
  const lo = Math.round(blockGrams * beRange[0]);
  const hi = Math.round(blockGrams * beRange[1]);

  return (
    <Section label="Yield estimator">
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          gap: 14,
        }}
      >
        <label style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <span className="t-label">Block size (g)</span>
          <input
            type="number"
            className="t-input"
            min={0}
            value={grams}
            onChange={(e) => onGrams(e.target.value)}
            onClick={(e) => e.stopPropagation()}
            style={{ width: 140 }}
          />
        </label>
        <span className="t-mono-sm">×</span>
        <span className="t-mono-sm">
          BE {Math.round(beRange[0] * 100)}–{Math.round(beRange[1] * 100)}%
        </span>
        <span className="t-mono-sm">=</span>
        <span className="t-num">
          {lo.toLocaleString()}–{hi.toLocaleString()} g
        </span>
        <span className="t-mono-sm" style={{ color: "var(--text-3)" }}>
          (~{(lo / 454).toFixed(1)}–{(hi / 454).toFixed(1)} lb wet)
        </span>
      </div>
    </Section>
  );
}

