import {
  CloudSyncIndicator,
  DataTable,
  PI_HEALTH,
  PI_LOCAL_FLEET,
  PageHeader,
} from "@sporeprint/design";

const LATEST_FIRMWARE = "2.14.1";
const OUTDATED_OVERRIDES: Record<string, string> = {
  "CH-002": "2.13.4",
  "CH-005": "2.13.4",
};

export function FirmwarePage() {
  const rows = PI_LOCAL_FLEET.map((c) => {
    const current = OUTDATED_OVERRIDES[c.id] ?? c.firmware;
    const updateAvailable = current !== LATEST_FIRMWARE;
    return { id: c.id, current, updateAvailable, species: c.species, rack: c.rack };
  });

  const updateCount = rows.filter((r) => r.updateAvailable).length;

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>system</span>
          <span className="sep">/</span>
          <b className="accent">firmware</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Pi-mediated distribution"
        title="Firmware"
        italic={false}
        meta={
          <span>
            {updateCount > 0
              ? `${updateCount} of ${rows.length} chambers have updates available`
              : `all ${rows.length} chambers running ${LATEST_FIRMWARE}`}
          </span>
        }
        right={
          <button type="button" disabled={updateCount === 0} className="t-btn-primary">
            {updateCount > 0 ? `update ${updateCount} →` : "all up to date"}
          </button>
        }
      />

      <div className="shell-body single">
        <main className="stack-16">
          <DataTable
            rowKey={(r) => r.id}
            columns={[
              { key: "id", header: "Chamber", render: (r) => <span className="mono-cell">{r.id}</span> },
              { key: "species", header: "Species", render: (r) => <span className="binomial-cell">{r.species.binomial}</span> },
              { key: "rack", header: "Rack", render: (r) => <span className="mono-cell">R{r.rack.rack}·S{r.rack.shelf}</span> },
              { key: "current", header: "Current", render: (r) => (
                <span className={`status-pill ${r.updateAvailable ? "warn" : "signal"}`}>v{r.current}</span>
              ) },
              { key: "latest", header: "Latest", render: () => <span className="mono-cell">v{LATEST_FIRMWARE}</span> },
              { key: "action", header: "", align: "right", render: (r) => r.updateAvailable
                  ? <button type="button" className="t-link-cta">→ update</button>
                  : <span className="t-mono-sm">current</span> },
            ]}
            rows={rows}
          />

          <p className="t-mono-sm">
            firmware images are downloaded by the Pi from the cloud and pushed to chambers over MQTT.
            cloud → device OTA without the Pi mediating is not supported.
          </p>
        </main>
      </div>
    </>
  );
}
