import type { CSSProperties } from "react";

export type LiveDotKind = "accent" | "signal" | "warn" | "err";

export function LiveDot({ kind = "accent", style }: { kind?: LiveDotKind; style?: CSSProperties }) {
  const cls = kind === "accent" ? "live-dot" : `live-dot ${kind}`;
  return <span className={cls} style={style} aria-hidden />;
}

export function LivePill({ label = "live", kind = "accent" }: { label?: string; kind?: LiveDotKind }) {
  return (
    <span className="live">
      <LiveDot kind={kind} />
      {label}
    </span>
  );
}
