import { useMemo, useState } from "react";
import {
  AUTOMATION_RULES,
  CloudSyncIndicator,
  PI_HEALTH,
  PageHeader,
  type RuleStub,
} from "@sporeprint/design";

type AuditAction = "enabled" | "suspended" | "edited" | "fired" | "cooldown";
interface AuditEntry {
  ts: string;
  ruleId: string;
  ruleName: string;
  action: AuditAction;
  operator: string;
  detail: string;
}

const AUDIT_LOG: AuditEntry[] = [
  { ts: "14:31:08", ruleId: "r:1", ruleName: "Mister · humidity guardrail", action: "fired", operator: "engine", detail: "CH-007 · 91.6% → 0.4s burst" },
  { ts: "14:25:00", ruleId: "r:2", ruleName: "FAE · co₂ ceiling", action: "fired", operator: "engine", detail: "CH-007 · 870ppm → fan 30s" },
  { ts: "14:18:02", ruleId: "r:1", ruleName: "Mister · humidity guardrail", action: "cooldown", operator: "engine", detail: "CH-014 · skipped (90s cooldown)" },
  { ts: "12:14:33", ruleId: "r:7", ruleName: "Setpoint adjust · pinning", action: "suspended", operator: "Brandon", detail: "Disabled pending strain-specific tuning" },
  { ts: "11:09:00", ruleId: "r:5", ruleName: "Pump · res low", action: "fired", operator: "engine", detail: "CH-014 · 18% → 60s pump" },
  { ts: "09:42:11", ruleId: "r:1", ruleName: "Mister · humidity guardrail", action: "edited", operator: "Brandon", detail: "Threshold 90% → 92%" },
  { ts: "09:14:02", ruleId: "r:6", ruleName: "Contam quarantine", action: "enabled", operator: "Brandon", detail: "Re-armed after CH-013 cleanup" },
];

const ACTION_TONE: Record<AuditAction, "accent" | "warn" | "err" | "signal" | "idle"> = {
  enabled: "accent",
  suspended: "warn",
  edited: "signal",
  fired: "accent",
  cooldown: "idle",
};

export function AutomationPage() {
  const active = AUTOMATION_RULES.filter((r) => r.active).length;
  const [selectedId, setSelectedId] = useState<string>(AUTOMATION_RULES[0]?.id ?? "");
  const [suspendedAt, setSuspendedAt] = useState<Record<string, number>>({});

  const selected = useMemo(
    () => AUTOMATION_RULES.find((r) => r.id === selectedId) ?? AUTOMATION_RULES[0]!,
    [selectedId],
  );

  function handleSuspend(id: string) {
    setSuspendedAt((prev) => ({ ...prev, [id]: Date.now() + 5 * 60 * 1000 }));
  }

  const totalFires7d = AUTOMATION_RULES.reduce((n, r) => n + r.fires7d, 0);
  const skippedRecent = AUTOMATION_RULES.reduce(
    (n, r) => n + r.recentFires.filter((f) => f.outcome === "skipped").length,
    0,
  );

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>control</span>
          <span className="sep">/</span>
          <b className="accent">automation</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Control"
        title="Automation rules"
        italic={false}
        meta={
          <span>
            {active} of {AUTOMATION_RULES.length} active · {totalFires7d.toLocaleString()} fires · 7d ·{" "}
            {skippedRecent} cooldown-skipped recently
          </span>
        }
        right={<button className="t-back-btn" type="button">authoring → cloud</button>}
      />

      <div className="shell-body pi">
        <main className="stack-14">
          {AUTOMATION_RULES.map((r) => (
            <RuleCard
              key={r.id}
              rule={r}
              selected={selectedId === r.id}
              onSelect={() => setSelectedId(r.id)}
              suspendedUntil={suspendedAt[r.id]}
              onSuspend={() => handleSuspend(r.id)}
            />
          ))}
          <p className="t-mono-sm">
            to author or change a rule, open{" "}
            <a href="https://sporeprint.ai/automation" className="t-link-cta" style={{ display: "inline" }}>
              sporeprint.ai/automation
            </a>
            . Pi can suspend per-chamber from this view, but rule edits sync from the cloud.
          </p>
        </main>

        <aside className="stack-14">
          <section className="side-panel">
            <div className="head">Recent firings · {selected.name}</div>
            <span className="t-mono-sm">{selected.recentFires.length} firings tracked over the last 24h</span>
            {selected.recentFires.length > 0 ? (
              <table className="data-table">
                <thead>
                  <tr>
                    <th scope="col">Time</th>
                    <th scope="col">Chamber</th>
                    <th scope="col">Value</th>
                    <th scope="col">Outcome</th>
                  </tr>
                </thead>
                <tbody>
                  {selected.recentFires.map((f, i) => (
                    <tr key={`${f.ts}-${i}`}>
                      <td className="mono-cell">{f.ts}</td>
                      <td className="mono-cell">{f.chamberId}</td>
                      <td className="mono-cell">{f.value}</td>
                      <td>
                        <span
                          className={`status-pill ${
                            f.outcome === "fired" ? "accent" : f.outcome === "skipped" ? "idle" : "warn"
                          }`}
                        >
                          {f.outcome}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <p className="t-body-sm">No firings yet · the rule has not tripped in the last 24h.</p>
            )}
          </section>

          <section className="side-panel">
            <div className="head">Audit log</div>
            <span className="t-mono-sm">last 24h of operator + engine actions across all rules</span>
            <ul className="stack-10" style={{ listStyle: "none", padding: 0, margin: 0 }}>
              {AUDIT_LOG.map((e, i) => (
                <li
                  key={`${e.ts}-${i}`}
                  className="stack-4"
                  style={{
                    padding: "12px 14px",
                    background: "var(--bg-2)",
                    border: "1px solid var(--border-soft)",
                    borderRadius: "var(--r-sm)",
                  }}
                >
                  <div className="row-between">
                    <span className="t-mono-sm">{e.ts} · {e.operator}</span>
                    <span className={`status-pill ${ACTION_TONE[e.action]}`}>{e.action}</span>
                  </div>
                  <span className="t-body-sm t-soft">{e.ruleName}</span>
                  <span className="t-mono-sm t-muted">↳ {e.detail}</span>
                </li>
              ))}
            </ul>
          </section>
        </aside>
      </div>
    </>
  );
}

function RuleCard({
  rule,
  selected,
  onSelect,
  suspendedUntil,
  onSuspend,
}: {
  rule: RuleStub;
  selected: boolean;
  onSelect: () => void;
  suspendedUntil: number | undefined;
  onSuspend: () => void;
}) {
  const remaining = suspendedUntil ? Math.max(0, suspendedUntil - Date.now()) : 0;
  const remainingS = Math.ceil(remaining / 1000);
  const isSuspended = remaining > 0;
  return (
    <section
      className={`side-panel${selected ? " tone-accent" : ""}`}
      onClick={onSelect}
      style={{ cursor: "pointer" }}
    >
      <div className="row-between-baseline">
        <div className="stack-4" style={{ minWidth: 0 }}>
          <span className="t-eyebrow" style={{ marginBottom: 0 }}>{rule.scope}</span>
          <h2 className="t-display-sm" style={{ fontStyle: "normal" }}>{rule.name}</h2>
        </div>
        <div className="row-10">
          <span className={`status-pill ${rule.active && !isSuspended ? "accent" : isSuspended ? "warn" : "idle"}`}>
            {isSuspended ? `suspend ${remainingS}s` : rule.active ? "active" : "suspended"}
          </span>
          <input
            type="checkbox"
            className="toggle"
            defaultChecked={rule.active}
            onClick={(e) => e.stopPropagation()}
          />
        </div>
      </div>
      <p className="t-body-sm">{rule.description}</p>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(150px, 1fr))", gap: 10 }}>
        <Stat label="metric" value={rule.metric} />
        <Stat label="condition" value={rule.condition} />
        <Stat label="last fired" value={rule.lastFired} />
        <Stat label="fires · 7d" value={rule.fires7d.toLocaleString()} />
        <Stat label="cooldown" value={`${rule.cooldownSec}s`} />
      </div>
      <div className="row-10" style={{ marginTop: 4 }}>
        <button
          type="button"
          className="t-back-btn"
          onClick={(e) => { e.stopPropagation(); onSuspend(); }}
          disabled={isSuspended}
        >
          {isSuspended ? `suspended · ${remainingS}s` : "suspend 5m"}
        </button>
        <button
          type="button"
          className="t-back-btn"
          onClick={(e) => e.stopPropagation()}
        >
          view fires →
        </button>
      </div>
    </section>
  );
}

function Stat({ label, value }: { label: string; value: string }) {
  return (
    <div
      className="stack-4"
      style={{ background: "var(--bg-2)", border: "1px solid var(--border-soft)", borderRadius: "var(--r-sm)", padding: 12 }}
    >
      <span className="t-label">{label}</span>
      <span className="t-mono">{value}</span>
    </div>
  );
}
