"use client";
import type { ReactNode } from "react";

type ChipTone = "accent" | "signal" | "warn" | "err" | "idle" | "default";

export function Chip({
  active = false,
  count,
  tone = "default",
  onClick,
  type = "button",
  children,
  ariaLabel,
}: {
  active?: boolean;
  count?: number;
  tone?: ChipTone;
  onClick?: () => void;
  type?: "button" | "submit";
  children: ReactNode;
  ariaLabel?: string;
}) {
  const cls = active
    ? `status-pill ${tone === "default" ? "accent" : tone}`
    : "status-pill idle";
  return (
    <button
      type={type}
      className={cls}
      aria-pressed={active}
      aria-label={ariaLabel}
      onClick={onClick}
      style={{ cursor: "pointer", appearance: "none", padding: "6px 14px" }}
    >
      <span>{children}</span>
      {count !== undefined && (
        <span className="t-mono-sm" style={{ marginLeft: 6 }}>
          {count}
        </span>
      )}
    </button>
  );
}

export function ChipGroup({
  label,
  children,
}: {
  label?: string;
  children: ReactNode;
}) {
  return (
    <div className="row-8" role="group" aria-label={label}>
      {label && <span className="t-label" style={{ marginBottom: 0 }}>{label}</span>}
      <div className="cluster">{children}</div>
    </div>
  );
}
