interface SpeciesOpt {
  binomial: string;
  common: string;
  difficulty: "beginner" | "intermediate" | "advanced";
  category: "gourmet" | "medicinal";
  climate: "cool" | "moderate" | "warm";
  substrates: string[];
  baseScore: number;
  reason: string;
}

