interface Recommendation {
  binomial: string;
  common: string;
  score: number;
  reason: string;
  tags: string[];
}

function score(answers: Partial<Record<AnswerKey, string>>): Recommendation[] {
  return SPECIES.map((s) => {
    let score = s.baseScore;
    const tags: string[] = [];
    // Experience
    if (answers.experience === "first" && s.difficulty !== "beginner") {
      score -= 25;
      tags.push("difficulty mismatch");
    } else if (answers.experience === "20+" && s.difficulty === "beginner") {
      score -= 4;
    }
    // Substrate
    if (answers.substrate && answers.substrate !== "all") {
      if (!s.substrates.includes(answers.substrate)) {
        score -= 18;
        tags.push("substrate mismatch");
      } else {
        tags.push("substrate match");
      }
    } else if (answers.substrate === "all") {
      tags.push("any substrate");
    }
    // Climate
    if (answers.climate === "cool" && s.climate !== "cool") score -= 8;
    if (answers.climate === "warm" && s.climate !== "warm") score -= 6;
    if (answers.climate === "moderate" && s.climate === "moderate") {
      score += 4;
      tags.push("climate match");
    }
    if (answers.climate === "hvac") {
      score += 6;
      tags.push("hvac flexible");
    }
    // Goal
    if (answers.goal === "medicinal" && s.category !== "medicinal") score -= 18;
    if (answers.goal === "restaurant" && s.category === "gourmet") {
      score += 6;
      tags.push("restaurant grade");
    }
    if (answers.goal === "home" && s.category === "gourmet") tags.push("home cooking");
    // Commitment
    if (answers.commitment === "low" && s.difficulty === "advanced") score -= 12;
    if (answers.commitment === "high" && s.difficulty !== "beginner") score += 4;
    return {
      binomial: s.binomial,
      common: s.common,
      score: Math.max(0, Math.min(100, score)),
      reason: s.reason,
      tags,
    };
  })
    .sort((a, b) => b.score - a.score)
    .slice(0, 3);
}

export function WizardPage() {
  const [answers, setAnswers] = useState<Partial<Record<AnswerKey, string>>>({
    substrate: "mastersmix",
  });
  const [committed, setCommitted] = useState(false);

  const recs = useMemo(() => score(answers), [answers]);
  const answeredCount = Object.keys(answers).length;
  const allAnswered = answeredCount === STEPS.length;

  function setAnswer(key: AnswerKey, value: string) {
    setAnswers((prev) => ({ ...prev, [key]: value }));
  }

  function reset() {
    setAnswers({});
    setCommitted(false);
  }

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>plan</span>
          <span className="sep">/</span>
          <b className="accent">species wizard</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Plan"
        title="Species Wizard"
        italic={false}
        meta={
          <span>
            answer five questions · {answeredCount}/{STEPS.length} answered · top-3 recommendations update live
          </span>
        }
      />

      <div className="shell-body pi">
        <main className="stack-16">
          {STEPS.map((s) => {
            const current = answers[s.key];
            return (
              <section key={s.key} className="side-panel">
                <div className="row-12" style={{ alignItems: "baseline" }}>
                  <span className="t-eyebrow" style={{ marginBottom: 0 }}>{s.roman}</span>
                  <h2 className="t-h3-sans">{s.title}</h2>
                  {current && <span className="status-pill accent" style={{ marginLeft: "auto" }}>answered</span>}
                </div>
                <p className="t-body">{s.question}</p>
                <div className="stack-10">
                  {s.options.map((opt) => {
                    const active = current === opt.value;
                    return (
                      <label
                        key={opt.value}
                        className={`t-mono row-12 ${active ? "t-accent" : "t-soft"}`}
                        style={{
                          padding: "14px 18px",
                          background: active ? "var(--accent-soft)" : "var(--bg-2)",
                          border: `1px solid ${active ? "var(--accent-line)" : "var(--border-soft)"}`,
                          borderRadius: "var(--r-sm)",
                          cursor: "pointer",
                        }}
                      >
                        <input
                          type="radio"
                          name={s.key}
                          value={opt.value}
                          checked={active}
                          onChange={() => setAnswer(s.key, opt.value)}
                          style={{ accentColor: "var(--accent)" }}
                        />
                        {opt.label}
                      </label>
                    );
                  })}
                </div>
              </section>
            );
          })}
          <div className="row-12" style={{ justifyContent: "flex-end" }}>
            <button className="t-back-btn" type="button" onClick={reset}>reset</button>
            <button
              className="t-btn-primary"
              type="button"
              onClick={() => setCommitted(true)}
              disabled={!allAnswered}
            >
              {allAnswered ? "lock recommendations →" : `answer ${STEPS.length - answeredCount} more →`}
            </button>
          </div>
        </main>

        <aside className="stack-14">
          <section className="side-panel">
            <div className="head">
              {committed ? "Final recommendations" : "Live recommendations"}
            </div>
            <span className="t-mono-sm">
              ranked across substrate · climate · goal · experience · time-commitment
            </span>
            {recs.map((r, i) => (
              <article
                key={r.binomial}
                className="stack-8"
                style={{
                  background: "var(--bg-2)",
                  border: `1px solid ${i === 0 ? "var(--accent-line)" : "var(--border-soft)"}`,
                  borderRadius: "var(--r-sm)",
                  padding: 16,
                }}
              >
                <div className="row-between-baseline">
                  <div className="row-8" style={{ alignItems: "baseline" }}>
                    <span className="t-num-sm t-accent">#{i + 1}</span>
                    <h3 className="t-display-sm binomial">{r.binomial}</h3>
                  </div>
                  <span className={`t-num-sm ${i === 0 ? "t-accent" : "t-soft"}`}>
                    {r.score}
                  </span>
                </div>
                <span className="t-mono-sm">{r.common}</span>
                <ScoreBar score={r.score} />
                <p className="t-body-sm">{r.reason}</p>
                {r.tags.length > 0 && (
                  <div className="cluster" style={{ gap: 6 }}>
                    {r.tags.map((t) => {
                      const isMismatch = t.includes("mismatch");
                      return (
                        <span
                          key={t}
                          className={`t-mono-sm ${isMismatch ? "t-err" : "t-muted"}`}
                          style={{
                            background: isMismatch ? "rgba(200, 90, 76, 0.12)" : "var(--bg-3)",
                            padding: "2px 8px",
                            borderRadius: "var(--r-pill)",
                          }}
                        >
                          {t}
                        </span>
                      );
                    })}
                  </div>
                )}
              </article>
            ))}
            {!allAnswered && (
              <p className="t-body-sm t-muted">
                Scores update as you answer · finish all five questions to lock the ranking.
              </p>
            )}
          </section>
        </aside>
      </div>
    </>
  );
}

function ScoreBar({ score }: { score: number }) {
  return (
    <div className="exp-confidence-bar" aria-hidden="true">
      <i style={{ width: `${score}%` }} />
    </div>
  );
}
