import { useMemo, useState } from "react";
import {
  CloudSyncIndicator,
  PI_HEALTH,
  PI_LOCAL_FLEET,
  PageHeader,
  seedRand,
} from "@sporeprint/design";

interface ClaudeCheck {
  state: "idle" | "pending" | "complete" | "failed";
  result?: { health: "healthy" | "warn" | "contam"; summary: string };
}

interface FrameThumb {
  ts: string;
  ago: string;
  label: string;
}

function buildStrip(seed: string): FrameThumb[] {
  const r = seedRand(seed);
  const labels = ["pin set", "expansion", "primordia", "veil tear", "harvest ready", "after mist", "lights on"];
  return Array.from({ length: 8 }, (_, i) => {
    const minsAgo = i * 18 + Math.floor(r() * 8);
    const totalMin = 14 * 60 + 30 - minsAgo;
    const hh = Math.floor(totalMin / 60).toString().padStart(2, "0");
    const mm = Math.floor(totalMin % 60).toString().padStart(2, "0");
    return {
      ts: `${hh}:${mm}`,
      ago: minsAgo === 0 ? "now" : `${minsAgo}m ago`,
      label: labels[Math.floor(r() * labels.length)] ?? labels[0]!,
    };
  });
}

export function VisionPage() {
  const [checks, setChecks] = useState<Record<string, ClaudeCheck>>({});
  const [contamMarks, setContamMarks] = useState<
    Record<string, { type: string; confidence: number }>
  >({});
  const [contamForm, setContamForm] = useState<{ chamberId: string; type: string; confidence: string }>({
    chamberId: "",
    type: "Trichoderma viride",
    confidence: "0.85",
  });
  const [captureLog, setCaptureLog] = useState<Array<{ chamberId: string; ts: string }>>([]);

  const strips = useMemo(() => {
    const out: Record<string, FrameThumb[]> = {};
    for (const c of PI_LOCAL_FLEET) {
      out[c.id] = buildStrip(c.id);
    }
    return out;
  }, []);

  function runClaudeCheck(chamberId: string) {
    setChecks((prev) => ({ ...prev, [chamberId]: { state: "pending" } }));
    setTimeout(() => {
      const r = Math.random();
      const health: ClaudeCheck["result"] = r > 0.7
        ? { health: "warn", summary: "Cap surfaces glistening with free water — consider dropping mist freq." }
        : r > 0.55
          ? { health: "contam", summary: "Suspected wisp on substrate edge — recommend close-up frame." }
          : { health: "healthy", summary: "Pins evenly distributed · uniform pigmentation · veil intact." };
      setChecks((prev) => ({ ...prev, [chamberId]: { state: "complete", result: health } }));
    }, 700);
  }

  function captureFrame(chamberId: string) {
    const ts = new Date().toLocaleTimeString("en-GB", { hour12: false });
    setCaptureLog((prev) => [{ chamberId, ts }, ...prev].slice(0, 6));
  }

  function markContam() {
    const conf = Math.max(0, Math.min(1, parseFloat(contamForm.confidence) || 0));
    if (!contamForm.chamberId) return;
    setContamMarks((prev) => ({
      ...prev,
      [contamForm.chamberId]: { type: contamForm.type, confidence: conf },
    }));
  }

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>monitor</span>
          <span className="sep">/</span>
          <b className="accent">vision</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="On this Pi"
        title="Camera feed"
        italic={false}
        meta={
          <span>
            {PI_LOCAL_FLEET.length} cameras · live frame stream · runs against on-Pi BYOK Claude when set
          </span>
        }
        right={<button className="t-btn-primary" type="button">refresh all →</button>}
      />

      <div className="shell-body pi">
        <main className="stack-14">
          <div className="gallery">
            {PI_LOCAL_FLEET.map((c, i) => {
              const check = checks[c.id];
              const mark = contamMarks[c.id];
              return (
                <article key={c.id} className="frame">
                  <div className="preview">
                    <span style={{ position: "relative", zIndex: 1 }}>[live · {c.id}]</span>
                  </div>
                  <div className="meta" style={{ height: "auto" }}>
                    <div className="row-between-baseline">
                      <span className="id">{c.id} · R{c.rack.rack}·S{c.rack.shelf}</span>
                      <span className={`status-pill ${c.state === "active" ? "accent" : c.state === "warn" ? "warn" : "signal"}`}>
                        {c.phase}
                      </span>
                    </div>
                    <span className="species">{c.species.binomial}</span>
                    <span className="ts">last frame {(i % 14) + 4}s ago · 1280×720</span>
                    <div className="cluster" style={{ marginTop: 6, gap: 6 }}>
                      <button
                        type="button"
                        className="t-back-btn t-mono-sm"
                        style={{ padding: "6px 10px" }}
                        onClick={() => captureFrame(c.id)}
                      >
                        capture frame
                      </button>
                      <button
                        type="button"
                        className="t-btn-primary t-mono-sm"
                        style={{ padding: "6px 10px" }}
                        onClick={() => runClaudeCheck(c.id)}
                        disabled={check?.state === "pending"}
                      >
                        {check?.state === "pending" ? "claude…" : "claude check"}
                      </button>
                    </div>
                    {check?.state === "complete" && check.result && (
                      <div
                        style={{
                          marginTop: 6,
                          padding: 10,
                          borderRadius: "var(--r-sm)",
                          background:
                            check.result.health === "healthy"
                              ? "var(--accent-soft)"
                              : check.result.health === "warn"
                                ? "rgba(200, 150, 96, 0.12)"
                                : "rgba(200, 90, 76, 0.12)",
                        }}
                      >
                        <span
                          className={`t-mono-sm ${
                            check.result.health === "healthy"
                              ? "t-accent"
                              : check.result.health === "warn"
                                ? "t-warn"
                                : "t-err"
                          }`}
                        >
                          ↳ {check.result.summary}
                        </span>
                      </div>
                    )}
                    {mark && (
                      <div
                        style={{
                          marginTop: 6,
                          padding: "6px 10px",
                          borderRadius: "var(--r-sm)",
                          background: "rgba(200, 90, 76, 0.12)",
                          border: "1px solid var(--err)",
                        }}
                      >
                        <span className="t-mono-sm t-err">
                          flagged · {mark.type} · {(mark.confidence * 100).toFixed(0)}%
                        </span>
                      </div>
                    )}
                    <TimelapseStrip frames={strips[c.id] ?? []} />
                  </div>
                </article>
              );
            })}
          </div>
        </main>

        <aside className="stack-14">
          <section className="side-panel">
            <div className="head">Manual contam mark</div>
            <p className="t-body-sm">
              Override the classifier when you spot something it missed. Logs against the chamber for
              cloud root-cause review.
            </p>
            <label className="form-field">
              <span className="form-label">chamber</span>
              <select
                className="t-input"
                value={contamForm.chamberId}
                onChange={(e) => setContamForm({ ...contamForm, chamberId: e.target.value })}
              >
                <option value="">pick a chamber…</option>
                {PI_LOCAL_FLEET.map((c) => (
                  <option key={c.id} value={c.id}>{c.id} · {c.species.binomial}</option>
                ))}
              </select>
            </label>
            <label className="form-field">
              <span className="form-label">type</span>
              <select
                className="t-input"
                value={contamForm.type}
                onChange={(e) => setContamForm({ ...contamForm, type: e.target.value })}
              >
                <option value="Trichoderma viride">Trichoderma viride</option>
                <option value="Cobweb (Cladobotryum)">Cobweb (Cladobotryum)</option>
                <option value="Penicillium">Penicillium</option>
                <option value="Aspergillus">Aspergillus</option>
                <option value="Bacterial blotch">Bacterial blotch</option>
              </select>
            </label>
            <label className="form-field">
              <span className="form-label">confidence (0–1)</span>
              <input
                className="t-input"
                type="number"
                step="0.05"
                min={0}
                max={1}
                value={contamForm.confidence}
                onChange={(e) => setContamForm({ ...contamForm, confidence: e.target.value })}
              />
            </label>
            <button
              type="button"
              className="t-btn-primary"
              style={{ alignSelf: "flex-start" }}
              disabled={!contamForm.chamberId}
              onClick={markContam}
            >
              flag chamber →
            </button>
          </section>

          <section className="side-panel">
            <div className="head">Recent captures</div>
            {captureLog.length === 0 ? (
              <p className="t-body-sm t-muted">
                Capture a frame from any camera card · the manual frames are pinned to the cloud sync queue.
              </p>
            ) : (
              <ul className="stack-6" style={{ listStyle: "none", padding: 0, margin: 0 }}>
                {captureLog.map((e, i) => (
                  <li key={`${e.ts}-${i}`} className="t-mono-sm row-between">
                    <span>{e.chamberId}</span>
                    <span className="t-muted">{e.ts}</span>
                  </li>
                ))}
              </ul>
            )}
          </section>

          <section className="side-panel">
            <div className="head">BYOK status</div>
            <div className="stack-8">
              <Row k="claude key" v="set · sk-…7c9e (Pi-local)" />
              <Row k="rate limit" v="60 / hr" />
              <Row k="last call" v="14:09:08 · ok" />
              <Row k="cost · 24h" v="$0.34" />
            </div>
            <p className="t-body-sm t-muted">
              When the Pi BYOK key is unset, the Claude check buttons fall back to the local CNN — accuracy
              drops, but no API call leaves the LAN.
            </p>
          </section>
        </aside>
      </div>
    </>
  );
}

function TimelapseStrip({ frames }: { frames: FrameThumb[] }) {
  if (frames.length === 0) return null;
  return (
    <div className="stack-4" style={{ marginTop: 8 }}>
      <span className="t-label">last 8 frames</span>
      <div style={{ display: "flex", gap: 4, overflowX: "auto" }}>
        {frames.map((f, i) => (
          <div
            key={`${f.ts}-${i}`}
            title={`${f.ts} · ${f.label}`}
            style={{
              flex: "0 0 auto",
              width: 56,
              height: 42,
              borderRadius: "var(--r-sm)",
              background:
                "radial-gradient(circle at 30% 30%, var(--bg-2), var(--bg-0))",
              border: "1px solid var(--border-soft)",
              display: "flex",
              alignItems: "flex-end",
              justifyContent: "flex-start",
              padding: 3,
            }}
          >
            <span className="t-mono-sm t-faint">{f.ts}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

function Row({ k, v }: { k: string; v: string }) {
  return (
    <div className="row-between">
      <span className="t-label">{k}</span>
      <span className="t-mono">{v}</span>
    </div>
  );
}
