import { useMemo, useState } from "react";
import {
  CloudSyncIndicator,
  CULTURES,
  PageHeader,
  PI_HEALTH,
  type CultureStub,
} from "@sporeprint/design";

const KIND_LABEL: Record<CultureStub["kind"], string> = {
  agar: "agar plate",
  lc: "liquid culture",
  spawn: "grain spawn",
};
const KIND_TONE: Record<CultureStub["kind"], "signal" | "accent" | "warn"> = {
  agar: "signal",
  lc: "accent",
  spawn: "warn",
};

const REFRESH_AGE_DAYS = 120;
const REFRESH_VIGOUR = 2;

function refreshDue(c: CultureStub): boolean {
  return c.ageDays >= REFRESH_AGE_DAYS || (c.vigour ?? 5) <= REFRESH_VIGOUR;
}

interface TreeNode {
  culture: CultureStub;
  children: TreeNode[];
}

function buildTree(roots: CultureStub[], all: CultureStub[]): TreeNode[] {
  return roots.map((c) => ({
    culture: c,
    children: buildTree(all.filter((x) => x.parent === c.id), all),
  }));
}

export function CulturesPage() {
  const [selectedId, setSelectedId] = useState<string>(CULTURES[0]?.id ?? "");
  const [transferParent, setTransferParent] = useState<string>("");
  const [transferKind, setTransferKind] = useState<CultureStub["kind"]>("lc");
  const [transferLabel, setTransferLabel] = useState("");
  const [recent, setRecent] = useState<Array<{ child: string; parent: string; kind: CultureStub["kind"] }>>([]);

  const selected = useMemo(
    () => CULTURES.find((c) => c.id === selectedId) ?? CULTURES[0]!,
    [selectedId],
  );

  const roots = useMemo(() => CULTURES.filter((c) => !c.parent), []);
  const tree = useMemo(() => buildTree(roots, CULTURES), [roots]);

  const refreshCount = useMemo(() => CULTURES.filter(refreshDue).length, []);

  function commitTransfer() {
    if (!transferParent || !transferLabel.trim()) return;
    setRecent((prev) => [
      { child: transferLabel.trim(), parent: transferParent, kind: transferKind },
      ...prev,
    ].slice(0, 5));
    setTransferLabel("");
  }

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>track</span>
          <span className="sep">/</span>
          <b className="accent">cultures</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Track"
        title="Cultures"
        italic={false}
        meta={
          <span>
            {CULTURES.length} cultures · {refreshCount} flagged for refresh · ancestry cached for offline browsing
          </span>
        }
        right={<button className="t-btn-primary" type="button">+ new culture →</button>}
      />

      <div className="shell-body pi">
        <main className="stack-14">
          <table className="data-table">
            <thead>
              <tr>
                <th scope="col">ID</th>
                <th scope="col">Strain</th>
                <th scope="col">Kind</th>
                <th scope="col" className="num">Age</th>
                <th scope="col" className="num">Gen</th>
                <th scope="col">Parent</th>
                <th scope="col" className="num">Vigour</th>
                <th scope="col">Status</th>
              </tr>
            </thead>
            <tbody>
              {CULTURES.map((c) => {
                const due = refreshDue(c);
                return (
                  <tr
                    key={c.id}
                    onClick={() => setSelectedId(c.id)}
                    style={{
                      cursor: "pointer",
                      background: selectedId === c.id ? "var(--bg-2)" : undefined,
                    }}
                  >
                    <td className="mono-cell">{c.id}</td>
                    <td className="binomial-cell">{c.strain}</td>
                    <td><span className={`status-pill ${KIND_TONE[c.kind]}`}>{KIND_LABEL[c.kind]}</span></td>
                    <td className="num mono-cell">{c.ageDays}d</td>
                    <td className="num mono-cell">G{c.generation}</td>
                    <td className="mono-cell">{c.parent ?? "—"}</td>
                    <td className="num"><VigourPips n={c.vigour ?? 0} /></td>
                    <td>
                      {due ? (
                        <span className="status-pill warn">refresh</span>
                      ) : (
                        <span className="status-pill signal">healthy</span>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>

          <section className="side-panel">
            <div className="head">Lineage tree</div>
            <span className="t-mono-sm">click a row above or a node below to surface details on the right</span>
            <div className="lineage">
              {tree.map((n) => (
                <TreeBranch key={n.culture.id} node={n} selectedId={selectedId} onSelect={setSelectedId} />
              ))}
            </div>
          </section>
        </main>

        <aside className="stack-14">
          <section className="side-panel">
            <div className="head">Selected · {selected.id}</div>
            <h2 className="t-display-sm binomial">{selected.binomial}</h2>
            <span className="t-mono-sm">{selected.strain}</span>
            <div className="stack-10">
              <Row k="kind" v={KIND_LABEL[selected.kind]} />
              <Row k="age" v={`${selected.ageDays}d`} />
              <Row k="gen" v={`G${selected.generation}`} />
              <Row k="parent" v={selected.parent ?? "—"} />
              <Row k="created" v={selected.createdOn ?? "—"} />
              <Row k="vigour" v={`${selected.vigour ?? "—"} / 5`} />
              <Row k="sessions" v={selected.sessions?.length ? selected.sessions.join(" · ") : "—"} />
            </div>
            {selected.notes && (
              <p className="t-body-sm t-muted">↳ {selected.notes}</p>
            )}
            {refreshDue(selected) && (
              <div
                className="stack-4"
                style={{
                  background: "rgba(200, 150, 96, 0.12)",
                  border: "1px solid var(--warn)",
                  borderRadius: "var(--r-sm)",
                  padding: 12,
                }}
              >
                <span className="t-eyebrow t-warn" style={{ marginBottom: 0 }}>refresh due</span>
                <span className="t-body-sm">
                  {selected.ageDays >= REFRESH_AGE_DAYS
                    ? `Age past ${REFRESH_AGE_DAYS}d — schedule a transfer to a fresh plate.`
                    : "Vigour rating low — sluggish leading edge means next spawn run will lag."}
                </span>
              </div>
            )}
          </section>

          <section className="side-panel">
            <div className="head">Transfer flow</div>
            <p className="t-body-sm">
              Take an existing plate or LC and fork off the next generation. Parent picker auto-prefills
              the binomial; pick a kind for the new entry.
            </p>
            <label className="form-field">
              <span className="form-label">parent culture</span>
              <select
                className="t-input"
                value={transferParent}
                onChange={(e) => setTransferParent(e.target.value)}
              >
                <option value="">pick a parent…</option>
                {CULTURES.map((c) => (
                  <option key={c.id} value={c.id}>{c.id} · {c.strain} · G{c.generation}</option>
                ))}
              </select>
            </label>
            <label className="form-field">
              <span className="form-label">new kind</span>
              <select
                className="t-input"
                value={transferKind}
                onChange={(e) => setTransferKind(e.target.value as CultureStub["kind"])}
              >
                <option value="agar">agar plate</option>
                <option value="lc">liquid culture</option>
                <option value="spawn">grain spawn</option>
              </select>
            </label>
            <label className="form-field">
              <span className="form-label">label</span>
              <input
                className="t-input"
                placeholder="e.g. C-001.1.b"
                value={transferLabel}
                onChange={(e) => setTransferLabel(e.target.value)}
              />
            </label>
            <button
              type="button"
              className="t-btn-primary"
              style={{ alignSelf: "flex-start" }}
              onClick={commitTransfer}
              disabled={!transferParent || !transferLabel.trim()}
            >
              record transfer →
            </button>
            {recent.length > 0 && (
              <ul className="stack-4" style={{ listStyle: "none", padding: 0, margin: 0 }}>
                {recent.map((r, i) => (
                  <li key={`${r.child}-${i}`} className="t-mono-sm">
                    {r.parent} → {r.child} ({KIND_LABEL[r.kind]})
                  </li>
                ))}
              </ul>
            )}
          </section>
        </aside>
      </div>
    </>
  );
}

function TreeBranch({
  node,
  selectedId,
  onSelect,
}: {
  node: TreeNode;
  selectedId: string;
  onSelect: (id: string) => void;
}) {
  const c = node.culture;
  const due = refreshDue(c);
  return (
    <div className="node">
      <button
        type="button"
        onClick={() => onSelect(c.id)}
        style={{
          appearance: "none",
          background: selectedId === c.id ? "var(--accent-soft)" : "transparent",
          border: "none",
          padding: "4px 8px",
          textAlign: "left",
          cursor: "pointer",
          width: "100%",
          borderRadius: "var(--r-sm)",
        }}
      >
        <span className="id">{c.id}</span>
        <span className="strain">{c.strain}</span>
        <span style={{ color: "var(--text-2)", marginLeft: 8 }}>
          · G{c.generation} · {c.ageDays}d{due && <span style={{ color: "var(--warn)", marginLeft: 6 }}>refresh</span>}
        </span>
      </button>
      {node.children.length > 0 && (
        <div className="child">
          {node.children.map((child) => (
            <TreeBranch key={child.culture.id} node={child} selectedId={selectedId} onSelect={onSelect} />
          ))}
        </div>
      )}
    </div>
  );
}

function VigourPips({ n }: { n: number }) {
  return (
    <span style={{ display: "inline-flex", gap: 2 }}>
      {[1, 2, 3, 4, 5].map((i) => (
        <span
          key={i}
          style={{
            display: "inline-block",
            width: 6,
            height: 12,
            borderRadius: 1,
            background: i <= n ? "var(--accent)" : "var(--bg-3)",
          }}
        />
      ))}
    </span>
  );
}

function Row({ k, v }: { k: string; v: string }) {
  return (
    <div className="row-between" style={{ alignItems: "baseline" }}>
      <span className="t-label">{k}</span>
      <span className="t-mono">{v}</span>
    </div>
  );
}
