import { useMemo, useState } from "react";
import { Link } from "react-router-dom";
import {
  CHAMBER_ASSETS,
  Chip,
  ChipGroup,
  CloudSyncIndicator,
  DataTable,
  KpiCard,
  PageHeader,
  PI_HEALTH,
  PI_LOCAL_FLEET,
  SENSOR_CALIBRATION_HISTORY,
  SearchInput,
  type ChamberAsset,
  type ChamberActivity,
  maintenanceStatusFor,
} from "@sporeprint/design";

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="form-field">
      <span className="form-label">{label}</span>
      {children}
    </label>
  );
}

type ActivityFilter = "all" | ChamberActivity;
type MaintFilter = "all" | "overdue" | "due-soon" | "current";
type RackFilter = "all" | "1" | "2" | "3" | "4";

export function ChambersInventoryPage() {
  // Pi only sees its own chambers — restrict to PI_LOCAL_FLEET ids.
  const localIds = new Set(PI_LOCAL_FLEET.map((c) => c.id));
  const allLocal = useMemo(
    () => CHAMBER_ASSETS.filter((a) => localIds.has(a.id)),
    [localIds],
  );

  const [activity, setActivity] = useState<ActivityFilter>("all");
  const [maint, setMaint] = useState<MaintFilter>("all");
  const [rack, setRack] = useState<RackFilter>("all");
  const [query, setQuery] = useState("");
  const [selectedId, setSelectedId] = useState<string>(allLocal[0]?.id ?? "");
  const [showSchedule, setShowSchedule] = useState(false);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return allLocal.filter((a) => {
      if (activity !== "all" && a.activity !== activity) return false;
      if (maint !== "all" && maintenanceStatusFor(a.nextMaintDays) !== maint) return false;
      if (rack !== "all" && !a.rack.startsWith(`R${rack}`)) return false;
      if (!q) return true;
      return [a.id, a.enclosure, a.nextMaintLabel].join(" ").toLowerCase().includes(q);
    });
  }, [allLocal, activity, maint, rack, query]);

  const selected = useMemo(
    () => filtered.find((a) => a.id === selectedId) ?? filtered[0] ?? allLocal[0],
    [filtered, selectedId, allLocal],
  );

  const kpis = useMemo(() => {
    const total = allLocal.length;
    const inRotation = allLocal.filter((a) => a.activity === "in-rotation").length;
    const idle = allLocal.filter((a) => a.activity === "idle").length;
    const overdue = allLocal.filter((a) => maintenanceStatusFor(a.nextMaintDays) === "overdue").length;
    const dueSoon = allLocal.filter((a) => maintenanceStatusFor(a.nextMaintDays) === "due-soon").length;
    return { total, inRotation, idle, overdue, dueSoon };
  }, [allLocal]);

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>track</span>
          <span className="sep">/</span>
          <b className="accent">chambers</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Track"
        title="Chambers"
        italic={false}
        meta={
          <span>
            physical asset inventory · maintenance · lifetime stats · {filtered.length} of {allLocal.length}{" "}
            visible
          </span>
        }
        right={
          <button
            type="button"
            className={showSchedule ? "t-btn-primary" : "t-back-btn"}
            onClick={() => setShowSchedule((v) => !v)}
          >
            {showSchedule ? "cancel" : "+ schedule maintenance"}
          </button>
        }
      />

      <div className="shell-body pi">
        <main className="stack-14">
          <section className="kpi-grid">
            <KpiCard label="total" value={kpis.total.toString()} />
            <KpiCard label="in rotation" value={kpis.inRotation.toString()} tone="signal" />
            <KpiCard label="idle" value={kpis.idle.toString()} />
            <KpiCard label="maintenance due" value={(kpis.overdue + kpis.dueSoon).toString()} tone="accent" />
          </section>

          <Toolbar
            query={query}
            onQuery={setQuery}
            activity={activity}
            onActivity={setActivity}
            maint={maint}
            onMaint={setMaint}
            rack={rack}
            onRack={setRack}
          />

          {showSchedule && selected && (
            <ScheduleForm chamber={selected} onClose={() => setShowSchedule(false)} />
          )}

          <DataTable<ChamberAsset>
            rowKey={(a) => a.id}
            onRowClick={(a) => setSelectedId(a.id)}
            columns={[
              { key: "id", header: "Chamber", render: (a) => (
                <Link to={`/chamber/${a.id}`} className="t-link-mono" onClick={(e) => e.stopPropagation()}>{a.id}</Link>
              ) },
              { key: "rack", header: "Rack", render: (a) => <span className="mono-cell">{a.rack}</span> },
              { key: "enclosure", header: "Enclosure", render: (a) => <>{a.enclosure}</> },
              { key: "activity", header: "Activity", render: (a) => (
                <span className={`status-pill ${
                  a.activity === "in-rotation" ? "accent" : a.activity === "idle" ? "idle" : "warn"
                }`}>{a.activity}</span>
              ) },
              { key: "grows", header: "Lifetime grows", align: "right", render: (a) => <span className="mono-cell">{a.lifetimeSessions}</span> },
              { key: "yield", header: "Lifetime yield", align: "right", render: (a) => <span className="mono-cell">{a.lifetimeYieldG.toLocaleString()}g</span> },
              { key: "contam", header: "Contam", align: "right", render: (a) => <span className="mono-cell">{(a.contamRate * 100).toFixed(1)}%</span> },
              { key: "next", header: "Next maintenance", render: (a) => {
                const status = maintenanceStatusFor(a.nextMaintDays);
                return (
                  <>
                    <span className={`status-pill ${
                      status === "overdue" ? "err" : status === "due-soon" ? "warn" : "idle"
                    }`}>
                      {a.nextMaintDays < 0 ? `${Math.abs(a.nextMaintDays)}d overdue` : `${a.nextMaintDays}d`}
                    </span>
                    <div className="t-mono-sm" style={{ marginTop: 4 }}>{a.nextMaintLabel}</div>
                  </>
                );
              } },
            ]}
            rows={filtered}
          />

          <YieldChart assets={allLocal} />
        </main>

        {selected && <DetailPanel chamber={selected} />}
      </div>
    </>
  );
}

function Toolbar({
  query,
  onQuery,
  activity,
  onActivity,
  maint,
  onMaint,
  rack,
  onRack,
}: {
  query: string;
  onQuery: (v: string) => void;
  activity: ActivityFilter;
  onActivity: (a: ActivityFilter) => void;
  maint: MaintFilter;
  onMaint: (m: MaintFilter) => void;
  rack: RackFilter;
  onRack: (r: RackFilter) => void;
}) {
  return (
    <section
      className="side-panel cluster"
      style={{ flexDirection: "row" }}
    >
      <div style={{ flex: "1 1 240px", minWidth: 200 }}>
        <SearchInput
          value={query}
          onChange={onQuery}
          placeholder="search id, enclosure, maintenance task …"
          ariaLabel="search chambers"
        />
      </div>
      <ChipGroup label="rack">
        {(["all", "1", "2", "3", "4"] as const).map((r) => (
          <Chip key={r} active={rack === r} onClick={() => onRack(r)}>
            {r === "all" ? "all" : `R${r}`}
          </Chip>
        ))}
      </ChipGroup>
      <ChipGroup label="activity">
        {(["all", "in-rotation", "idle", "retired"] as const).map((a) => (
          <Chip key={a} active={activity === a} onClick={() => onActivity(a as ActivityFilter)}>
            {a}
          </Chip>
        ))}
      </ChipGroup>
      <ChipGroup label="maintenance">
        {(["all", "overdue", "due-soon", "current"] as const).map((m) => (
          <Chip key={m} active={maint === m} onClick={() => onMaint(m as MaintFilter)}>
            {m}
          </Chip>
        ))}
      </ChipGroup>
    </section>
  );
}

function ScheduleForm({ chamber, onClose }: { chamber: ChamberAsset; onClose: () => void }) {
  const [kind, setKind] = useState("pco-clean");
  const [dueIn, setDueIn] = useState("7");
  const [note, setNote] = useState("");
  return (
    <form
      className="side-panel stack-12"
      onSubmit={(e) => {
        e.preventDefault();
        onClose();
      }}
    >
      <div className="head">Schedule maintenance · {chamber.id}</div>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
          gap: 12,
        }}
      >
        <Field label="Task">
          <select
            value={kind}
            onChange={(e) => setKind(e.target.value)}
            className="t-input"
          >
            <option value="pco-clean">PCO clean</option>
            <option value="gasket-replace">Gasket replacement</option>
            <option value="sensor-recal">Sensor recalibration</option>
            <option value="filter-swap">Filter swap</option>
            <option value="leak-test">Static-pressure leak test</option>
          </select>
        </Field>
        <Field label="Due in (days)">
          <input
            className="t-input"
            type="number"
            min={0}
            value={dueIn}
            onChange={(e) => setDueIn(e.target.value)}
          />
        </Field>
        <Field label="Note">
          <input
            className="t-input"
            value={note}
            onChange={(e) => setNote(e.target.value)}
            placeholder="optional"
          />
        </Field>
      </div>
      <div className="row-10" style={{ justifyContent: "flex-end" }}>
        <button type="button" className="t-back-btn" onClick={onClose}>
          cancel
        </button>
        <button type="submit" className="t-btn-primary">
          schedule →
        </button>
      </div>
    </form>
  );
}

function DetailPanel({ chamber }: { chamber: ChamberAsset }) {
  const calibration = SENSOR_CALIBRATION_HISTORY.filter(
    (c) => c.chamberId === chamber.id,
  ).slice(0, 4);
  return (
    <aside className="stack-14">
      <section className="side-panel">
        <div className="head">{chamber.id} · {chamber.enclosure}</div>
        <span className="t-mono-sm">
          installed {chamber.installed} · {chamber.installedDaysAgo}d in service
        </span>

        <div className="kpi-grid" style={{ gridTemplateColumns: "1fr 1fr" }}>
          <KpiCard label="lifetime grows" value={chamber.lifetimeSessions.toString()} />
          <KpiCard label="lifetime yield" value={`${chamber.lifetimeYieldG.toLocaleString()}g`} tone="accent" />
          <KpiCard label="avg ttf" value={`${chamber.avgTimeToFruit}d`} />
          <KpiCard label="longest run" value={`${chamber.longestRunDays}d`} />
          <KpiCard label="contam rate" value={`${(chamber.contamRate * 100).toFixed(1)}%`} tone="signal" />
          <KpiCard label="next maint." value={`${chamber.nextMaintDays}d`} />
        </div>

        <div className="row-8">
          <button className="t-btn-primary" type="button">
            mark cleaned →
          </button>
          <button className="t-back-btn" type="button">
            log harvest →
          </button>
        </div>
      </section>

      <section className="side-panel">
        <div className="head">Maintenance log</div>
        <ul className="stack-8" style={{ listStyle: "none", padding: 0, margin: 0 }}>
          {chamber.log.map((entry) => (
            <li
              key={entry.id}
              style={{
                display: "flex",
                gap: 12,
                padding: "10px 12px",
                background: "var(--bg-2)",
                border: "1px solid var(--border-soft)",
                borderRadius: "var(--r-sm)",
              }}
            >
              <span
                className="t-mono-sm t-faint"
                style={{
                  width: 60,
                  flexShrink: 0,
                }}
              >
                {entry.date}
              </span>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div className="t-body-sm">{entry.note}</div>
                <div className="t-mono-sm t-faint" style={{ marginTop: 2 }}>
                  {entry.daysAgo}d ago · {entry.by}
                </div>
              </div>
            </li>
          ))}
        </ul>
      </section>

      <section className="side-panel">
        <div className="head">Photo gallery</div>
        <div className="gallery" style={{ gridTemplateColumns: "1fr 1fr" }}>
          {chamber.photos.map((p) => (
            <div key={p.id} className="frame">
              <div className="preview">{p.kind}</div>
              <div className="meta">
                <span className="id">{p.label}</span>
                <span className="t-mono-sm">{p.ts}</span>
              </div>
            </div>
          ))}
        </div>
      </section>

      <section className="side-panel">
        <div className="head">Sensor calibration</div>
        {calibration.length === 0 ? (
          <p className="t-mono-sm">No calibrations recorded for this chamber.</p>
        ) : (
          <DataTable
            rowKey={(c) => c.id}
            columns={[
              { key: "sensor", header: "Sensor", render: (c) => <>{c.sensor}</> },
              { key: "drift", header: "Drift", render: (c) => <span className="mono-cell">{c.drift}</span> },
              { key: "last", header: "Last cal.", align: "right", render: (c) => <span className="mono-cell">{c.lastCalibratedDaysAgo}d ago</span> },
              { key: "due", header: "Due in", align: "right", render: (c) => (
                <span className={`mono-cell ${c.daysUntilDue < 0 ? "t-err" : "t-soft"}`}>
                  {c.daysUntilDue < 0 ? `${Math.abs(c.daysUntilDue)}d overdue` : `${c.daysUntilDue}d`}
                </span>
              ) },
            ]}
            rows={calibration}
          />
        )}
      </section>
    </aside>
  );
}

function YieldChart({ assets }: { assets: ChamberAsset[] }) {
  const max = Math.max(1, ...assets.map((a) => a.lifetimeYieldG));
  return (
    <section className="side-panel">
      <div className="head">Lifetime yield by chamber</div>
      <div className="stack-6">
        {assets.map((a) => {
          const pct = (a.lifetimeYieldG / max) * 100;
          return (
            <div
              key={a.id}
              style={{
                display: "grid",
                gridTemplateColumns: "80px 1fr 100px",
                alignItems: "center",
                gap: 12,
              }}
            >
              <Link to={`/chamber/${a.id}`} className="t-link-mono">
                {a.id}
              </Link>
              <div
                style={{
                  height: 14,
                  background: "var(--bg-2)",
                  borderRadius: "var(--r-pill)",
                  overflow: "hidden",
                }}
              >
                <div
                  style={{
                    width: `${pct}%`,
                    height: "100%",
                    background: a.activity === "in-rotation" ? "var(--accent)" : "var(--signal)",
                  }}
                />
              </div>
              <span className="num mono-cell" style={{ textAlign: "right" }}>
                {a.lifetimeYieldG.toLocaleString()}g
              </span>
            </div>
          );
        })}
      </div>
    </section>
  );
}

