/**
 * Color-coded SVG wiring diagrams per hardware tier.
 * Ported from v3.4.x sporeprint/ui/src/components/builder/WiringDiagram.tsx
 * Wiring colors are functional (electrical convention), not brand —
 * keep them bright + saturated so connections read clearly on dark bg.
 */

const COLORS = {
  power3v3: "#ef4444",
  power5v: "#f97316",
  power12v: "#eab308",
  gnd: "#64748b",
  sda: "#3b82f6",
  scl: "#22c55e",
  gpio: "#a855f7",
  signal: "#06b6d4",
  board: "#1e293b",
  boardStroke: "#475569",
  label: "#e2e8f0",
  sublabel: "#94a3b8",
} as const;

function Board({ x, y, w, h, label, sublabel }: { x: number; y: number; w: number; h: number; label: string; sublabel?: string }) {
  return (
    <g>
      <rect x={x} y={y} width={w} height={h} rx={6} fill={COLORS.board} stroke={COLORS.boardStroke} strokeWidth={1.5} />
      <text x={x + w / 2} y={y + 20} textAnchor="middle" fill={COLORS.label} fontSize={12} fontWeight="bold">{label}</text>
      {sublabel && <text x={x + w / 2} y={y + 36} textAnchor="middle" fill={COLORS.sublabel} fontSize={10}>{sublabel}</text>}
    </g>
  );
}

function Pin({ x, y, label, color, side = "right" }: { x: number; y: number; label: string; color: string; side?: "left" | "right" }) {
  return (
    <g>
      <circle cx={x} cy={y} r={4} fill={color} stroke={color} />
      <text
        x={side === "right" ? x + 8 : x - 8}
        y={y + 3.5}
        textAnchor={side === "right" ? "start" : "end"}
        fill={COLORS.sublabel}
        fontSize={9}
      >
        {label}
      </text>
    </g>
  );
}

function Wire({ x1, y1, x2, y2, color, label, labelPos = 0.5 }: { x1: number; y1: number; x2: number; y2: number; color: string; label?: string; labelPos?: number }) {
  const mx = x1 + (x2 - x1) * 0.4;
  const path = `M ${x1} ${y1} C ${mx} ${y1}, ${mx} ${y2}, ${x2} ${y2}`;
  const lx = x1 + (x2 - x1) * labelPos;
  const ly = y1 + (y2 - y1) * labelPos - 6;
  return (
    <g>
      <path d={path} fill="none" stroke={color} strokeWidth={2} strokeLinecap="round" />
      {label && <text x={lx} y={ly} textAnchor="middle" fill={color} fontSize={9} fontWeight="bold">{label}</text>}
    </g>
  );
}

function Legend({ x, y }: { x: number; y: number }) {
  const items = [
    { color: COLORS.power3v3, label: "3.3V" },
    { color: COLORS.power5v, label: "5V" },
    { color: COLORS.power12v, label: "12V" },
    { color: COLORS.gnd, label: "GND" },
    { color: COLORS.sda, label: "SDA · I²C data" },
    { color: COLORS.scl, label: "SCL · I²C clock" },
    { color: COLORS.gpio, label: "GPIO control" },
  ];
  return (
    <g>
      <text x={x} y={y} fill={COLORS.sublabel} fontSize={10} fontWeight="bold">LEGEND</text>
      {items.map((item, i) => (
        <g key={i}>
          <line x1={x} y1={y + 14 + i * 16} x2={x + 18} y2={y + 14 + i * 16} stroke={item.color} strokeWidth={2.5} strokeLinecap="round" />
          <text x={x + 26} y={y + 17 + i * 16} fill={COLORS.sublabel} fontSize={10}>{item.label}</text>
        </g>
      ))}
    </g>
  );
}

function ClimateNodeDiagram() {
  const espX = 30;
  const espY = 40;
  const espW = 140;
  const espH = 200;
  const sensorX = 320;
  return (
    <svg viewBox="0 0 560 320" style={{ width: "100%", height: "auto" }}>
      <rect width="560" height="320" fill="var(--bg-2)" rx={8} />
      <text x={280} y={22} textAnchor="middle" fill={COLORS.label} fontSize={14} fontWeight="bold">Climate Node — I²C Sensor Hub</text>

      <Board x={espX} y={espY} w={espW} h={espH} label="ESP32-WROOM-32" sublabel="Climate Node" />
      <Pin x={espX + espW} y={espY + 60} label="3.3V" color={COLORS.power3v3} />
      <Pin x={espX + espW} y={espY + 80} label="GND" color={COLORS.gnd} />
      <Pin x={espX + espW} y={espY + 110} label="GPIO 21 (SDA)" color={COLORS.sda} />
      <Pin x={espX + espW} y={espY + 130} label="GPIO 22 (SCL)" color={COLORS.scl} />

      <Board x={sensorX} y={40} w={120} h={64} label="SHT31-D" sublabel="Temp + Humidity" />
      <Pin x={sensorX} y={62} label="VIN" color={COLORS.power3v3} side="left" />
      <Pin x={sensorX} y={82} label="GND" color={COLORS.gnd} side="left" />
      <Pin x={sensorX + 120} y={62} label="SDA" color={COLORS.sda} />
      <Pin x={sensorX + 120} y={82} label="SCL" color={COLORS.scl} />
      <text x={sensorX + 132} y={104} fill={COLORS.sublabel} fontSize={9}>addr 0x44</text>

      <Board x={sensorX} y={120} w={120} h={64} label="SCD41" sublabel="CO₂" />
      <Pin x={sensorX} y={142} label="VIN" color={COLORS.power3v3} side="left" />
      <Pin x={sensorX} y={162} label="GND" color={COLORS.gnd} side="left" />
      <Pin x={sensorX + 120} y={142} label="SDA" color={COLORS.sda} />
      <Pin x={sensorX + 120} y={162} label="SCL" color={COLORS.scl} />
      <text x={sensorX + 132} y={184} fill={COLORS.sublabel} fontSize={9}>addr 0x62</text>

      <Board x={sensorX} y={200} w={120} h={64} label="BH1750" sublabel="Light · Lux" />
      <Pin x={sensorX} y={222} label="VCC" color={COLORS.power3v3} side="left" />
      <Pin x={sensorX} y={242} label="GND" color={COLORS.gnd} side="left" />
      <Pin x={sensorX + 120} y={222} label="SDA" color={COLORS.sda} />
      <Pin x={sensorX + 120} y={242} label="SCL" color={COLORS.scl} />
      <text x={sensorX + 132} y={264} fill={COLORS.sublabel} fontSize={9}>addr 0x23</text>

      {/* 3.3V */}
      <Wire x1={espX + espW + 4} y1={espY + 60} x2={sensorX - 4} y2={62} color={COLORS.power3v3} label="3.3V" />
      <Wire x1={espX + espW + 4} y1={espY + 60} x2={sensorX - 4} y2={142} color={COLORS.power3v3} />
      <Wire x1={espX + espW + 4} y1={espY + 60} x2={sensorX - 4} y2={222} color={COLORS.power3v3} />

      {/* GND */}
      <Wire x1={espX + espW + 4} y1={espY + 80} x2={sensorX - 4} y2={82} color={COLORS.gnd} label="GND" />
      <Wire x1={espX + espW + 4} y1={espY + 80} x2={sensorX - 4} y2={162} color={COLORS.gnd} />
      <Wire x1={espX + espW + 4} y1={espY + 80} x2={sensorX - 4} y2={242} color={COLORS.gnd} />

      {/* SDA shared bus */}
      <Wire x1={espX + espW + 4} y1={espY + 110} x2={sensorX - 4} y2={62} color={COLORS.sda} label="SDA" labelPos={0.3} />
      <line x1={sensorX - 12} y1={62} x2={sensorX - 12} y2={222} stroke={COLORS.sda} strokeWidth={2} strokeDasharray="4 2" />

      {/* SCL shared bus */}
      <Wire x1={espX + espW + 4} y1={espY + 130} x2={sensorX - 22} y2={82} color={COLORS.scl} label="SCL" labelPos={0.3} />
      <line x1={sensorX - 30} y1={82} x2={sensorX - 30} y2={242} stroke={COLORS.scl} strokeWidth={2} strokeDasharray="4 2" />

      {/* GPIO 0 — factory reset (added in v3.4.9 firmware) */}
      <Pin x={espX} y={espY + 160} label="GPIO 0 (FACTORY RESET — hold 10s)" color="#eab308" side="left" />

      <Legend x={20} y={260} />
      <text x={300} y={300} textAnchor="middle" fill={COLORS.sublabel} fontSize={10}>
        All 3 sensors share the I²C bus (SDA + SCL). Power from ESP32 3.3V pin.
      </text>
    </svg>
  );
}

function RelayNodeDiagram() {
  const espX = 20;
  return (
    <svg viewBox="0 0 600 280" style={{ width: "100%", height: "auto" }}>
      <rect width="600" height="280" fill="var(--bg-2)" rx={8} />
      <text x={300} y={20} textAnchor="middle" fill={COLORS.label} fontSize={14} fontWeight="bold">Relay Node — MOSFET Fan Control · 4 channels</text>
      <Board x={espX} y={30} w={130} h={180} label="ESP32-WROOM-32" sublabel="Relay Node" />

      {[
        { gpio: "GPIO 25", name: "FAE Fan", y: 60 },
        { gpio: "GPIO 26", name: "Exhaust", y: 110 },
        { gpio: "GPIO 27", name: "Circulation", y: 160 },
        { gpio: "GPIO 14", name: "Aux / Mister", y: 210 },
      ].map((ch, i) => {
        const mosfetX = 250;
        const fanX = 450;
        const cy = ch.y;
        return (
          <g key={i}>
            <Pin x={espX + 130} y={cy} label={ch.gpio} color={COLORS.gpio} />
            <rect x={205} y={cy - 6} width={26} height={12} rx={2} fill={COLORS.board} stroke={COLORS.gpio} strokeWidth={1} />
            <text x={218} y={cy + 3} textAnchor="middle" fill={COLORS.sublabel} fontSize={7}>100R</text>
            <Board x={mosfetX} y={cy - 20} w={80} h={40} label="IRLZ44N" />
            <text x={mosfetX + 40} y={cy + 14} textAnchor="middle" fill={COLORS.sublabel} fontSize={7}>G  D  S</text>
            <rect x={345} y={cy - 10} width={36} height={20} rx={2} fill={COLORS.board} stroke={COLORS.power5v} strokeWidth={1} />
            <text x={363} y={cy + 4} textAnchor="middle" fill={COLORS.power5v} fontSize={7}>1N4007</text>
            <Board x={fanX} y={cy - 16} w={110} h={32} label={ch.name} sublabel="12V" />
            <Wire x1={espX + 134} y1={cy} x2={205} y2={cy} color={COLORS.gpio} />
            <line x1={231} y1={cy} x2={mosfetX} y2={cy} stroke={COLORS.gpio} strokeWidth={2} />
            <line x1={mosfetX + 80} y1={cy} x2={fanX} y2={cy} stroke={COLORS.power12v} strokeWidth={2} />
          </g>
        );
      })}

      <text x={520} y={250} textAnchor="middle" fill={COLORS.power12v} fontSize={11} fontWeight="bold">+12V Supply</text>
      {/* GPIO 0 — factory reset (relay node, espY=30 from Board call above) */}
      <Pin x={espX} y={30 + 170} label="GPIO 0 (FACTORY RESET — hold 10s)" color="#eab308" side="left" />
      <Legend x={20} y={230} />
    </svg>
  );
}

function LightingNodeDiagram() {
  const espX = 20;
  return (
    <svg viewBox="0 0 600 240" style={{ width: "100%", height: "auto" }}>
      <rect width="600" height="240" fill="var(--bg-2)" rx={8} />
      <text x={300} y={18} textAnchor="middle" fill={COLORS.label} fontSize={14} fontWeight="bold">Lighting Node — 10-bit PWM LED dimming</text>
      <Board x={espX} y={30} w={130} h={160} label="ESP32-WROOM-32" sublabel="Lighting Node" />
      {[
        { gpio: "GPIO 25", name: "6500K White", y: 60, color: "#f8fafc" },
        { gpio: "GPIO 26", name: "450nm Blue", y: 100, color: "#3b82f6" },
        { gpio: "GPIO 27", name: "660nm Red", y: 140, color: "#ef4444" },
        { gpio: "GPIO 14", name: "730nm Far-Red", y: 180, color: "#991b1b" },
      ].map((ch, i) => {
        const stripX = 410;
        return (
          <g key={i}>
            <Pin x={espX + 130} y={ch.y} label={ch.gpio} color={COLORS.gpio} />
            <rect x={220} y={ch.y - 12} width={70} height={24} rx={3} fill={COLORS.board} stroke={COLORS.gpio} strokeWidth={1} />
            <text x={255} y={ch.y + 3} textAnchor="middle" fill={COLORS.sublabel} fontSize={9}>IRLZ44N</text>
            <rect x={stripX} y={ch.y - 12} width={140} height={24} rx={3} fill={ch.color} fillOpacity={0.18} stroke={ch.color} strokeWidth={1.5} />
            <text x={stripX + 70} y={ch.y + 3} textAnchor="middle" fill={ch.color} fontSize={10} fontWeight="bold">{ch.name}</text>
            <line x1={espX + 134} y1={ch.y} x2={220} y2={ch.y} stroke={COLORS.gpio} strokeWidth={2} />
            <line x1={290} y1={ch.y} x2={stripX} y2={ch.y} stroke={COLORS.power12v} strokeWidth={2} />
          </g>
        );
      })}
      <text x={580} y={120} textAnchor="middle" fill={COLORS.power12v} fontSize={10} fontWeight="bold" transform="rotate(90,580,120)">+12V Supply</text>
      {/* GPIO 0 — factory reset */}
      <Pin x={espX} y={30 + 140} label="GPIO 0 (FACTORY RESET)" color="#eab308" side="left" />
      <text x={300} y={222} textAnchor="middle" fill={COLORS.sublabel} fontSize={10}>PWM 10-bit (0–1023) at 25kHz · smooth, flicker-free dimming</text>
    </svg>
  );
}

