interface Props {
  tierId: "bare_bones" | "recommended" | "all_the_things";
}

export function WiringDiagram({ tierId }: Props) {
  if (tierId === "bare_bones") {
    return (
      <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
        <ClimateNodeDiagram />
      </div>
    );
  }

  if (tierId === "recommended") {
    return (
      <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
        <ClimateNodeDiagram />
        <RelayNodeDiagram />
        <LightingNodeDiagram />
        <CameraNodeDiagram />
      </div>
    );
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <ClimateNodeDiagram />
      <RelayNodeDiagram />
      <LightingNodeDiagram />
      <CameraNodeDiagram />
      <div className="side-panel" style={{ borderColor: "var(--accent-line)" }}>
        <div className="head">All The Things — additional</div>
        <ul className="t-body" style={{ paddingLeft: 18, margin: 0, display: "flex", flexDirection: "column", gap: 6 }}>
          <li>+ Second Climate Node — wire identically, set <code>node_id</code> to <code>climate-02</code></li>
          <li>+ Second ESP32-CAM — wire identically, set <code>node_id</code> to <code>cam-02</code>, mount top-down</li>
          <li>+ HX711 Load Cell — DOUT → GPIO 32, SCK → GPIO 33 on relay node</li>
          <li>+ Reed Switch — one leg to any GPIO (INPUT_PULLUP), other to GND</li>
          <li>+ Peristaltic Pump — connect to relay node aux channel (GPIO 14) via IRLZ44N</li>
        </ul>
      </div>
    </div>
  );
}
