import { CloudSyncIndicator, PI_HEALTH, PI_LOCAL_FLEET, PageHeader } from "@sporeprint/design";

interface NodeHealth {
  name: string;
  state: "ok" | "warn" | "err";
  detail: string;
}

function nodeHealthFor(idx: number): NodeHealth[] {
  const climate: NodeHealth =
    idx === 4
      ? { name: "climate", state: "warn", detail: "SHT31 calibration drift 0.6°C — recal in 3 days" }
      : { name: "climate", state: "ok", detail: "SHT31 + SCD41 nominal · last cal 12d ago" };
  const relay: NodeHealth = { name: "relay", state: "ok", detail: "5 channels · all responsive" };
  const lighting: NodeHealth = { name: "lighting", state: "ok", detail: "PWM 24% · driver temp 41°C" };
  const cam: NodeHealth =
    idx === 1
      ? { name: "camera", state: "warn", detail: "frame rate dropped to 0.4 fps · check USB" }
      : { name: "camera", state: "ok", detail: "1 fps · last frame 8s ago" };
  return [climate, relay, lighting, cam];
}

export function HardwarePage() {
  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>monitor</span>
          <span className="sep">/</span>
          <b className="accent">hardware</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="On this Pi"
        title="Hardware health"
        italic={false}
        meta={<span>per-chamber sensor + relay + lighting + camera nodes</span>}
      />

      <div className="shell-body single">
        <main className="stack-14">
          {PI_LOCAL_FLEET.map((c, i) => {
            const nodes = nodeHealthFor(i);
            const worst = nodes.some((n) => n.state === "err") ? "err" : nodes.some((n) => n.state === "warn") ? "warn" : "ok";
            return (
              <section key={c.id} className="side-panel">
                <div className="row-between-baseline">
                  <div className="stack-4">
                    <span className="t-eyebrow" style={{ marginBottom: 0 }}>{c.id} · R{c.rack.rack}·S{c.rack.shelf}</span>
                    <h2 className="t-display-sm binomial">{c.species.binomial}</h2>
                  </div>
                  <span className={`status-pill ${worst === "ok" ? "signal" : worst === "warn" ? "warn" : "err"}`}>
                    {worst === "ok" ? "all nominal" : worst === "warn" ? "needs attention" : "fault"}
                  </span>
                </div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: 10 }}>
                  {nodes.map((n) => {
                    const tone = n.state === "ok" ? "signal" : n.state === "warn" ? "warn" : "err";
                    return (
                      <div key={n.name} className={`side-panel left-${tone}`} style={{ padding: 14 }}>
                        <span className="t-label">{n.name}</span>
                        <span className="t-mono">{n.detail}</span>
                      </div>
                    );
                  })}
                </div>
              </section>
            );
          })}
        </main>
      </div>
    </>
  );
}
