import { useMemo, useState } from "react";
import {
  CloudSyncIndicator,
  PI_HEALTH,
  PI_LOCAL_FLEET,
  PageHeader,
  PLANNER_MONTH,
} from "@sporeprint/design";

const DOW = ["mon", "tue", "wed", "thu", "fri", "sat", "sun"];
const EVENT_CLASS: Record<string, string> = { inoc: "signal", fruit: "", harvest: "warn", clean: "" };
const MONTHS = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

interface SlotConflict {
  day: number;
  reason: string;
  involved: string[];
  severity: "warn" | "err";
}

const CONFLICTS: SlotConflict[] = [
  { day: 14, reason: "harvest · K. trumpet · CH-14 overlaps with rack-3 cleaning slot", involved: ["CH-014", "rack-3"], severity: "warn" },
  { day: 18, reason: "harvest · L. mane · CH-07 same day as Reishi inoc — flow-hood double-book", involved: ["CH-007", "CH-023"], severity: "err" },
  { day: 21, reason: "PCO clean · rack-4 leaves only 2 idle chambers for spillover", involved: ["rack-4"], severity: "warn" },
];

interface ChamberSlot {
  id: string;
  phase: string;
  daysLeft: number;
  nextSlot: string;
}

function buildSlots(): ChamberSlot[] {
  return PI_LOCAL_FLEET.map((c) => {
    const total = c.day.total > 0 ? c.day.total : 14;
    const daysLeft = Math.max(0, total - c.day.current);
    return {
      id: c.id,
      phase: c.phase,
      daysLeft,
      nextSlot: daysLeft > 0 ? `Apr ${24 + daysLeft}` : "ready",
    };
  });
}

export function PlannerPage() {
  const [year, setYear] = useState(2026);
  const [monthIdx, setMonthIdx] = useState(3);
  const [draggingDay, setDraggingDay] = useState<number | null>(null);
  const [hoverDay, setHoverDay] = useState<number | null>(null);
  const [moves, setMoves] = useState<Array<{ from: number; to: number; label: string }>>([]);

  const slots = useMemo(buildSlots, []);

  const lead = useMemo(() => {
    const d = new Date(year, monthIdx, 1);
    return (d.getDay() + 6) % 7;
  }, [year, monthIdx]);
  const total = useMemo(() => new Date(year, monthIdx + 1, 0).getDate(), [year, monthIdx]);

  const cells: Array<{ day?: number; events: typeof PLANNER_MONTH[number]["events"] } | null> = [];
  for (let i = 0; i < lead; i++) cells.push(null);
  for (let day = 1; day <= total; day++) {
    const entry = PLANNER_MONTH.find((e) => e.day === day);
    cells.push({ day, events: entry?.events ?? [] });
  }
  while (cells.length < 42) cells.push(null);

  function shift(delta: number) {
    let m = monthIdx + delta;
    let y = year;
    while (m < 0) { m += 12; y -= 1; }
    while (m > 11) { m -= 12; y += 1; }
    setMonthIdx(m);
    setYear(y);
  }

  function handleDrop(targetDay: number) {
    if (draggingDay === null || draggingDay === targetDay) {
      setDraggingDay(null);
      setHoverDay(null);
      return;
    }
    const entry = PLANNER_MONTH.find((e) => e.day === draggingDay);
    const label = entry?.events[0]?.label ?? `event · day ${draggingDay}`;
    setMoves((prev) => [{ from: draggingDay, to: targetDay, label }, ...prev].slice(0, 6));
    setDraggingDay(null);
    setHoverDay(null);
  }

  const monthLabel = `${MONTHS[monthIdx]} ${year}`;
  const eventCount = cells.reduce((n, c) => n + (c?.events.length ?? 0), 0);
  const conflictCount = CONFLICTS.length;

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>plan</span>
          <span className="sep">/</span>
          <b className="accent">planner</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Plan"
        title={monthLabel}
        italic={false}
        meta={
          <span>
            {eventCount} events · {conflictCount} conflicts · drag a day to reschedule its event
          </span>
        }
        right={
          <div className="row-8">
            <button type="button" className="t-back-btn" onClick={() => shift(-1)} aria-label="previous month">←</button>
            <button type="button" className="t-back-btn" onClick={() => { setYear(2026); setMonthIdx(3); }}>today</button>
            <button type="button" className="t-back-btn" onClick={() => shift(1)} aria-label="next month">→</button>
            <button type="button" className="t-btn-primary">add event →</button>
          </div>
        }
      />

      <div className="shell-body pi">
        <main className="stack-14">
          <div className="calendar">
            {DOW.map((d) => (<div key={d} className="dow">{d}</div>))}
            {cells.map((c, i) => {
              if (!c) return <div key={`pad-${i}`} className="day dim" />;
              const hasEvents = c.events.length > 0;
              const isDragging = draggingDay === c.day;
              const isHover = hoverDay === c.day && draggingDay !== null && draggingDay !== c.day;
              return (
                <div
                  key={`d-${c.day}`}
                  className="day"
                  draggable={hasEvents}
                  onDragStart={() => hasEvents && setDraggingDay(c.day!)}
                  onDragOver={(e) => { e.preventDefault(); setHoverDay(c.day!); }}
                  onDragLeave={() => setHoverDay(null)}
                  onDrop={() => handleDrop(c.day!)}
                  onDragEnd={() => { setDraggingDay(null); setHoverDay(null); }}
                  style={{
                    cursor: hasEvents ? "grab" : "default",
                    opacity: isDragging ? 0.4 : 1,
                    borderColor: isHover ? "var(--accent-line)" : undefined,
                    background: isHover ? "var(--accent-soft)" : undefined,
                  }}
                >
                  <span className="dnum">{c.day}</span>
                  {c.events.map((e, ei) => (
                    <span key={ei} className={`event ${EVENT_CLASS[e.kind] ?? ""}`.trim()}>{e.label}</span>
                  ))}
                </div>
              );
            })}
          </div>

          {moves.length > 0 && (
            <section className="side-panel">
              <div className="head">Pending reschedules</div>
              <ul className="stack-8" style={{ listStyle: "none", padding: 0, margin: 0 }}>
                {moves.map((m, i) => (
                  <li key={`mv-${i}`} className="t-mono-sm row-between">
                    <span>{m.label}</span>
                    <span className="t-accent">day {m.from} → day {m.to}</span>
                  </li>
                ))}
              </ul>
              <button type="button" className="t-btn-primary" style={{ alignSelf: "flex-start" }}>commit reschedules →</button>
            </section>
          )}
        </main>

        <aside className="stack-14">
          <section className="side-panel">
            <div className="head">Conflicts · {conflictCount}</div>
            {CONFLICTS.length === 0 ? (
              <p className="t-body-sm">No conflicts detected for {monthLabel}.</p>
            ) : (
              <ul className="stack-10" style={{ listStyle: "none", padding: 0, margin: 0 }}>
                {CONFLICTS.map((c, i) => (
                  <li
                    key={`cf-${i}`}
                    className="stack-6"
                    style={{
                      padding: "12px 14px",
                      background: "var(--bg-2)",
                      border: `1px solid ${c.severity === "err" ? "var(--err)" : "var(--border-soft)"}`,
                      borderRadius: "var(--r-sm)",
                    }}
                  >
                    <div className="row-between">
                      <span className="t-mono">day {c.day}</span>
                      <span className={`status-pill ${c.severity}`}>{c.severity}</span>
                    </div>
                    <span className="t-body-sm">{c.reason}</span>
                    <div className="cluster" style={{ gap: 6 }}>
                      {c.involved.map((id) => (
                        <span key={id} className="t-mono-sm" style={{ background: "var(--bg-3)", padding: "2px 8px", borderRadius: "var(--r-sm)" }}>{id}</span>
                      ))}
                    </div>
                  </li>
                ))}
              </ul>
            )}
          </section>

          <section className="side-panel">
            <div className="head">Local chamber slots</div>
            <span className="t-mono-sm">{slots.length} chambers attached · next free slot per chamber</span>
            <table className="data-table">
              <thead>
                <tr>
                  <th scope="col">Chamber</th>
                  <th scope="col">Phase</th>
                  <th scope="col" className="num">Days left</th>
                  <th scope="col">Next slot</th>
                </tr>
              </thead>
              <tbody>
                {slots.map((s) => (
                  <tr key={s.id}>
                    <td className="mono-cell">{s.id}</td>
                    <td>{s.phase}</td>
                    <td className="num mono-cell">{s.daysLeft}d</td>
                    <td className="mono-cell">{s.nextSlot}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </section>
        </aside>
      </div>
    </>
  );
}
