import { useState } from "react";
import { Link, useParams } from "react-router-dom";
import {
  CloudSyncIndicator,
  PI_HEALTH,
  PI_LOCAL_FLEET,
  PageHeader,
  RangeSelector,
  TraceRow,
  chamberHistory,
} from "@sporeprint/design";
import type { TimeRange } from "@sporeprint/design";

interface Props {
  onBack: (id: string) => void;
}

const HOURS: Partial<Record<TimeRange, number>> = {
  LIVE: 1,
  "1H": 1,
  "4H": 4,
  "24H": 24,
};

export function ChamberHistoryPage({ onBack }: Props) {
  const { id } = useParams();
  const chamber = PI_LOCAL_FLEET.find((c) => c.id === id) ?? PI_LOCAL_FLEET[0]!;
  const [range, setRange] = useState<TimeRange>("4H");
  const hours = HOURS[range] ?? 4;
  const history = chamberHistory(chamber.id, hours);

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <Link to="/" style={{ color: "inherit", textDecoration: "none" }}>chambers</Link>
          <span className="sep">/</span>
          <Link to={`/chamber/${chamber.id}`} style={{ color: "inherit", textDecoration: "none" }}>
            {chamber.id.toLowerCase()}
          </Link>
          <span className="sep">/</span>
          <b className="accent">history</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow={chamber.species.common}
        title={chamber.species.binomial}
        meta={
          <span>
            {chamber.id} · {chamber.phase} · day {chamber.day.current}/{chamber.day.total}
          </span>
        }
        right={
          <div className="stack-8" style={{ alignItems: "flex-end" }}>
            <RangeSelector
              value={range}
              onChange={setRange}
              options={["LIVE", "1H", "4H", "24H"]}
            />
            <button type="button" onClick={() => onBack(chamber.id)} className="t-link-cta">
              ← back to chamber
            </button>
          </div>
        }
      />

      <div className="shell-body single">
        <main className="stack-16">
          <section
            style={{
              border: "1px solid var(--border-soft)",
              borderRadius: "var(--r-md)",
              overflow: "hidden",
            }}
          >
            <TraceRow
              channel="temp"
              trace={history.temp}
              nowValue={chamber.telemetry.tempF.toFixed(1)}
              delta="holding"
            />
            <TraceRow
              channel="hum"
              trace={history.hum}
              nowValue={Math.round(chamber.telemetry.humidity).toString()}
              delta={`mister · ${history.hum.ticks.length} cycles`}
              deltaActive
            />
            <TraceRow
              channel="co2"
              trace={history.co2}
              nowValue={Math.round(chamber.telemetry.co2).toString()}
              delta={`fae · ${history.co2.ticks.length} cycles`}
            />
            <TraceRow
              channel="vpd"
              trace={history.vpd}
              nowValue={chamber.telemetry.vpdKpa.toFixed(2)}
              delta="derived"
            />
            <div className="t-axis" aria-label="time axis">
              {history.axis.map((label) => (
                <span key={label}>{label}</span>
              ))}
            </div>
          </section>
          <p className="t-mono-sm">
            long-range history (&gt; 24h) opens on the cloud app — Pi keeps the last day local.
          </p>
        </main>
      </div>
    </>
  );
}
