"use client";

import { useCallback, useEffect, useState } from "react";
import {
  IntegrationsPanel,
  PageHeader,
  type IntegrationDriverState,
  type IntegrationState,
} from "@sporeprint/design";

/**
 * v4.1 third-party device integrations — Pi LAN UI surface.
 *
 * Fetches the live driver list from the Pi's own /api/integrations
 * endpoint (same-origin), so this page works equally well on
 * `chambers.local` and `localhost:5173` (dev).
 *
 * For free-tier Pis (the default), this is the only configuration
 * surface. Browsers can't reach a LAN Pi from the cloud-web shell, so
 * the cloud-web mirror in v4.1.x will be a paired-Pi proxy view rather
 * than a competing source of truth.
 */
export function IntegrationsPage() {
  const [drivers, setDrivers] = useState<IntegrationDriverState[]>([]);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  const refresh = useCallback(async () => {
    setLoading(true);
    setLoadError(null);
    try {
      const res = await fetch("/api/integrations", {
        credentials: "same-origin",
      });
      if (!res.ok) {
        throw new Error(`HTTP ${res.status}`);
      }
      const body = (await res.json()) as IntegrationDriverState[];
      setDrivers(body);
    } catch (err) {
      setLoadError(err instanceof Error ? err.message : "fetch failed");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  const onSave = useCallback(
    async (slug: string, enabled: boolean, config: Record<string, unknown>) => {
      const res = await fetch(`/api/integrations/${slug}/config`, {
        method: "PUT",
        credentials: "same-origin",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ enabled, config }),
      });
      if (!res.ok) {
        const text = await res.text();
        throw new Error(`HTTP ${res.status}: ${text.slice(0, 200)}`);
      }
      await refresh();
    },
    [refresh],
  );

  const onTest = useCallback(
    async (slug: string) => {
      const res = await fetch(`/api/integrations/${slug}/test`, {
        method: "POST",
        credentials: "same-origin",
      });
      if (!res.ok) {
        const text = await res.text();
        throw new Error(`HTTP ${res.status}: ${text.slice(0, 200)}`);
      }
      const body = (await res.json()) as {
        state: IntegrationState;
        last_error: string | null;
      };
      // Refresh after a successful test so the persisted health
      // snapshot updates.
      void refresh();
      return body;
    },
    [refresh],
  );

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <PageHeader
        title="Integrations"
        italic={false}
        meta="Third-party device drivers (Grafana · Aranet · Pulse Grow · …)"
      />
      {loadError ? (
        <p className="t-meta" style={{ color: "var(--err, #d97757)" }}>
          Failed to load integrations: {loadError}
        </p>
      ) : loading ? (
        <p className="t-meta">Loading…</p>
      ) : (
        <IntegrationsPanel
          drivers={drivers}
          callbacks={{ onSave, onTest }}
          intro={
            <span>
              Each driver runs locally on this Pi. Free-tier drivers
              (Grafana, Aranet) keep all data on your LAN. Premium drivers
              (Pulse Grow cloud) require a paired SporePrint subscription.
            </span>
          }
        />
      )}
    </div>
  );
}
