import { useMemo, useState } from "react";
import {
  CloudSyncIndicator,
  EXPERIMENTS,
  PageHeader,
  PI_HEALTH,
  Sparkline,
  chamberHistory,
  type ExperimentStub,
} from "@sporeprint/design";

function pickWinner(ex: ExperimentStub): "A" | "B" | "tie" {
  if (ex.armB.yieldGrams > ex.armA.yieldGrams) return "B";
  if (ex.armA.yieldGrams > ex.armB.yieldGrams) return "A";
  return "tie";
}

interface SigResult {
  delta: number;
  pctLift: number;
  /** Stub p-value computed from a simple variance hand-wave. */
  pValue: number;
  /** Significance label so we can color the pill. */
  label: "significant" | "marginal" | "not significant" | "underway";
}

function pseudoSignificance(ex: ExperimentStub): SigResult {
  if (ex.status === "running" || ex.armA.flushes === 0 || ex.armB.flushes === 0) {
    return { delta: 0, pctLift: 0, pValue: 1, label: "underway" };
  }
  const delta = ex.armB.yieldGrams - ex.armA.yieldGrams;
  const pctLift = ex.armA.yieldGrams ? (delta / ex.armA.yieldGrams) * 100 : 0;
  const absLift = Math.abs(pctLift);
  // Stub mapping — large lifts on multiple flushes get a stronger significance.
  const flushBoost = Math.min(ex.armA.flushes, ex.armB.flushes);
  const score = absLift * Math.sqrt(flushBoost);
  let pValue = 1;
  let label: SigResult["label"] = "not significant";
  if (score > 30) { pValue = 0.01; label = "significant"; }
  else if (score > 18) { pValue = 0.04; label = "significant"; }
  else if (score > 10) { pValue = 0.12; label = "marginal"; }
  else { pValue = 0.4; label = "not significant"; }
  return { delta, pctLift, pValue, label };
}

const SIG_TONE: Record<SigResult["label"], "accent" | "warn" | "signal" | "idle"> = {
  significant: "accent",
  marginal: "warn",
  "not significant": "signal",
  underway: "idle",
};

export function ExperimentsPage() {
  const [selectedId, setSelectedId] = useState<string>(EXPERIMENTS[0]?.id ?? "");
  const selected = useMemo(
    () => EXPERIMENTS.find((e) => e.id === selectedId) ?? EXPERIMENTS[0]!,
    [selectedId],
  );

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>track</span>
          <span className="sep">/</span>
          <b className="accent">experiments</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Track"
        title="Experiments"
        italic={false}
        meta={
          <span>
            {EXPERIMENTS.length} runs · A/B comparisons · pair two chambers · vary one parameter
          </span>
        }
        right={<button className="t-btn-primary" type="button">+ new experiment →</button>}
      />

      <div className="shell-body pi">
        <main className="stack-14">
          <div className="card-grid wide">
            {EXPERIMENTS.map((ex) => {
              const winning = pickWinner(ex);
              const sig = pseudoSignificance(ex);
              const isSelected = ex.id === selectedId;
              return (
                <article
                  key={ex.id}
                  className="card-cell"
                  onClick={() => setSelectedId(ex.id)}
                  style={{
                    cursor: "pointer",
                    borderColor: isSelected ? "var(--accent-line)" : "var(--border-soft)",
                  }}
                >
                  <div className="card-head">
                    <div className="title-block">
                      <span className="t-eyebrow" style={{ marginBottom: 0 }}>{ex.species}</span>
                      <h2 className="t-h3-sans">{ex.name}</h2>
                      <span className="t-mono-sm">variable: {ex.variable}</span>
                    </div>
                    <span className={`status-pill ${ex.status === "running" ? "accent" : "signal"}`}>{ex.status}</span>
                  </div>
                  <div style={{ display: "grid", gridTemplateColumns: "1fr auto 1fr", gap: 14, alignItems: "stretch" }}>
                    <Arm label={ex.armA.label} chamber={ex.armA.chamber} yieldG={ex.armA.yieldGrams} flushes={ex.armA.flushes} winning={winning === "A"} />
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "center", padding: "0 8px" }}>
                      <span className="t-eyebrow" style={{ marginBottom: 0 }}>vs</span>
                    </div>
                    <Arm label={ex.armB.label} chamber={ex.armB.chamber} yieldG={ex.armB.yieldGrams} flushes={ex.armB.flushes} winning={winning === "B"} />
                  </div>
                  <div className="cluster" style={{ marginTop: "auto" }}>
                    <span className={`status-pill ${SIG_TONE[sig.label]}`}>{sig.label}</span>
                    {sig.label !== "underway" && (
                      <span className="t-mono-sm">
                        Δ {sig.delta > 0 ? "+" : ""}{sig.delta}g · {sig.pctLift > 0 ? "+" : ""}{sig.pctLift.toFixed(1)}% · p≈{sig.pValue.toFixed(2)}
                      </span>
                    )}
                  </div>
                </article>
              );
            })}
          </div>
        </main>

        <aside className="stack-14">
          <DetailPanel experiment={selected} />
        </aside>
      </div>
    </>
  );
}

function DetailPanel({ experiment: ex }: { experiment: ExperimentStub }) {
  const sig = pseudoSignificance(ex);
  const histA = useMemo(() => chamberHistory(ex.armA.chamber, 4), [ex.armA.chamber]);
  const histB = useMemo(() => chamberHistory(ex.armB.chamber, 4), [ex.armB.chamber]);

  return (
    <>
      <section className="side-panel">
        <div className="head">Detail · {ex.id}</div>
        <h2 className="t-display-sm binomial">{ex.species}</h2>
        <span className="t-mono-sm">{ex.name}</span>
        {ex.hypothesis && (
          <div className="stack-4">
            <span className="t-eyebrow" style={{ marginBottom: 0 }}>hypothesis</span>
            <p className="t-body">{ex.hypothesis}</p>
            {typeof ex.confidencePre === "number" && (
              <div className="exp-hyp-meta">
                <span className="t-mono-sm">pre-confidence {ex.confidencePre}%</span>
                <div className="exp-confidence-bar" aria-hidden="true">
                  <i style={{ width: `${ex.confidencePre}%` }} />
                </div>
              </div>
            )}
          </div>
        )}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
          <Stat label="started" value={ex.startedOn ?? "—"} />
          <Stat label="ended" value={ex.endedOn ?? "—"} />
          <Stat label="primary var" value={ex.variable} />
          <Stat label="status" value={ex.status} />
        </div>
        {ex.additionalVariables && ex.additionalVariables.length > 0 && (
          <div className="stack-6">
            <span className="t-eyebrow" style={{ marginBottom: 0 }}>covaried</span>
            {ex.additionalVariables.map((v) => (
              <div key={v.name} className="row-between">
                <span className="t-mono-sm">{v.name}</span>
                <span className="t-mono-sm">{v.controlValue} → {v.treatmentValue}</span>
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="side-panel">
        <div className="head">Observations</div>
        <table className="data-table">
          <thead>
            <tr>
              <th scope="col" className="num">Flush</th>
              <th scope="col" className="num">{ex.armA.label}</th>
              <th scope="col" className="num">{ex.armB.label}</th>
              <th scope="col" className="num">Δ</th>
            </tr>
          </thead>
          <tbody>
            {(ex.armA.observations ?? []).map((o, i) => {
              const b = ex.armB.observations?.[i];
              const delta = b ? b.yieldGrams - o.yieldGrams : 0;
              const deltaClass = delta > 0 ? "t-accent" : delta < 0 ? "t-err" : "";
              return (
                <tr key={o.flush}>
                  <td className="num mono-cell">flush {o.flush}</td>
                  <td className="num mono-cell">{o.yieldGrams}g</td>
                  <td className="num mono-cell">{b ? `${b.yieldGrams}g` : "—"}</td>
                  <td className={`num mono-cell ${deltaClass}`}>
                    {delta > 0 ? "+" : ""}{delta}g
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        <div className="exp-sig-row">
          <Stat label="delta" value={sig.label === "underway" ? "—" : `${sig.delta > 0 ? "+" : ""}${sig.delta}g`} />
          <Stat label="lift" value={sig.label === "underway" ? "—" : `${sig.pctLift > 0 ? "+" : ""}${sig.pctLift.toFixed(1)}%`} />
          <Stat label="p-value" value={sig.label === "underway" ? "—" : sig.pValue.toFixed(2)} />
          <div className="stack-6" style={{ background: "var(--bg-2)", border: "1px solid var(--border-soft)", borderRadius: "var(--r-sm)", padding: 12 }}>
            <span className="t-label">test</span>
            <span className={`status-pill ${SIG_TONE[sig.label]}`}>{sig.label}</span>
          </div>
        </div>
      </section>

      <section className="side-panel">
        <div className="head">Side-by-side telemetry · 4h</div>
        <div className="exp-telem-grid">
          <div className="exp-telem-col">
            <div className="exp-telem-head">
              <span className="t-mono">{ex.armA.chamber}</span>
              <span className="t-mono-sm">control</span>
            </div>
            <Sparkline channel="temp" trace={histA.temp} label="temp" display={`${histA.temp.samples.at(-1)?.v.toFixed(1) ?? "—"}°F`} />
            <Sparkline channel="hum" trace={histA.hum} label="hum" display={`${histA.hum.samples.at(-1)?.v.toFixed(0) ?? "—"}%`} />
            <Sparkline channel="co2" trace={histA.co2} label="co₂" display={`${histA.co2.samples.at(-1)?.v.toFixed(0) ?? "—"}ppm`} />
          </div>
          <div className="exp-telem-col" style={{ borderColor: "var(--accent-line)" }}>
            <div className="exp-telem-head">
              <span className="t-mono">{ex.armB.chamber}</span>
              <span className="t-mono-sm t-accent">treatment</span>
            </div>
            <Sparkline channel="temp" trace={histB.temp} label="temp" display={`${histB.temp.samples.at(-1)?.v.toFixed(1) ?? "—"}°F`} />
            <Sparkline channel="hum" trace={histB.hum} label="hum" display={`${histB.hum.samples.at(-1)?.v.toFixed(0) ?? "—"}%`} />
            <Sparkline channel="co2" trace={histB.co2} label="co₂" display={`${histB.co2.samples.at(-1)?.v.toFixed(0) ?? "—"}ppm`} />
          </div>
        </div>
      </section>

      {ex.milestones && ex.milestones.length > 0 && (
        <section className="side-panel">
          <div className="head">Milestones</div>
          <ul className="exp-timeline" style={{ paddingLeft: 16 }}>
            {ex.milestones.map((m, i) => {
              const toneClass = m.tone === "a" ? "t-accent" : m.tone === "w" ? "t-warn" : m.tone === "e" ? "t-err" : "t-soft";
              return (
                <li key={`${m.on}-${i}`} className="t-body-sm">
                  <span className="t-mono-sm" style={{ marginRight: 6 }}>{m.on}</span>
                  <span className={toneClass}>
                    {m.label}
                  </span>
                </li>
              );
            })}
          </ul>
        </section>
      )}
    </>
  );
}

function Arm({ label, chamber, yieldG, flushes, winning }: { label: string; chamber: string; yieldG: number; flushes: number; winning: boolean }) {
  return (
    <div className="card-stat" style={{ borderColor: winning ? "var(--accent-line)" : "var(--border-soft)", padding: 16, gap: 6 }}>
      <span className="t-eyebrow" style={{ marginBottom: 0 }}>{label}</span>
      <span className="t-mono">{chamber}</span>
      <div className="row-16" style={{ alignItems: "baseline", marginTop: 6 }}>
        <div>
          <span className="t-label">yield</span>
          <div className={`t-num ${winning ? "t-accent" : ""}`}>{yieldG ? `${yieldG}g` : "—"}</div>
        </div>
        <div>
          <span className="t-label">flushes</span>
          <div className="t-num-sm">{flushes || "—"}</div>
        </div>
      </div>
    </div>
  );
}

function Stat({ label, value }: { label: string; value: string }) {
  return (
    <div className="stack-4" style={{ background: "var(--bg-2)", border: "1px solid var(--border-soft)", borderRadius: "var(--r-sm)", padding: 12 }}>
      <span className="t-label">{label}</span>
      <span className="t-mono">{value}</span>
    </div>
  );
}
