import { useState } from "react";
import { PublicTopBar } from "@sporeprint/design";

const SETUP_COMPLETE_KEY = "sporeprint:setup_complete";

/**
 * Mark first-run setup as complete on the Pi server, then mirror the
 * flag in localStorage. Best-effort — if the server call fails we
 * still set localStorage so the operator isn't stuck in a redirect
 * loop on an offline Pi.
 */
async function markSetupComplete(): Promise<void> {
  try {
    await fetch("/api/settings/setup-status", {
      method: "POST",
      credentials: "same-origin",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ setup_complete: true }),
    });
  } catch {
    // ignore — localStorage is the fallback
  }
  if (typeof window !== "undefined") {
    window.localStorage.setItem(SETUP_COMPLETE_KEY, "1");
  }
}

type Step = 1 | 2 | 3 | 4 | 5;

const STEPS: Record<Step, { roman: string; title: string; sub: string }> = {
  1: { roman: "§ I", title: "Welcome", sub: "Let's get your chambers online. This wizard takes about 5 minutes." },
  2: { roman: "§ II", title: "Network", sub: "Wired ethernet works without setup. WiFi networks ask once." },
  3: { roman: "§ III", title: "Cloud link", sub: "Pair this Pi to a paid sporeprint.ai account, or run locally only." },
  4: { roman: "§ IV", title: "First chamber", sub: "Scan the LAN for an unclaimed ESP32 chamber and add it to the rack." },
  5: { roman: "§ V", title: "Done", sub: "Your fleet is live at chambers.local. Everything else happens in flight." },
};

export function SetupPage() {
  const [step, setStep] = useState<Step>(1);
  const meta = STEPS[step];

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "var(--bg-0)",
        display: "flex",
        flexDirection: "column",
      }}
    >
      <PublicTopBar
        brand={{ word: "sporeprint", suffix: " · local" }}
        rightNav={<span className="t-eyebrow" style={{ marginBottom: 0 }}>First-run setup</span>}
      />

      {/* Step indicator strip */}
      <nav
        aria-label="setup progress"
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(5, 1fr)",
          padding: "0 40px",
          background: "var(--bg-1)",
          borderBottom: "1px solid var(--border-soft)",
        }}
      >
        {([1, 2, 3, 4, 5] as Step[]).map((s) => {
          const past = s < step;
          const current = s === step;
          return (
            <button
              key={s}
              type="button"
              onClick={() => setStep(s)}
              className="stack-4"
              style={{
                padding: "20px 16px",
                background: "transparent",
                border: "none",
                borderBottom: `3px solid ${current ? "var(--accent)" : past ? "var(--accent-line)" : "transparent"}`,
                color: current ? "var(--accent)" : past ? "var(--text-1)" : "var(--text-3)",
                cursor: "pointer",
                alignItems: "flex-start",
                textAlign: "left",
              }}
            >
              <span className="t-eyebrow" style={{ marginBottom: 0, color: "inherit" }}>
                {STEPS[s].roman}
              </span>
              <span className="t-h3-sans" style={{ color: "inherit" }}>
                {STEPS[s].title}
              </span>
            </button>
          );
        })}
      </nav>

      {/* Step body — generous, full-width */}
      <main
        className="stack-24"
        style={{
          flex: 1,
          maxWidth: 960,
          width: "100%",
          margin: "0 auto",
          padding: "48px 40px 64px",
        }}
      >
        <section className="stack-12">
          <span className="t-eyebrow">{meta.roman}</span>
          <h1 className="h-display">{meta.title}</h1>
          <p className="t-body-lg" style={{ maxWidth: 720 }}>{meta.sub}</p>
        </section>

        {step === 1 && <StepOne />}
        {step === 2 && <StepTwo />}
        {step === 3 && <StepThree />}
        {step === 4 && <StepFour />}
        {step === 5 && <StepFive />}

        {/* Bottom nav */}
        <nav
          className="row-between"
          style={{
            paddingTop: 24,
            borderTop: "1px solid var(--border-soft)",
          }}
        >
          <button
            type="button"
            disabled={step === 1}
            onClick={() => setStep((s) => (s > 1 ? ((s - 1) as Step) : s))}
            className="t-back-btn"
            style={step === 1 ? { opacity: 0.4, cursor: "not-allowed" } : undefined}
          >
            ← back
          </button>
          <button
            type="button"
            onClick={async () => {
              if (step === 5) {
                await markSetupComplete();
                window.location.href = "/";
              } else {
                setStep((s) => ((s + 1) as Step));
              }
            }}
            className="t-btn-primary"
          >
            {step === 5 ? "open fleet →" : "continue →"}
          </button>
        </nav>
      </main>
    </div>
  );
}

