import type { ChannelTrace } from "../data/types";

interface Props {
  /** Either pass a full ChannelTrace... */
  trace?: ChannelTrace;
  /** ...or a flat numeric series and let Sparkline derive the trace. */
  values?: number[];

  channel: "temp" | "hum" | "co2" | "vpd";
  label: string;
  /** Display value with unit ("64.2", "94", "812"). */
  display: string;
}

/**
 * Compact 22px-tall sparkline used in side panels per components.md §9.
 * For full oscilloscope traces use TraceRow.
 *
 * Accepts either a `trace: ChannelTrace` (preferred when ticks are
 * meaningful) or a flat `values: number[]` series for the common case
 * of "just plot these numbers".
 */
export function Sparkline({ channel, trace, values, label, display }: Props) {
  // Normalize: build a synthetic ChannelTrace if `values` was passed.
  const effective: ChannelTrace = trace
    ? trace
    : ((): ChannelTrace => {
        const vs = values ?? [];
        if (vs.length === 0) {
          return { samples: [], ticks: [], range: [0, 1] };
        }
        let lo = vs[0]!;
        let hi = vs[0]!;
        for (const v of vs) {
          if (v < lo) lo = v;
          if (v > hi) hi = v;
        }
        return {
          samples: vs.map((v, i) => ({ t: i, v })),
          ticks: [],
          range: [lo, hi],
        };
      })();

  const w = 100;
  const h = 22;
  const [lo, hi] = effective.range;
  const span = Math.max(1e-6, hi - lo);
  const n = effective.samples.length;
  const points = effective.samples
    .map((s, i) => {
      const x = (i / Math.max(1, n - 1)) * w;
      const y = h - ((s.v - lo) / span) * h;
      return `${i === 0 ? "M" : "L"} ${x.toFixed(1)} ${y.toFixed(1)}`;
    })
    .join(" ");
  return (
    <div className="c-sparkrow">
      <div className={`srow ${channel}`}>
        <span>{label}</span>
        <svg viewBox={`0 0 ${w} ${h}`} preserveAspectRatio="none" aria-hidden>
          <path className="spark" d={points} />
        </svg>
        <span className="val">{display}</span>
      </div>
    </div>
  );
}
