import { useMemo, useState } from "react";
import {
  ActuatorRow,
  AlertList,
  ALERTS,
  CloudSyncIndicator,
  EventFeed,
  FleetTile,
  PageHeader,
  PI_DASHBOARD_EVENTS,
  PI_DASHBOARD_KPIS,
  PI_FLEET_STATUS_LINE,
  PI_HEALTH,
  PI_HEALTH_TRACE,
  PI_LOCAL_FLEET,
  PI_NETWORK_STATS,
  PiHealthPanel,
  Sparkline,
} from "@sporeprint/design";
import type { ActuatorKey, AlertItem, Actuators, Chamber } from "@sporeprint/design";

interface Props {
  onSelect: (id: string) => void;
}

export function FleetPage({ onSelect }: Props) {
  // Active alert banner ─ surface the highest-severity unacked alert.
  const topAlert = useMemo<AlertItem | null>(() => {
    const ranked = [...ALERTS].sort((a, b) => sevWeight(b.severity) - sevWeight(a.severity));
    return ranked.find((a) => !a.acked) ?? null;
  }, []);

  // Quick actuator override target — defaults to the first warn chamber, else CH-007.
  const initialOverrideId = useMemo(() => {
    const warn = PI_LOCAL_FLEET.find((c) => c.state === "warn");
    return warn?.id ?? PI_LOCAL_FLEET[0]!.id;
  }, []);
  const [overrideTargetId, setOverrideTargetId] = useState(initialOverrideId);
  const overrideChamber = useMemo<Chamber>(
    () => PI_LOCAL_FLEET.find((c) => c.id === overrideTargetId) ?? PI_LOCAL_FLEET[0]!,
    [overrideTargetId],
  );
  const [overrides, setOverrides] = useState<Actuators>(overrideChamber.actuators);

  function applyOverride(key: ActuatorKey) {
    setOverrides((prev) => {
      const cur = prev[key];
      const next = !cur.on;
      return {
        ...prev,
        [key]: {
          ...cur,
          on: next,
          sub: cur.override ? cur.sub : `override · 5m`,
          override: cur.override
            ? undefined
            : {
                untilIso: new Date(Date.now() + 5 * 60_000).toISOString(),
                durationSec: 300,
              },
        },
      };
    });
  }

  function switchOverrideTarget(id: string) {
    setOverrideTargetId(id);
    const next = PI_LOCAL_FLEET.find((c) => c.id === id) ?? PI_LOCAL_FLEET[0]!;
    setOverrides(next.actuators);
  }

  const onlineCount = PI_LOCAL_FLEET.filter((c) => c.state !== "idle").length;
  const warnCount = PI_LOCAL_FLEET.filter((c) => c.state === "warn").length;
  const errCount = PI_LOCAL_FLEET.filter((c) => c.state === "err").length;

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>local</span>
          <span className="sep">/</span>
          <b className="accent">chambers</b>
        </nav>
        <div className="right">
          <span className="host-pill">
            {PI_HEALTH.hostname}
            <span className="mut">· {PI_HEALTH.ip}</span>
          </span>
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="On this Pi"
        title="Local chambers"
        italic={false}
        meta={
          <span>
            {PI_LOCAL_FLEET.length} attached · {onlineCount} online
            {warnCount > 0 && ` · ${warnCount} warn`}
            {errCount > 0 && ` · ${errCount} err`} · firmware {PI_HEALTH.firmwareVersion}
          </span>
        }
      />

      <div className="shell-body pi">
        <main className="stack-16">
          {/* ---------- Active alert banner ---------- */}
          {topAlert && (
            <div
              role="alert"
              className="t-banner-btn"
              style={{
                background:
                  topAlert.severity === "err"
                    ? "rgba(184, 100, 92, 0.10)"
                    : topAlert.severity === "warn"
                      ? "rgba(200, 150, 96, 0.10)"
                      : "var(--bg-1)",
                borderColor:
                  topAlert.severity === "err"
                    ? "var(--err)"
                    : topAlert.severity === "warn"
                      ? "var(--warn)"
                      : "var(--border-soft)",
                color:
                  topAlert.severity === "err"
                    ? "var(--err)"
                    : topAlert.severity === "warn"
                      ? "var(--warn)"
                      : "var(--text-1)",
                cursor: "pointer",
                textTransform: "none",
                letterSpacing: "0.04em",
              }}
              onClick={() => onSelect(topAlert.chamberId)}
            >
              <span className="row-12">
                <span className="live-dot warn" style={{ width: 8, height: 8 }} />
                <span className="t-eyebrow" style={{ color: "inherit" }}>
                  {topAlert.severity === "err"
                    ? "fault"
                    : topAlert.severity === "warn"
                      ? "watching"
                      : "info"}
                </span>
                <span className="t-mono t-strong">
                  {topAlert.chamberId}
                </span>
                <span className="t-body t-soft">
                  {topAlert.message}
                </span>
              </span>
              <span className="t-meta">{topAlert.ts} · open chamber →</span>
            </div>
          )}

          {/* ---------- Status line ---------- */}
          <section
            className="cluster"
            style={{
              padding: "14px 18px",
              background: "var(--bg-1)",
              border: "1px solid var(--border-soft)",
              borderRadius: "var(--r-md)",
            }}
            aria-label="Right now"
          >
            <span className="t-eyebrow">right now</span>
            <span className="t-body t-soft">
              {PI_FLEET_STATUS_LINE.sentence}
            </span>
            <span className="row-8" style={{ marginLeft: "auto" }}>
              <span className="status-pill signal">{PI_FLEET_STATUS_LINE.active} active</span>
              {PI_FLEET_STATUS_LINE.warn > 0 && (
                <span className="status-pill warn">{PI_FLEET_STATUS_LINE.warn} warn</span>
              )}
              {PI_FLEET_STATUS_LINE.err > 0 && (
                <span className="status-pill err">{PI_FLEET_STATUS_LINE.err} err</span>
              )}
            </span>
          </section>

          {/* ---------- KPI strip ---------- */}
          <section
            className="kpi-grid"
            style={{ gridTemplateColumns: "repeat(auto-fit, minmax(160px, 1fr))" }}
            aria-label="Pi system KPIs"
          >
            {PI_DASHBOARD_KPIS.map((kpi) => (
              <div key={kpi.label} className={`kpi-card ${kpi.tone === "signal" ? "signal" : kpi.tone === "accent" ? "accent" : ""}`}>
                <span className="kpi-label">{kpi.label}</span>
                <span className="kpi-value">
                  {kpi.value}
                  {kpi.unit && <span className="u">{kpi.unit}</span>}
                </span>
                {kpi.delta && <span className="kpi-delta">{kpi.delta}</span>}
              </div>
            ))}
          </section>

          {/* ---------- System sparklines ---------- */}
          <section className="side-panel" aria-label="Pi system trace · last hour">
            <div className="head">Pi system · last hour</div>
            <Sparkline channel="temp" trace={PI_HEALTH_TRACE.cpu} label="cpu %" display={String(PI_HEALTH.cpuPct)} />
            <Sparkline channel="hum" trace={PI_HEALTH_TRACE.mem} label="ram %" display={String(PI_HEALTH.memPct)} />
            <Sparkline channel="co2" trace={PI_HEALTH_TRACE.temp} label="temp °C" display={String(PI_HEALTH.tempC)} />
          </section>

          {/* ---------- Local fleet grid ---------- */}
          <section aria-label="Local fleet">
            <div className="t-eyebrow" style={{ marginBottom: 10 }}>
              Chambers
            </div>
            <div className="fleet-grid cols-3">
              {PI_LOCAL_FLEET.map((c) => {
                const offset = ((c.id.charCodeAt(c.id.length - 1) * 37) % 300) / 100;
                return (
                  <FleetTile
                    key={c.id}
                    chamber={c}
                    large
                    showRackPosition
                    pulseOffsetSec={offset}
                    onSelect={onSelect}
                    selected={c.id === overrideTargetId}
                  />
                );
              })}
            </div>
          </section>

          {/* ---------- Quick actuator overrides ---------- */}
          <section className="side-panel" aria-label="Quick overrides">
            <div className="head row-between">
              <span>Quick overrides · {overrideChamber.id}</span>
              <select
                aria-label="select chamber to override"
                className="t-input compact"
                value={overrideTargetId}
                onChange={(e) => switchOverrideTarget(e.target.value)}
                style={{ width: 200 }}
              >
                {PI_LOCAL_FLEET.map((c) => (
                  <option key={c.id} value={c.id}>
                    {c.id} · {c.species.common}
                  </option>
                ))}
              </select>
            </div>
            <p className="t-body" style={{ marginTop: -4 }}>
              5-minute manual pin. Rule automation pauses for the override window. Tap a tile above to switch target.
            </p>
            <ActuatorRow
              actuators={overrides}
              editable
              onOverride={(k) => applyOverride(k)}
            />
            <div className="row-between" style={{ justifyContent: "flex-end" }}>
              <button
                type="button"
                className="t-link-cta"
                onClick={() => onSelect(overrideChamber.id)}
              >
                open {overrideChamber.id} →
              </button>
            </div>
          </section>

          {/* ---------- Recent fleet alerts (full list) ---------- */}
          <section className="side-panel" aria-label="Recent alerts">
            <div className="head">Recent alerts</div>
            <AlertList alerts={ALERTS} onTap={(a) => onSelect(a.chamberId)} />
          </section>
        </main>

        {/* ---------- Right rail ---------- */}
        <aside className="stack-14">
          <PiHealthPanel health={PI_HEALTH} />

          <section className="side-panel" aria-label="Network">
            <div className="head">Network</div>
            <NetRow k="broker" v={`${PI_NETWORK_STATS.brokerHost}:${PI_NETWORK_STATS.brokerPort}`} />
            <NetRow k="connections" v={String(PI_NETWORK_STATS.brokerConnections)} />
            <NetRow
              k="rtt"
              v={`${PI_NETWORK_STATS.rttP50Ms}ms`}
              sub={`p95 ${PI_NETWORK_STATS.rttP95Ms}ms`}
            />
            <NetRow
              k="packet loss"
              v={`${PI_NETWORK_STATS.packetLossPct.toFixed(2)}%`}
              tone={
                PI_NETWORK_STATS.packetLossPct > 1
                  ? "err"
                  : PI_NETWORK_STATS.packetLossPct > 0.2
                    ? "warn"
                    : "ok"
              }
            />
            <NetRow
              k="rx"
              v={`${(PI_NETWORK_STATS.bytesRxKb / 1024).toFixed(1)} MB`}
              sub={`${PI_NETWORK_STATS.packetsRx.toLocaleString()} pkt`}
            />
            <NetRow
              k="tx"
              v={`${(PI_NETWORK_STATS.bytesTxKb / 1024).toFixed(1)} MB`}
              sub={`${PI_NETWORK_STATS.packetsTx.toLocaleString()} pkt`}
            />
            <NetRow k="reconnects" v={`${PI_NETWORK_STATS.reconnectsLast24h} / 24h`} />
          </section>

          <section className="side-panel" aria-label="Live event feed" style={{ padding: 0 }}>
            <EventFeed events={PI_DASHBOARD_EVENTS} title="Live events" />
          </section>
        </aside>
      </div>
    </>
  );
}

// ---------- Helpers ----------

function sevWeight(sev: "info" | "warn" | "err") {
  return sev === "err" ? 3 : sev === "warn" ? 2 : 1;
}

function NetRow({
  k,
  v,
  sub,
  tone,
}: {
  k: string;
  v: string;
  sub?: string;
  tone?: "ok" | "warn" | "err";
}) {
  const valueClass =
    tone === "err"
      ? "t-err"
      : tone === "warn"
        ? "t-warn"
        : tone === "ok"
          ? "t-signal"
          : "t-strong";
  return (
    <div
      style={{
        display: "grid",
        gridTemplateColumns: "1fr auto",
        alignItems: "baseline",
        gap: 12,
        padding: "10px 0",
        borderTop: "1px solid var(--border-soft)",
      }}
    >
      <span className="t-meta" style={{ textTransform: "uppercase", letterSpacing: "0.1em" }}>
        {k}
      </span>
      <span className="row-8" style={{ alignItems: "baseline" }}>
        <span className={`t-mono ${valueClass}`}>
          {v}
        </span>
        {sub && <span className="t-meta">· {sub}</span>}
      </span>
    </div>
  );
}
