import { useMemo, useState } from "react";
import { Link } from "react-router-dom";
import {
  Chip,
  ChipGroup,
  CloudSyncIndicator,
  DataTable,
  EventFeed,
  GROW_SESSIONS,
  KpiCard,
  PI_HEALTH,
  PI_LOCAL_FLEET,
  PageHeader,
  SearchInput,
  type GrowSessionStub,
  type HarvestStub,
  type SessionPhaseSegment,
} from "@sporeprint/design";

const PHASE_TONE: Record<GrowSessionStub["phase"], "accent" | "signal" | "warn" | "err" | "idle"> = {
  spawn: "signal",
  fruiting: "accent",
  harvest: "signal",
  complete: "idle",
  contam: "err",
};

type StatusFilter = "all" | "active" | "complete" | "contam";
type PhaseFilter = "all" | GrowSessionStub["phase"];
type SortMode = "newest" | "oldest" | "yield" | "duration";

export function SessionsPage() {
  // Pi only shows sessions on its own chambers.
  const localIds = new Set(PI_LOCAL_FLEET.map((c) => c.id));
  const allLocal = useMemo(
    () => GROW_SESSIONS.filter((s) => localIds.has(s.chamberId)),
    [localIds],
  );

  const [status, setStatus] = useState<StatusFilter>("all");
  const [phaseFilter, setPhaseFilter] = useState<PhaseFilter>("all");
  const [sort, setSort] = useState<SortMode>("newest");
  const [query, setQuery] = useState("");
  const [showNew, setShowNew] = useState(false);
  const [selectedId, setSelectedId] = useState<string>(allLocal[0]?.id ?? "");

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    let list = allLocal.filter((s) => {
      if (status === "active" && (s.phase === "complete" || s.phase === "contam")) return false;
      if (status === "complete" && s.phase !== "complete") return false;
      if (status === "contam" && s.phase !== "contam") return false;
      if (phaseFilter !== "all" && s.phase !== phaseFilter) return false;
      if (!q) return true;
      return [s.id, s.chamberId, s.species.binomial, s.species.common, s.substrate]
        .join(" ")
        .toLowerCase()
        .includes(q);
    });
    list = [...list];
    list.sort((a, b) => {
      switch (sort) {
        case "newest":
          return a.startedDaysAgo - b.startedDaysAgo;
        case "oldest":
          return b.startedDaysAgo - a.startedDaysAgo;
        case "yield":
          return (b.yieldGrams ?? 0) - (a.yieldGrams ?? 0);
        case "duration":
          return b.startedDaysAgo - a.startedDaysAgo;
      }
    });
    return list;
  }, [allLocal, status, phaseFilter, sort, query]);

  const selected = useMemo(
    () => filtered.find((s) => s.id === selectedId) ?? filtered[0] ?? allLocal[0],
    [filtered, selectedId, allLocal],
  );

  const kpis = useMemo(() => {
    const total = allLocal.length;
    const active = allLocal.filter((s) => s.phase !== "complete" && s.phase !== "contam").length;
    const completed = allLocal.filter((s) => s.phase === "complete").length;
    const contam = allLocal.filter((s) => s.phase === "contam").length;
    const contamRate = total > 0 ? contam / total : 0;
    const yieldRecent = allLocal
      .filter((s) => (s.yieldGrams ?? 0) > 0 && s.startedDaysAgo <= 30)
      .reduce((sum, s) => sum + (s.yieldGrams ?? 0), 0);
    return { total, active, completed, contam, contamRate, yieldRecent };
  }, [allLocal]);

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>monitor</span>
          <span className="sep">/</span>
          <b className="accent">grows</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="On this Pi"
        title="Grow sessions"
        italic={false}
        meta={
          <span>
            {filtered.length} of {allLocal.length} sessions on local chambers · last 30d yield {kpis.yieldRecent.toLocaleString()}g
          </span>
        }
        right={
          <button
            type="button"
            className={showNew ? "t-btn-primary" : "t-back-btn"}
            onClick={() => setShowNew((v) => !v)}
          >
            {showNew ? "cancel" : "+ new session"}
          </button>
        }
      />

      <div className="shell-body pi">
        <main className="stack-14">
          <section className="kpi-grid">
            <KpiCard label="active" value={kpis.active.toString()} tone="accent" />
            <KpiCard label="completed" value={kpis.completed.toString()} tone="signal" />
            <KpiCard label="contam rate" value={`${(kpis.contamRate * 100).toFixed(1)}%`} />
            <KpiCard label="yield · 30d" value={`${kpis.yieldRecent.toLocaleString()}g`} tone="accent" />
          </section>

          <Toolbar
            query={query}
            onQuery={setQuery}
            status={status}
            onStatus={setStatus}
            phaseFilter={phaseFilter}
            onPhaseFilter={setPhaseFilter}
            sort={sort}
            onSort={setSort}
          />

          {showNew && <NewSessionForm onClose={() => setShowNew(false)} />}

          <table className="data-table">
            <thead>
              <tr>
                <th scope="col">Session</th>
                <th scope="col">Chamber</th>
                <th scope="col">Species</th>
                <th scope="col">Substrate</th>
                <th scope="col">Phase</th>
                <th scope="col" className="num">Day</th>
                <th scope="col" className="num">Yield</th>
                <th scope="col" />
              </tr>
            </thead>
            <tbody>
              {filtered.map((s) => {
                const isSel = s.id === selectedId;
                return (
                  <tr
                    key={s.id}
                    onClick={() => setSelectedId(s.id)}
                    style={{
                      cursor: "pointer",
                      background: isSel ? "var(--accent-soft)" : undefined,
                    }}
                  >
                    <td className="mono-cell">{s.id}</td>
                    <td>
                      <Link to={`/chamber/${s.chamberId}`} className="t-link-mono">
                        {s.chamberId}
                      </Link>
                    </td>
                    <td className="binomial-cell">{s.species.binomial}</td>
                    <td>{s.substrate}</td>
                    <td>
                      <span className={`status-pill ${PHASE_TONE[s.phase]}`}>{s.phase}</span>
                    </td>
                    <td className="num mono-cell">{s.startedDaysAgo}d</td>
                    <td className="num mono-cell">
                      {s.yieldGrams !== null ? `${s.yieldGrams}g` : "—"}
                    </td>
                    <td className="num">
                      <Link to={`/chamber/${s.chamberId}`} className="t-link-cta">
                        open →
                      </Link>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>

          <p className="t-mono-sm">
            long-range session history opens on the cloud · Pi keeps the last 24h locally
          </p>
        </main>

        {selected && <DetailPanel session={selected} />}
      </div>
    </>
  );
}

function Toolbar({
  query,
  onQuery,
  status,
  onStatus,
  phaseFilter,
  onPhaseFilter,
  sort,
  onSort,
}: {
  query: string;
  onQuery: (v: string) => void;
  status: StatusFilter;
  onStatus: (s: StatusFilter) => void;
  phaseFilter: PhaseFilter;
  onPhaseFilter: (p: PhaseFilter) => void;
  sort: SortMode;
  onSort: (s: SortMode) => void;
}) {
  return (
    <section
      className="side-panel cluster"
      style={{ flexDirection: "row" }}
    >
      <div style={{ flex: "1 1 240px", minWidth: 200 }}>
        <SearchInput
          value={query}
          onChange={onQuery}
          placeholder="search id, chamber, species …"
          ariaLabel="search sessions"
        />
      </div>
      <ChipGroup label="status">
        {(["all", "active", "complete", "contam"] as const).map((s) => (
          <Chip key={s} active={status === s} onClick={() => onStatus(s)}>{s}</Chip>
        ))}
      </ChipGroup>
      <ChipGroup label="phase">
        {(["all", "spawn", "fruiting", "harvest", "complete", "contam"] as const).map((p) => (
          <Chip
            key={p}
            active={phaseFilter === p}
            onClick={() => onPhaseFilter(p as PhaseFilter)}
          >
            {p}
          </Chip>
        ))}
      </ChipGroup>
      <label className="row-8" style={{ marginLeft: "auto" }}>
        <span className="t-label">sort</span>
        <select
          value={sort}
          onChange={(e) => onSort(e.target.value as SortMode)}
          className="t-input compact"
          style={{ width: 160 }}
        >
          <option value="newest">newest</option>
          <option value="oldest">oldest</option>
          <option value="yield">yield (high → low)</option>
          <option value="duration">duration</option>
        </select>
      </label>
    </section>
  );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="form-field">
      <span className="form-label">{label}</span>
      {children}
    </label>
  );
}

function NewSessionForm({ onClose }: { onClose: () => void }) {
  const [chamber, setChamber] = useState(PI_LOCAL_FLEET[0]?.id ?? "");
  const [species, setSpecies] = useState("Pleurotus ostreatus");
  const [substrate, setSubstrate] = useState("MasterMix · 4lb");
  const [culture, setCulture] = useState("");
  return (
    <form
      className="side-panel stack-12"
      onSubmit={(e) => {
        e.preventDefault();
        onClose();
      }}
    >
      <div className="head">New session</div>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
          gap: 12,
        }}
      >
        <Field label="Chamber">
          <select className="t-input" value={chamber} onChange={(e) => setChamber(e.target.value)}>
            {PI_LOCAL_FLEET.map((c) => (
              <option key={c.id} value={c.id}>
                {c.id} · {c.species.common}
              </option>
            ))}
          </select>
        </Field>
        <Field label="Species (binomial)">
          <input className="t-input" value={species} onChange={(e) => setSpecies(e.target.value)} />
        </Field>
        <Field label="Substrate">
          <input className="t-input" value={substrate} onChange={(e) => setSubstrate(e.target.value)} />
        </Field>
        <Field label="Culture (optional)">
          <input className="t-input" value={culture} onChange={(e) => setCulture(e.target.value)} placeholder="e.g. C-001.1.a.s2" />
        </Field>
      </div>
      <div className="row-10" style={{ justifyContent: "flex-end" }}>
        <button type="button" className="t-back-btn" onClick={onClose}>
          cancel
        </button>
        <button type="submit" className="t-btn-primary">
          start session →
        </button>
      </div>
    </form>
  );
}

function DetailPanel({ session }: { session: GrowSessionStub }) {
  const isActive = session.phase !== "complete" && session.phase !== "contam";
  const phaseDay = session.phaseDayTotal ?? Math.max(session.startedDaysAgo, 1);
  const currentSegment = session.phaseSegments?.find((p) => p.active);
  const currentDays = currentSegment?.days ?? 0;
  const pct = Math.min(100, Math.round((currentDays / Math.max(1, phaseDay)) * 100));
  return (
    <aside className="stack-14">
      <section className="side-panel">
        <div className="head">{session.id} · {session.chamberId}</div>
        <span className="t-mono-sm t-muted">
          started {session.startedOn ?? `${session.startedDaysAgo}d ago`}
          {session.cultureId && ` · culture ${session.cultureId}`}
          {session.endedOn && ` · ended ${session.endedOn}`}
        </span>

        <h2 className="t-display-sm binomial">{session.species.binomial}</h2>
        <span className="t-body-sm">{session.species.common} · {session.substrate}</span>

        <PhaseProgress segments={session.phaseSegments} pct={pct} totalDays={phaseDay} />

        {session.notes && (
          <p className="t-body-sm t-soft">
            {session.notes}
          </p>
        )}
      </section>

      <section className="side-panel">
        <div className="head">Run summary</div>
        <div className="kpi-grid" style={{ gridTemplateColumns: "1fr 1fr" }}>
          <KpiCard label="mister cycles" value={(session.misterCycles ?? 0).toLocaleString()} />
          <KpiCard label="fae cycles" value={(session.faeCycles ?? 0).toLocaleString()} />
          {session.env && (
            <>
              <KpiCard label="avg temp" value={`${session.env.tempAvgF.toFixed(1)}°F`} />
              <KpiCard label="avg rh" value={`${session.env.humAvgPct.toFixed(0)}%`} tone="accent" />
              <KpiCard label="avg co₂" value={`${session.env.co2AvgPpm.toFixed(0)}ppm`} tone="signal" />
              <KpiCard label="avg vpd" value={`${session.env.vpdAvgKpa.toFixed(2)}kPa`} />
            </>
          )}
        </div>
        {session.bioEfficiency && (
          <span className="t-mono-sm">bio-efficiency · {session.bioEfficiency}</span>
        )}
      </section>

      {session.harvests && session.harvests.length > 0 && (
        <section className="side-panel">
          <div className="head">Harvest log</div>
          <table className="data-table compact">
            <thead>
              <tr>
                <th scope="col" className="num">#</th>
                <th scope="col">Date</th>
                <th scope="col" className="num">Wet</th>
                <th scope="col" className="num">Dry</th>
                <th scope="col">Quality</th>
              </tr>
            </thead>
            <tbody>
              {session.harvests.map((h: HarvestStub) => (
                <tr key={h.flush}>
                  <td className="num mono-cell">{h.flush}</td>
                  <td className="mono-cell">{h.date}</td>
                  <td className="num mono-cell">{h.wetGrams}g</td>
                  <td className="num mono-cell">{h.dryGrams}g</td>
                  <td>
                    <span className={`status-pill ${
                      h.quality === "excellent" ? "accent" : h.quality === "good" ? "signal" : "warn"
                    }`}>{h.quality}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>
      )}

      {session.contaminations && session.contaminations.length > 0 && (
        <section className="side-panel tone-err">
          <div className="head t-err">Contamination events</div>
          <ul className="stack-8" style={{ listStyle: "none", padding: 0, margin: 0 }}>
            {session.contaminations.map((c, i) => (
              <li
                key={i}
                style={{
                  padding: "10px 12px",
                  background: "var(--bg-2)",
                  border: "1px solid var(--border-soft)",
                  borderRadius: "var(--r-sm)",
                }}
              >
                <div className="t-mono-sm t-faint">{c.ts}</div>
                <div className="t-body-sm">
                  {c.classification} · confidence {c.confidence.toFixed(2)} · {c.resolved ? "resolved" : "unresolved"}
                </div>
              </li>
            ))}
          </ul>
        </section>
      )}

      {session.timeline && session.timeline.length > 0 && (
        <EventFeed events={session.timeline} title="Session timeline" />
      )}

      <section className="side-panel">
        <div className="head">Actions</div>
        <div className="cluster">
          {isActive && (
            <>
              <button className="t-btn-primary" type="button">log harvest →</button>
              <button className="t-back-btn" type="button">extend window</button>
              <button className="t-back-btn t-warn" type="button">
                mark contaminated
              </button>
              <button className="t-back-btn t-err" type="button">
                end session
              </button>
            </>
          )}
          {!isActive && (
            <button className="t-back-btn" type="button">view archived data →</button>
          )}
        </div>
      </section>
    </aside>
  );
}

function PhaseProgress({
  segments,
  pct,
  totalDays,
}: {
  segments: SessionPhaseSegment[] | undefined;
  pct: number;
  totalDays: number;
}) {
  if (!segments || segments.length === 0) return null;
  const totalSegmentDays = segments.reduce((sum, s) => sum + s.days, 0) || 1;
  return (
    <div className="stack-6">
      <span className="t-eyebrow" style={{ marginBottom: 0 }}>
        Phase progress · day {segments.find((s) => s.active)?.days ?? totalSegmentDays}/{totalDays}
      </span>
      <div
        style={{
          display: "flex",
          height: 16,
          borderRadius: "var(--r-pill)",
          overflow: "hidden",
          border: "1px solid var(--border-soft)",
        }}
      >
        {segments.map((seg, i) => (
          <div
            key={i}
            title={`${seg.phase} · ${seg.days}d`}
            style={{
              flex: seg.days,
              background: seg.active ? "var(--accent)" : i % 2 === 0 ? "var(--bg-2)" : "var(--signal-soft)",
            }}
          />
        ))}
      </div>
      <span className="t-mono-sm t-faint">
        active phase · {pct}% complete
      </span>
    </div>
  );
}

