import { useEffect } from "react";
import { BrowserRouter, Route, Routes, useLocation, useNavigate } from "react-router-dom";
import { AppShell } from "./components/AppShell";
import { FleetPage } from "./pages/FleetPage";
import { ChamberDetailPage } from "./pages/ChamberDetailPage";
import { ChamberHistoryPage } from "./pages/ChamberHistoryPage";
import { SetupPage } from "./pages/SetupPage";
import { FirmwarePage } from "./pages/FirmwarePage";
import { SessionsPage } from "./pages/SessionsPage";
import { HardwarePage } from "./pages/HardwarePage";
import { VisionPage } from "./pages/VisionPage";
import { AutomationPage } from "./pages/AutomationPage";
import { SpeciesPage } from "./pages/SpeciesPage";
import { CulturesPage } from "./pages/CulturesPage";
import { ContaminationPage } from "./pages/ContaminationPage";
import { SettingsPage } from "./pages/SettingsPage";
import { IntegrationsPage } from "./pages/IntegrationsPage";
import { BuilderPage } from "./pages/BuilderPage";
import { PlannerPage } from "./pages/PlannerPage";
import { WizardPage } from "./pages/WizardPage";
import { ChambersInventoryPage } from "./pages/ChambersInventoryPage";
import { ExperimentsPage } from "./pages/ExperimentsPage";
import { ShoppingPage } from "./pages/ShoppingPage";
import { TranscriptsPage } from "./pages/TranscriptsPage";

const SETUP_COMPLETE_KEY = "sporeprint:setup_complete";

/**
 * On boot, ask the Pi server whether first-run setup has finished. If
 * not, redirect to /setup. We mirror the answer in localStorage so a
 * brief network blip doesn't keep redirecting an already-set-up Pi.
 *
 * The setup wizard's finish step POSTs to /api/settings/setup-status —
 * once that lands the redirect stops firing.
 */
function SetupGate() {
  const navigate = useNavigate();
  const { pathname } = useLocation();

  useEffect(() => {
    // Already on setup → nothing to do.
    if (pathname === "/setup") return;

    let cancelled = false;
    (async () => {
      // Cached "completed" answer means we don't need to bug the API
      // on every navigation. The flag is sticky; only the wizard /
      // operator clears it.
      if (typeof window !== "undefined") {
        const cached = window.localStorage.getItem(SETUP_COMPLETE_KEY);
        if (cached === "1") return;
      }

      try {
        const res = await fetch("/api/settings/setup-status", {
          credentials: "same-origin",
        });
        if (!res.ok) return; // older Pi server without the endpoint — don't redirect
        const json = (await res.json()) as { setup_complete?: boolean };
        if (cancelled) return;
        if (json.setup_complete === true) {
          if (typeof window !== "undefined") {
            window.localStorage.setItem(SETUP_COMPLETE_KEY, "1");
          }
          return;
        }
        navigate("/setup", { replace: true });
      } catch {
        // Network error — leave the operator on whatever route they
        // requested rather than punting them to setup.
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [pathname, navigate]);

  return null;
}

export default function App() {
  return (
    <BrowserRouter>
      <SetupGate />
      <Routes>
        <Route path="/" element={<Wrap><FleetWithNav /></Wrap>} />
        <Route path="/chamber/:id" element={<Wrap><ChamberDetailWithNav /></Wrap>} />
        <Route path="/chamber/:id/history" element={<Wrap><ChamberHistoryWithNav /></Wrap>} />
        <Route path="/sessions" element={<Wrap><SessionsPage /></Wrap>} />
        <Route path="/hardware" element={<Wrap><HardwarePage /></Wrap>} />
        <Route path="/vision" element={<Wrap><VisionPage /></Wrap>} />
        <Route path="/automation" element={<Wrap><AutomationPage /></Wrap>} />
        <Route path="/species" element={<Wrap><SpeciesPage /></Wrap>} />
        <Route path="/planner" element={<Wrap><PlannerPage /></Wrap>} />
        <Route path="/wizard" element={<Wrap><WizardPage /></Wrap>} />
        <Route path="/shopping" element={<Wrap><ShoppingPage /></Wrap>} />
        <Route path="/cultures" element={<Wrap><CulturesPage /></Wrap>} />
        <Route path="/inventory" element={<Wrap><ChambersInventoryPage /></Wrap>} />
        <Route path="/experiments" element={<Wrap><ExperimentsPage /></Wrap>} />
        <Route path="/contamination" element={<Wrap><ContaminationPage /></Wrap>} />
        <Route path="/transcripts" element={<Wrap><TranscriptsPage /></Wrap>} />
        <Route path="/builder" element={<Wrap><BuilderPage /></Wrap>} />
        <Route path="/firmware" element={<Wrap><FirmwarePage /></Wrap>} />
        <Route path="/settings" element={<Wrap><SettingsPage /></Wrap>} />
        <Route path="/integrations" element={<Wrap><IntegrationsPage /></Wrap>} />
        {/* Setup runs full-bleed */}
        <Route path="/setup" element={<SetupPage />} />
      </Routes>
    </BrowserRouter>
  );
}

function Wrap({ children }: { children: React.ReactNode }) {
  return <AppShell>{children}</AppShell>;
}

function FleetWithNav() {
  const navigate = useNavigate();
  return <FleetPage onSelect={(id) => navigate(`/chamber/${id}`)} />;
}

function ChamberDetailWithNav() {
  const navigate = useNavigate();
  return <ChamberDetailPage onBack={() => navigate("/")} onHistory={(id) => navigate(`/chamber/${id}/history`)} />;
}

function ChamberHistoryWithNav() {
  const navigate = useNavigate();
  return <ChamberHistoryPage onBack={(id) => navigate(`/chamber/${id}`)} />;
}
