import { useMemo, useState } from "react";
import {
  CloudSyncIndicator,
  DataTable,
  PageHeader,
  PI_HEALTH,
  TRANSCRIPTS,
  type SessionTranscriptStub,
} from "@sporeprint/design";

const STATUS_TONE: Record<SessionTranscriptStub["status"], "accent" | "signal" | "err"> = {
  active: "accent",
  complete: "signal",
  contam: "err",
};

interface MarkdownBlock {
  kind: "h1" | "h2" | "h3" | "p" | "ul" | "kv";
  text?: string;
  items?: string[];
  pairs?: Array<[string, string]>;
}

function buildMarkdown(t: SessionTranscriptStub): MarkdownBlock[] {
  const blocks: MarkdownBlock[] = [
    { kind: "h1", text: `Session ${t.sessionId}` },
    { kind: "h2", text: "Summary" },
    {
      kind: "kv",
      pairs: [
        ["species", t.species],
        ["status", t.status],
        ["phase", t.phase],
        ["duration", `${t.durationDays}d`],
        ["yield", t.yieldGrams !== null ? `${t.yieldGrams}g` : "—"],
        ["flushes", String(t.flushes)],
      ],
    },
    { kind: "h2", text: "Phase log" },
    {
      kind: "ul",
      items: t.status === "contam"
        ? [
            "day 1 · spawn loaded · 1.2 lb mastersmix",
            "day 3 · colonization 35% · ok",
            "day 4 · vision flagged Trichoderma · auto-suspend triggered",
            "day 4 · session ended · chamber decontaminated",
          ]
        : [
            "day 1 · spawn loaded · substrate batch logged",
            "day 5 · 60% colonised · vigour normal",
            "day 9 · pin set · primordia uniform",
            t.status === "complete" ? "harvest closed · chamber reset" : "actively fruiting · flush in progress",
          ],
    },
    { kind: "h2", text: "Environment window" },
    {
      kind: "ul",
      items: [
        "temperature 64.2°F avg · ±0.4°F band",
        "humidity 94.0% avg · ±1.5% band",
        "co₂ 812ppm avg · 4 fae cycles per hour",
        "vpd 0.08kPa avg · within target",
      ],
    },
  ];
  if (t.status === "complete" && t.yieldGrams) {
    blocks.push(
      { kind: "h2", text: "Harvest" },
      {
        kind: "ul",
        items: [
          `flush 1 · ${Math.round(t.yieldGrams * 0.6)}g wet · grade A`,
          t.flushes >= 2 ? `flush 2 · ${Math.round(t.yieldGrams * 0.4)}g wet · grade B` : "flush 2 · n/a",
          "no contamination across the run",
        ],
      },
    );
  }
  blocks.push(
    { kind: "h3", text: "Operator notes" },
    {
      kind: "p",
      text:
        t.status === "contam"
          ? "Chamber pulled early after Trichoderma flagged on the substrate corner. Pressure-cooker cycle re-validated — psi sag suspected."
          : "Run tracked the standard playbook. No interventions required beyond scheduled fae and mist.",
    },
  );
  return blocks;
}

interface AnalysisResult {
  overallScore: number;
  bands: Array<{ label: string; score: number }>;
  highlights: string[];
  warnings: string[];
}

function buildAnalysis(t: SessionTranscriptStub): AnalysisResult {
  if (t.status === "contam") {
    return {
      overallScore: 18,
      bands: [
        { label: "environment", score: 62 },
        { label: "yield", score: 0 },
        { label: "consistency", score: 8 },
        { label: "contamination", score: 12 },
      ],
      highlights: ["Caught early — chamber decon happened within 18 hours of vision alert."],
      warnings: [
        "Sterilisation cycle ran short (psi sag). Re-validate gauge before next batch.",
        "RH held above 96% for 36h before pin set — high enough to widen the trichoderma window.",
      ],
    };
  }
  const yieldScore = t.yieldGrams ? Math.min(100, Math.round((t.yieldGrams / 600) * 100)) : 30;
  const overall = Math.min(100, Math.round((yieldScore + 80 + 88 + 92) / 4));
  return {
    overallScore: overall,
    bands: [
      { label: "environment", score: 92 },
      { label: "yield", score: yieldScore },
      { label: "consistency", score: 88 },
      { label: "contamination", score: 80 },
    ],
    highlights: [
      "Temp + humidity stayed within band 96.4% of the run.",
      "Flush 1 came in at the higher end of expected yield.",
      "No actuator stalls or rule-fire skips.",
    ],
    warnings: t.flushes < 2 ? ["Flush 2 yield will need one more week of monitoring."] : [],
  };
}

const SCORE_TONE = (n: number): "accent" | "signal" | "warn" | "err" => {
  if (n >= 80) return "accent";
  if (n >= 60) return "signal";
  if (n >= 40) return "warn";
  return "err";
};

export function TranscriptsPage() {
  const [selectedId, setSelectedId] = useState<number>(TRANSCRIPTS[0]?.id ?? 1);
  const [view, setView] = useState<"markdown" | "analysis">("markdown");
  const [analyzed, setAnalyzed] = useState<Set<number>>(new Set());
  const selected = useMemo(
    () => TRANSCRIPTS.find((t) => t.id === selectedId) ?? TRANSCRIPTS[0]!,
    [selectedId],
  );
  const blocks = useMemo(() => buildMarkdown(selected), [selected]);
  const analysis = useMemo(() => buildAnalysis(selected), [selected]);

  function runAnalysis() {
    setAnalyzed((prev) => new Set(prev).add(selected.id));
    setView("analysis");
  }

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>track</span>
          <span className="sep">/</span>
          <b className="accent">transcripts</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Track"
        title="Session transcripts"
        italic={false}
        meta={<span>structured grow logs · export json/markdown · claude analysis on demand</span>}
      />

      <div className="shell-body pi">
        <main className="stack-14">
          <DataTable<SessionTranscriptStub>
            rowKey={(t) => t.id}
            columns={[
              { key: "session", header: "Session", render: (t) => (
                <button
                  type="button"
                  onClick={() => { setSelectedId(t.id); setView("markdown"); }}
                  className="t-link-mono"
                >
                  {t.sessionId}
                </button>
              ) },
              { key: "species", header: "Species", render: (t) => <span className="binomial-cell">{t.species}</span> },
              { key: "status", header: "Status", render: (t) => (
                <span className={`status-pill ${STATUS_TONE[t.status]}`}>{t.status}</span>
              ) },
              { key: "phase", header: "Phase", render: (t) => <>{t.phase}</> },
              { key: "days", header: "Days", align: "right", render: (t) => <span className="mono-cell">{t.durationDays}d</span> },
              { key: "yield", header: "Yield", align: "right", render: (t) => (
                <span className="mono-cell">{t.yieldGrams !== null ? `${t.yieldGrams}g` : "—"}</span>
              ) },
              { key: "flushes", header: "Flushes", align: "right", render: (t) => <span className="mono-cell">{t.flushes || "—"}</span> },
              { key: "export", header: "Export", align: "right", render: () => (
                <button type="button" className="t-link-cta">json →</button>
              ) },
            ]}
            rows={TRANSCRIPTS}
          />

          <section className="side-panel">
            <div className="row-between" style={{ flexWrap: "wrap" }}>
              <div className="head" style={{ marginBottom: 0 }}>
                {view === "markdown" ? "Markdown preview" : "Claude analysis"} · {selected.sessionId}
              </div>
              <div className="row-8">
                <button
                  type="button"
                  className={`t-back-btn${view === "markdown" ? " t-accent" : ""}`}
                  onClick={() => setView("markdown")}
                  style={view === "markdown" ? { borderColor: "var(--accent-line)" } : undefined}
                >
                  preview
                </button>
                <button
                  type="button"
                  className={`t-back-btn${view === "analysis" ? " t-accent" : ""}`}
                  onClick={() => setView("analysis")}
                  disabled={!analyzed.has(selected.id) && !selected.analysisAvailable}
                  style={view === "analysis" ? { borderColor: "var(--accent-line)" } : undefined}
                >
                  analysis
                </button>
              </div>
            </div>
            {view === "markdown" ? (
              <article className="stack-14" style={{ padding: "12px 4px" }}>
                {blocks.map((b, i) => (
                  <RenderBlock key={i} b={b} />
                ))}
              </article>
            ) : (
              <AnalysisView analysis={analysis} />
            )}
          </section>
        </main>

        <aside className="stack-14">
          <section className="side-panel">
            <div className="head">Selected · {selected.sessionId}</div>
            <h2 className="t-display-sm binomial">{selected.species}</h2>
            <div className="stack-10">
              <Row k="status" v={selected.status} />
              <Row k="phase" v={selected.phase} />
              <Row k="duration" v={`${selected.durationDays}d`} />
              <Row k="yield" v={selected.yieldGrams !== null ? `${selected.yieldGrams}g` : "—"} />
              <Row k="flushes" v={selected.flushes.toString()} />
            </div>
            <div className="stack-10" style={{ marginTop: 8 }}>
              <button type="button" className="t-back-btn">export json</button>
              <button type="button" className="t-back-btn">export markdown</button>
              <button type="button" className="t-back-btn">copy to clipboard</button>
            </div>
          </section>

          {(selected.analysisAvailable || analyzed.has(selected.id)) && (
            <section className="side-panel">
              <div className="head">Claude analysis</div>
              <p className="t-body-sm">
                Available for this session — runs against captured telemetry, actuator log, harvest metadata.
                Analysis is BYOK on the Pi (rate limit applies).
              </p>
              <button
                type="button"
                className="t-btn-primary"
                onClick={runAnalysis}
              >
                {analyzed.has(selected.id) ? "re-run analysis →" : "analyze →"}
              </button>
              {analyzed.has(selected.id) && (
                <div
                  className="stack-6"
                  style={{
                    background: "var(--bg-2)",
                    border: "1px solid var(--border-soft)",
                    borderRadius: "var(--r-sm)",
                    padding: 12,
                  }}
                >
                  <span className="t-eyebrow" style={{ marginBottom: 0 }}>overall</span>
                  <div className="row-8" style={{ alignItems: "baseline" }}>
                    <span className={`t-num ${SCORE_TONE(analysis.overallScore) === "accent" ? "t-accent" : "t-strong"}`}>
                      {analysis.overallScore}
                    </span>
                    <span className="t-mono-sm">/ 100</span>
                  </div>
                  <span className={`status-pill ${SCORE_TONE(analysis.overallScore)}`}>{verdictFromScore(analysis.overallScore)}</span>
                </div>
              )}
            </section>
          )}
        </aside>
      </div>
    </>
  );
}

function AnalysisView({ analysis }: { analysis: AnalysisResult }) {
  return (
    <div className="stack-16">
      <div className="row-14" style={{ alignItems: "baseline" }}>
        <span className={`t-num-lg ${SCORE_TONE(analysis.overallScore) === "accent" ? "t-accent" : "t-strong"}`}>
          {analysis.overallScore}
        </span>
        <span className="t-mono">/ 100 · {verdictFromScore(analysis.overallScore)}</span>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: 10 }}>
        {analysis.bands.map((b) => (
          <div
            key={b.label}
            className="stack-6"
            style={{
              background: "var(--bg-2)",
              border: "1px solid var(--border-soft)",
              borderRadius: "var(--r-sm)",
              padding: 12,
            }}
          >
            <span className="t-label">{b.label}</span>
            <div className="row-8" style={{ alignItems: "baseline" }}>
              <span className={`t-num-sm ${SCORE_TONE(b.score) === "accent" ? "t-accent" : SCORE_TONE(b.score) === "err" ? "t-err" : "t-strong"}`}>{b.score}</span>
              <span className="t-mono-sm">/100</span>
            </div>
            <div className="exp-confidence-bar"><i style={{ width: `${b.score}%` }} /></div>
          </div>
        ))}
      </div>
      {analysis.highlights.length > 0 && (
        <div>
          <span className="t-eyebrow">highlights</span>
          <ul className="stack-4" style={{ paddingLeft: 18, margin: "6px 0" }}>
            {analysis.highlights.map((h, i) => (
              <li key={i} className="t-body-sm">{h}</li>
            ))}
          </ul>
        </div>
      )}
      {analysis.warnings.length > 0 && (
        <div>
          <span className="t-eyebrow t-warn">watch-outs</span>
          <ul className="stack-4" style={{ paddingLeft: 18, margin: "6px 0" }}>
            {analysis.warnings.map((w, i) => (
              <li key={i} className="t-body-sm t-warn">{w}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

function RenderBlock({ b }: { b: MarkdownBlock }) {
  if (b.kind === "h1") return <h1 className="t-display-sm" style={{ fontStyle: "normal" }}>{b.text}</h1>;
  if (b.kind === "h2") return <h2 className="t-h3-sans" style={{ marginTop: 4 }}>{b.text}</h2>;
  if (b.kind === "h3") return <h3 className="t-eyebrow" style={{ marginBottom: 0 }}>{b.text}</h3>;
  if (b.kind === "p") return <p className="t-body">{b.text}</p>;
  if (b.kind === "ul") {
    return (
      <ul className="stack-4" style={{ paddingLeft: 18, margin: 0 }}>
        {(b.items ?? []).map((it, i) => (<li key={i} className="t-body">{it}</li>))}
      </ul>
    );
  }
  if (b.kind === "kv") {
    return (
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: 10 }}>
        {(b.pairs ?? []).map(([k, v]) => (
          <div key={k} style={{ background: "var(--bg-2)", border: "1px solid var(--border-soft)", borderRadius: "var(--r-sm)", padding: 10 }}>
            <span className="t-label">{k}</span>
            <div className="t-mono">{v}</div>
          </div>
        ))}
      </div>
    );
  }
  return null;
}

function verdictFromScore(score: number): string {
  if (score >= 85) return "excellent";
  if (score >= 70) return "good";
  if (score >= 50) return "fair";
  if (score >= 30) return "poor";
  return "lost";
}

function Row({ k, v }: { k: string; v: string }) {
  return (
    <div className="row-between">
      <span className="t-label">{k}</span>
      <span className="t-mono">{v}</span>
    </div>
  );
}
