import { useEffect, useMemo, useState } from "react";
import {
  BUILDER_3D_MODELS,
  BUILDER_ALTERNATES,
  BUILDER_FIRMWARE,
  Chip,
  CloudSyncIndicator,
  HARDWARE_TIERS,
  KpiCard,
  PageHeader,
  PI_HEALTH,
  SegmentedControl,
  WiringDiagram,
  type BuilderTier,
} from "@sporeprint/design";

type Tab = "overview" | "shopping" | "models" | "wiring" | "firmware" | "setup";

const TIER_TABS: Tab[] = ["overview", "shopping", "models", "wiring", "firmware", "setup"];
const STORAGE_KEY = "pi:builder:setupProgress";

export function BuilderPage() {
  const [tierId, setTierId] = useState<BuilderTier["id"]>("recommended");
  const [tab, setTab] = useState<Tab>("overview");
  const [chambers, setChambers] = useState(1);
  const [completedSteps, setCompletedSteps] = useState<Record<string, boolean>>(() => {
    if (typeof window === "undefined") return {};
    try {
      const raw = window.localStorage.getItem(STORAGE_KEY);
      return raw ? (JSON.parse(raw) as Record<string, boolean>) : {};
    } catch {
      return {};
    }
  });

  const tier = HARDWARE_TIERS.find((t) => t.id === tierId)!;

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      window.localStorage.setItem(STORAGE_KEY, JSON.stringify(completedSteps));
    } catch {
      // ignore quota / private mode
    }
  }, [completedSteps]);

  function toggleStep(key: string) {
    setCompletedSteps((prev) => ({ ...prev, [key]: !prev[key] }));
  }

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>system</span>
          <span className="sep">/</span>
          <b className="accent">builder</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="Hardware"
        title="Builder"
        italic={false}
        meta={
          <span>
            3 reference builds · pre-wired BOMs · 8 printable enclosures · firmware tree · setup tracker
          </span>
        }
      />

      <div className="shell-body single">
        <main className="stack-22">
          <TierPicker tierId={tierId} onSelect={setTierId} />

          <ChamberMultiplier chambers={chambers} onChange={setChambers} />

          <SegmentedControl
            ariaLabel="builder section"
            value={tab}
            onChange={(t) => setTab(t)}
            options={TIER_TABS.map((t) => ({ value: t, label: t }))}
          />

          {tab === "overview" && <Overview tier={tier} />}
          {tab === "shopping" && <Shopping tier={tier} chambers={chambers} />}
          {tab === "models" && <Models />}
          {tab === "wiring" && <Wiring tier={tier} />}
          {tab === "firmware" && <Firmware tier={tier} />}
          {tab === "setup" && (
            <Setup
              tier={tier}
              completed={completedSteps}
              onToggle={toggleStep}
            />
          )}

          <Resources />
        </main>
      </div>
    </>
  );
}

function TierPicker({
  tierId,
  onSelect,
}: {
  tierId: BuilderTier["id"];
  onSelect: (id: BuilderTier["id"]) => void;
}) {
  return (
    <section className="card-grid three" aria-label="tier picker">
      {HARDWARE_TIERS.map((t) => {
        const active = t.id === tierId;
        return (
          <button
            key={t.id}
            type="button"
            onClick={() => onSelect(t.id)}
            className="card-cell"
            style={{
              appearance: "none",
              background: active ? "var(--accent-soft)" : "var(--bg-1)",
              borderColor: active ? "var(--accent-line)" : "var(--border-soft)",
              cursor: "pointer",
              textAlign: "left",
              color: "inherit",
              minHeight: 200,
            }}
          >
            <div className="card-head">
              <div className="title-block">
                <span className="t-eyebrow" style={{ marginBottom: 0 }}>
                  {t.tagline}
                </span>
                <h2 className="t-h3-sans">{t.name}</h2>
                <span className="t-mono-sm">
                  {t.componentCount} components · {t.estimatedCost}
                </span>
              </div>
              {active && <span className="status-pill accent">selected</span>}
            </div>
            <p className="t-body-sm" style={{ marginTop: "auto" }}>
              {t.bestFor}
            </p>
          </button>
        );
      })}
    </section>
  );
}

function ChamberMultiplier({
  chambers,
  onChange,
}: {
  chambers: number;
  onChange: (n: number) => void;
}) {
  const presets = [1, 2, 4, 6, 12];
  return (
    <section className="side-panel cluster" style={{ flexDirection: "row" }}>
      <span className="t-eyebrow" style={{ marginBottom: 0 }}>
        Chambers to build
      </span>
      <div className="cluster" role="group" aria-label="chambers">
        {presets.map((n) => (
          <Chip key={n} active={chambers === n} onClick={() => onChange(n)}>
            ×{n}
          </Chip>
        ))}
      </div>
      <span className="t-mono-sm" style={{ marginLeft: "auto" }}>
        cost calculator multiplies the BOM ·{" "}
        <span className="t-soft">shared parts (Pi, PSU)</span> are not duplicated
      </span>
    </section>
  );
}

function Overview({ tier }: { tier: BuilderTier }) {
  return (
    <section className="stack-18">
      <div className="kpi-grid">
        <KpiCard label="components" value={tier.componentCount.toString()} />
        <KpiCard label="est. cost" value={tier.estimatedCost} tone="accent" />
        <KpiCard label="firmware targets" value={tier.firmwareTargets.length.toString()} />
        <KpiCard label="setup steps" value={tier.setupSteps.length.toString()} />
      </div>

      <div className="side-panel">
        <div className="head">What you get</div>
        <ul
          className="t-body stack-8"
          style={{ paddingLeft: 20, margin: 0 }}
        >
          {tier.whatYouGet.map((line, i) => (
            <li key={i}>{line}</li>
          ))}
        </ul>
        <p className="t-mono-sm" style={{ marginTop: 6 }}>
          Best for · {tier.bestFor} · supports {tier.speciesSupport}
        </p>
      </div>

      <div className="card-grid">
        {tier.capabilityGroups.map((g) => (
          <article key={g.title} className="card-cell">
            <span className="t-eyebrow">{g.title}</span>
            <ul
              className="t-body stack-6"
              style={{ paddingLeft: 20, margin: 0 }}
            >
              {g.items.map((item, i) => (
                <li key={i}>{item}</li>
              ))}
            </ul>
          </article>
        ))}
      </div>

      {tier.limitations.length > 0 && (
        <div className="side-panel tone-warn">
          <div className="head t-warn">
            Limitations
          </div>
          <ul
            className="t-body stack-6"
            style={{ paddingLeft: 20, margin: 0 }}
          >
            {tier.limitations.map((lim, i) => (
              <li key={i}>{lim}</li>
            ))}
          </ul>
        </div>
      )}
    </section>
  );
}

function multiplyComponentQty(qty: number, chambers: number, isShared: boolean): number {
  if (isShared) return qty;
  return qty * chambers;
}

const SHARED_NAMES = new Set([
  "Raspberry Pi 5 (4GB)",
  "12V 5A Power Supply",
]);

function Shopping({ tier, chambers }: { tier: BuilderTier; chambers: number }) {
  const grouped = tier.components.reduce<Record<string, BuilderTier["components"]>>(
    (acc, c) => {
      if (!acc[c.category]) acc[c.category] = [];
      acc[c.category]!.push(c);
      return acc;
    },
    {},
  );

  const total = useMemo(() => {
    return tier.components.reduce((sum, c) => {
      const n = parseFloat(c.priceApprox.replace(/[^\d.]/g, ""));
      const qty = multiplyComponentQty(c.quantity, chambers, SHARED_NAMES.has(c.name));
      return sum + (Number.isFinite(n) ? n * qty : 0);
    }, 0);
  }, [tier, chambers]);

  return (
    <section className="stack-18">
      <div className="side-panel row-between" style={{ flexWrap: "wrap" }}>
        <div>
          <span className="t-eyebrow" style={{ marginBottom: 0 }}>
            Bill of materials · ×{chambers} chamber{chambers > 1 ? "s" : ""}
          </span>
          <p className="t-mono-sm" style={{ marginTop: 4 }}>
            shared infrastructure (Pi, PSU) does not duplicate ·{" "}
            <span className="t-soft">per-chamber</span> parts scale linearly
          </p>
        </div>
        <a className="t-btn-primary" href="/shopping">
          send BOM to /shopping →
        </a>
      </div>

      {Object.entries(grouped).map(([cat, items]) => (
        <div key={cat} className="stack-10">
          <span className="t-eyebrow">{cat}</span>
          <table className="data-table">
            <thead>
              <tr>
                <th scope="col">Component</th>
                <th scope="col">Role</th>
                <th scope="col" className="num">Qty</th>
                <th scope="col" className="num">~Price</th>
                <th scope="col" className="num">Buy</th>
              </tr>
            </thead>
            <tbody>
              {items.map((c, i) => {
                const isShared = SHARED_NAMES.has(c.name);
                const qty = multiplyComponentQty(c.quantity, chambers, isShared);
                return (
                  <tr key={`${cat}-${i}`}>
                    <td>
                      <a
                        href={c.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="t-link-body"
                      >
                        {c.name}
                      </a>
                      <div className="t-mono-sm" style={{ marginTop: 4 }}>
                        {c.notes}
                      </div>
                    </td>
                    <td>{c.role}</td>
                    <td className="num mono-cell">
                      ×{qty}
                      {isShared && chambers > 1 && (
                        <div className="t-mono-sm t-faint" style={{ marginTop: 2 }}>
                          (shared)
                        </div>
                      )}
                    </td>
                    <td className="num mono-cell">{c.priceApprox}</td>
                    <td className="num">
                      <a
                        href={c.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="t-link-cta"
                      >
                        buy →
                      </a>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      ))}

      <Substitutions tier={tier} />

      <div className="side-panel row-between-baseline">
        <span className="t-eyebrow" style={{ marginBottom: 0 }}>
          Estimated total · {chambers} chamber{chambers > 1 ? "s" : ""}
        </span>
        <span className="t-num">${total.toFixed(0)}</span>
      </div>
    </section>
  );
}

function Substitutions({ tier }: { tier: BuilderTier }) {
  const tierComponentNames = new Set(tier.components.map((c) => c.name));
  const relevant = BUILDER_ALTERNATES.filter((a) => tierComponentNames.has(a.forComponent));
  if (relevant.length === 0) return null;
  const grouped = relevant.reduce<Record<string, typeof BUILDER_ALTERNATES>>((acc, a) => {
    if (!acc[a.forComponent]) acc[a.forComponent] = [];
    acc[a.forComponent]!.push(a);
    return acc;
  }, {});

  return (
    <div className="side-panel">
      <div className="head">Substitutions</div>
      <p className="t-mono-sm" style={{ marginTop: -6 }}>
        cheaper or beefier alternatives · price/availability tradeoffs
      </p>
      <div className="stack-14">
        {Object.entries(grouped).map(([forComponent, alts]) => (
          <div key={forComponent} className="stack-8">
            <span className="t-eyebrow">in place of · {forComponent}</span>
            <table className="data-table compact">
              <thead>
                <tr>
                  <th scope="col">Alternate</th>
                  <th scope="col">Price</th>
                  <th scope="col">Tradeoff</th>
                  <th scope="col">Stock</th>
                  <th scope="col" className="num">Buy</th>
                </tr>
              </thead>
              <tbody>
                {alts.map((a, i) => (
                  <tr key={i}>
                    <td>
                      <a
                        href={a.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="t-link-body"
                      >
                        {a.name}
                      </a>
                    </td>
                    <td className="mono-cell">{a.priceApprox}</td>
                    <td>{a.tradeoff}</td>
                    <td>
                      <span
                        className={`status-pill ${
                          a.availability === "in-stock"
                            ? "accent"
                            : a.availability === "backorder"
                              ? "warn"
                              : "idle"
                        }`}
                      >
                        {a.availability}
                      </span>
                    </td>
                    <td className="num">
                      <a
                        href={a.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="t-link-cta"
                      >
                        buy →
                      </a>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ))}
      </div>
    </div>
  );
}

