function Firmware({ tier }: { tier: BuilderTier }) {
  const targetSet = new Set(tier.firmwareTargets);
  const nodes = BUILDER_FIRMWARE.filter((n) => targetSet.has(n.node));
  const otherNodes = BUILDER_FIRMWARE.filter((n) => !targetSet.has(n.node));

  return (
    <section className="stack-18">
      <div className="side-panel">
        <div className="head">Firmware tree</div>
        <div className="cluster">
          {tier.firmwareTargets.map((t) => (
            <span key={t} className="status-pill accent">
              {t}
            </span>
          ))}
        </div>
        <p className="t-body-sm" style={{ marginTop: 6 }}>
          Build with:{" "}
          <code className="t-mono-sm">pio run -t upload -e &lt;target&gt;</code> from{" "}
          <a
            href="https://github.com/59psi/SporePrint/tree/main/firmware"
            target="_blank"
            rel="noopener noreferrer"
            className="t-link-mono"
          >
            firmware/
          </a>
          .
        </p>
      </div>

      <div className="stack-14">
        {nodes.map((n) => (
          <FirmwareNodeCard key={n.node} node={n} included />
        ))}
      </div>

      {otherNodes.length > 0 && (
        <details>
          <summary
            className="t-eyebrow"
            style={{ cursor: "pointer", padding: "8px 0" }}
          >
            other targets · not in this tier ({otherNodes.length})
          </summary>
          <div className="stack-14" style={{ marginTop: 10 }}>
            {otherNodes.map((n) => (
              <FirmwareNodeCard key={n.node} node={n} included={false} />
            ))}
          </div>
        </details>
      )}
    </section>
  );
}

function FirmwareNodeCard({
  node,
  included,
}: {
  node: (typeof BUILDER_FIRMWARE)[number];
  included: boolean;
}) {
  return (
    <article
      className="card-cell"
      style={{
        gap: 12,
        opacity: included ? 1 : 0.7,
        borderColor: included ? "var(--accent-line)" : "var(--border-soft)",
      }}
    >
      <div className="card-head">
        <div className="title-block">
          <span className="t-eyebrow" style={{ marginBottom: 0 }}>
            firmware/src/{node.node}/
          </span>
          <h3 className="t-h3-sans">{node.node} node</h3>
          <span className="t-mono-sm">{node.description}</span>
        </div>
        <a
          href={node.bundleUrl}
          target="_blank"
          rel="noopener noreferrer"
          className="t-btn-primary"
        >
          ZIP bundle →
        </a>
      </div>
      <table className="data-table compact">
        <thead>
          <tr>
            <th scope="col">File</th>
            <th scope="col" className="num">Size</th>
            <th scope="col" className="num">Download</th>
          </tr>
        </thead>
        <tbody>
          {node.files.map((f) => (
            <tr key={f.filename}>
              <td className="mono-cell">{f.filename}</td>
              <td className="num mono-cell">{f.sizeKb.toFixed(1)} KB</td>
              <td className="num">
                <a
                  href={f.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="t-link-cta"
                >
                  raw →
                </a>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </article>
  );
}

function Setup({
  tier,
  completed,
  onToggle,
}: {
  tier: BuilderTier;
  completed: Record<string, boolean>;
  onToggle: (key: string) => void;
}) {
  const total = tier.setupSteps.length;
  const done = tier.setupSteps.filter((_, i) => completed[`${tier.id}:${i}`]).length;
  const pct = total > 0 ? Math.round((done / total) * 100) : 0;

  return (
    <section className="stack-18">
      <div className="side-panel row-between" style={{ flexWrap: "wrap" }}>
        <div>
          <span className="t-eyebrow" style={{ marginBottom: 0 }}>
            Setup progress
          </span>
          <p className="t-mono-sm" style={{ marginTop: 4 }}>
            {done} of {total} complete · saved locally on this Pi
          </p>
        </div>
        <span className="t-num">{pct}%</span>
      </div>

      <div
        style={{
          height: 6,
          background: "var(--bg-2)",
          borderRadius: "var(--r-pill)",
          overflow: "hidden",
        }}
        role="progressbar"
        aria-valuenow={pct}
        aria-valuemin={0}
        aria-valuemax={100}
      >
        <div
          style={{
            width: `${pct}%`,
            height: "100%",
            background: "var(--accent)",
            transition: "width var(--dur-base) var(--ease)",
          }}
        />
      </div>

      <ol className="stack-14" style={{ padding: 0, listStyle: "none" }}>
        {tier.setupSteps.map((step, i) => {
          const key = `${tier.id}:${i}`;
          const isDone = !!completed[key];
          return (
            <li
              key={key}
              className="side-panel"
              style={{
                flexDirection: "row",
                alignItems: "flex-start",
                gap: 18,
                cursor: "pointer",
                opacity: isDone ? 0.65 : 1,
              }}
              onClick={() => onToggle(key)}
            >
              <span
                className="t-mono-lg"
                style={{
                  flexShrink: 0,
                  width: 36,
                  height: 36,
                  borderRadius: "50%",
                  background: isDone ? "var(--accent-line)" : "var(--accent-soft)",
                  color: isDone ? "var(--bg-0)" : "var(--accent)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontWeight: 500,
                  border: isDone ? "none" : "1px solid var(--accent-line)",
                }}
                aria-hidden
              >
                {isDone ? "✓" : i + 1}
              </span>
              <p
                className="t-body"
                style={{
                  paddingTop: 6,
                  margin: 0,
                  textDecoration: isDone ? "line-through" : "none",
                }}
              >
                {step}
              </p>
            </li>
          );
        })}
      </ol>
    </section>
  );
}

