import type { FleetEvent } from "../data/types";

export function EventFeed({
  events,
  title = "Event Feed",
}: {
  events: FleetEvent[];
  title?: string;
}) {
  return (
    <div className="c-feed" aria-label={title}>
      <div className="head">
        <span>{title}</span>
        <span>local · 1Hz</span>
      </div>
      <div className="body">
        {events.map((e, i) => (
          <div key={`${e.ts}-${i}`} className="line">
            <span className="ts">{e.ts}</span>
            <span className={`tag ${e.cls ?? ""}`.trim()}>{e.tag}</span>
            <span className="msg">{e.msg}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
