"use client";

interface Opt<T extends string> { value: T; label: string }

export function SegmentedControl<T extends string>({
  options,
  value,
  onChange,
  ariaLabel,
}: {
  options: Opt<T>[];
  value: T;
  onChange: (v: T) => void;
  ariaLabel?: string;
}) {
  return (
    <div className="v-time-ranges" role="tablist" aria-label={ariaLabel}>
      {options.map((opt) => {
        const active = opt.value === value;
        return (
          <a
            key={opt.value}
            href={`#${opt.value}`}
            role="tab"
            aria-selected={active}
            className={active ? "active" : ""}
            onClick={(e) => { e.preventDefault(); onChange(opt.value); }}
          >
            {opt.label}
          </a>
        );
      })}
    </div>
  );
}
