import type { ReactNode } from "react";

interface Column<R> {
  key: string;
  header: string;
  align?: "left" | "right";
  render: (row: R) => ReactNode;
}

export function DataTable<R extends { id?: string | number }>({
  columns,
  rows,
  caption,
  rowKey,
  onRowClick,
  empty,
}: {
  columns: Column<R>[];
  rows: R[];
  caption?: string;
  rowKey?: (row: R) => string | number;
  onRowClick?: (row: R) => void;
  empty?: ReactNode;
}) {
  const getKey = rowKey ?? ((r: R) => (r.id ?? "") as string | number);
  if (rows.length === 0 && empty !== undefined) {
    return <>{empty}</>;
  }
  return (
    <table className="data-table">
      {caption && <caption className="t-eyebrow" style={{ textAlign: "left", marginBottom: 8 }}>{caption}</caption>}
      <thead>
        <tr>
          {columns.map((c) => (
            <th key={c.key} scope="col" className={c.align === "right" ? "num" : ""}>
              {c.header}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {rows.map((r) => (
          <tr
            key={getKey(r)}
            onClick={onRowClick ? () => onRowClick(r) : undefined}
            onKeyDown={onRowClick ? (e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); onRowClick(r); } } : undefined}
            tabIndex={onRowClick ? 0 : undefined}
            role={onRowClick ? "button" : undefined}
            style={onRowClick ? { cursor: "pointer" } : undefined}
          >
            {columns.map((c) => (
              <td key={c.key} className={c.align === "right" ? "num" : ""}>
                {c.render(r)}
              </td>
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  );
}
