"use client";

import type { Chamber, ChamberPhase, ChamberState } from "../data/types";
import { Logo } from "./Logo";

const STATE_CLASS: Record<ChamberState, string> = {
  active: "active",
  warn: "warn",
  err: "err",
  idle: "idle",
};

function phaseLabel(phase: ChamberPhase, day: { current: number; total: number }): string {
  if (day.total <= 0) return "idle";
  switch (phase) {
    case "fruiting": return `fruiting · day ${day.current}`;
    case "spawn":    return `spawn · d${day.current}/${day.total}`;
    case "harvest":  return `harvest · d${day.current}`;
    default:         return "idle";
  }
}

interface Props {
  chamber: Chamber;
  selected?: boolean;
  /** Pi UI shows `R{rack}·S{shelf}` on each tile (the Pi's superpower
   *  per pi-interface.md — physical position). */
  showRackPosition?: boolean;
  /** Larger tile variant for the Pi grid. */
  large?: boolean;
  /** Random pulse offset — 0..3s. Each tile picks one so the wall
   *  pulses asynchronously per components.md §3. */
  pulseOffsetSec?: number;
  onSelect?: (id: string) => void;
}

export function FleetTile({
  chamber,
  selected,
  showRackPosition,
  large,
  pulseOffsetSec = 0,
  onSelect,
}: Props) {
  const cls = ["f-tile", STATE_CLASS[chamber.state], selected ? "selected" : "", large ? "large" : ""]
    .filter(Boolean)
    .join(" ");
  const value = chamber.phase === "idle"
    ? "—"
    : `${Math.round(chamber.telemetry.humidity)}%`;

  return (
    <button
      type="button"
      className={cls}
      onClick={() => onSelect?.(chamber.id)}
      aria-pressed={selected}
      style={{ appearance: "none", textAlign: "left" }}
    >
      <span className="micro-mark">
        <Logo size={14} opts={{ baseDensity: 0.4, color: "currentColor" }} />
      </span>
      <div className="top">
        <span>{chamber.id}</span>
        {showRackPosition && (
          <span className="rack-pos">{`R${chamber.rack.rack}·S${chamber.rack.shelf}`}</span>
        )}
        <span
          className="dot"
          style={{ animationDelay: `-${pulseOffsetSec.toFixed(2)}s` }}
        />
      </div>
      <div className="species">{chamber.species.binomial}</div>
      <div className="met">
        <span className="k">{phaseLabel(chamber.phase, chamber.day)}</span>
        <strong>{value}</strong>
      </div>
      <div className="bar">
        <i style={{ width: `${chamber.progress}%`, display: "block", height: "100%" }} />
      </div>
    </button>
  );
}
