import { useState } from "react";
import { Link, useParams } from "react-router-dom";
import {
  ActuatorRow,
  CANONICAL_CHAMBER,
  ChamberHeroMark,
  CloudSyncIndicator,
  EventFeed,
  KvCluster,
  MetricReadout,
  Modal,
  PI_HEALTH,
  PI_LOCAL_FLEET,
  PageHeader,
  Sparkline,
  chamberHistory,
} from "@sporeprint/design";
import type { ActuatorKey, Actuators } from "@sporeprint/design";

interface Props {
  onBack: () => void;
  onHistory: (id: string) => void;
}

const DURATIONS = [
  { label: "5s", sec: 5 },
  { label: "10s", sec: 10 },
  { label: "30s", sec: 30 },
  { label: "1m", sec: 60 },
  { label: "5m", sec: 300 },
];

export function ChamberDetailPage({ onBack, onHistory }: Props) {
  const { id } = useParams();
  const chamber = PI_LOCAL_FLEET.find((c) => c.id === id) ?? PI_LOCAL_FLEET[0]!;
  const events = chamber.events.length > 0 ? chamber.events : CANONICAL_CHAMBER.events;
  const history = chamberHistory(chamber.id, 1);
  const [overrides, setOverrides] = useState<Actuators>(chamber.actuators);
  const [pendingOverride, setPendingOverride] = useState<ActuatorKey | null>(null);

  function applyOverride(key: ActuatorKey, sec: number) {
    const until = new Date(Date.now() + sec * 1000).toISOString();
    setOverrides((prev) => ({
      ...prev,
      [key]: {
        ...prev[key],
        on: !prev[key].on,
        sub: `override · ${sec}s`,
        override: { untilIso: until, durationSec: sec },
      },
    }));
    setPendingOverride(null);
  }

  function release(key: ActuatorKey) {
    setOverrides((prev) => ({
      ...prev,
      [key]: { ...chamber.actuators[key] },
    }));
  }

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <Link to="/" style={{ color: "inherit", textDecoration: "none" }}>chambers</Link>
          <span className="sep">/</span>
          <b className="accent">{chamber.id.toLowerCase()}</b>
        </nav>
        <div className="right">
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow={chamber.species.common}
        title={chamber.species.binomial}
        meta={
          <span>
            {chamber.id} · {chamber.phase} · day {chamber.day.current}/{chamber.day.total}
            {" · "}rack {chamber.rack.rack} shelf {chamber.rack.shelf}
            {" · "}fw {chamber.firmware}
          </span>
        }
        right={
          <button type="button" onClick={onBack} className="t-back-btn">
            ← back to fleet
          </button>
        }
      />

      <div className="shell-body pi">
        <main className="stack-24">
          <section
            style={{
              display: "grid",
              gridTemplateColumns: "1fr auto 1fr",
              gap: 32,
              alignItems: "center",
              padding: "12px 0",
            }}
          >
            <div className="stack-18">
              <MetricReadout
                label="Temperature"
                value={chamber.telemetry.tempF.toFixed(1)}
                unit="°F"
              />
              <MetricReadout
                label="Humidity · adjusting"
                value={Math.round(chamber.telemetry.humidity).toString()}
                unit="%"
                sub="mister on · 0.4s burst"
                variant="accent"
              />
            </div>
            <ChamberHeroMark display={chamber.display} />
            <div className="stack-18" style={{ textAlign: "right" }}>
              <MetricReadout
                label="CO₂"
                value={Math.round(chamber.telemetry.co2).toString()}
                unit="ppm"
                sub="fae · 04/12"
              />
              <MetricReadout
                label="VPD"
                value={chamber.telemetry.vpdKpa.toFixed(2)}
                unit="kPa"
                variant="signal"
              />
            </div>
          </section>

          <KvCluster t={chamber.telemetry} accent="humidity" />

          <ActuatorRow
            actuators={overrides}
            editable
            onOverride={(key) => {
              if (overrides[key].override) release(key);
              else setPendingOverride(key);
            }}
          />

          <Modal
            open={!!pendingOverride}
            onClose={() => setPendingOverride(null)}
            title={`Override · ${pendingOverride ?? ""}`}
          >
            <p className="t-body">
              Pin actuator state for a fixed duration. Rule automation is suspended for the window.
            </p>
            <div className="cluster">
              {DURATIONS.map((d) => (
                <button
                  key={d.label}
                  type="button"
                  onClick={() => pendingOverride && applyOverride(pendingOverride, d.sec)}
                  className="override-btn t-accent"
                  style={{ borderColor: "var(--accent-line)" }}
                >
                  {d.label}
                </button>
              ))}
              <button
                type="button"
                onClick={() => setPendingOverride(null)}
                className="override-btn"
                style={{ marginLeft: "auto" }}
              >
                cancel
              </button>
            </div>
          </Modal>
        </main>

        <aside className="stack-14">
          <section className="side-panel">
            <div className="head">Live event feed</div>
            <EventFeed events={events} title="" />
          </section>
          <section className="side-panel">
            <div className="head">Last hour</div>
            <Sparkline channel="temp" trace={history.temp} label="temp" display={chamber.telemetry.tempF.toFixed(1)} />
            <Sparkline channel="hum" trace={history.hum} label="hum" display={Math.round(chamber.telemetry.humidity).toString()} />
            <Sparkline channel="co2" trace={history.co2} label="co₂" display={Math.round(chamber.telemetry.co2).toString()} />
            <button type="button" onClick={() => onHistory(chamber.id)} className="t-link-cta">
              view 24h →
            </button>
          </section>
        </aside>
      </div>
    </>
  );
}
