import type { PiHealth } from "../data/types";

function pctClass(pct: number, type: "cpu" | "mem" | "disk") {
  void type;
  if (pct > 90) return "err";
  if (pct >= 70) return "warn";
  return "ok";
}

function tempClass(c: number) {
  if (c > 75) return "err";
  if (c >= 60) return "warn";
  return "ok";
}

function uplinkBadge(h: PiHealth["uplink"]) {
  if (h.kind === "offline") return { label: "offline", cls: "err" as const, dot: "err" };
  if (h.kind === "ethernet") return { label: "ethernet", cls: "ok" as const, dot: "signal" };
  if (h.signal !== undefined && h.signal < 40) return { label: "wifi", cls: "warn" as const, dot: "warn" };
  return { label: "wifi", cls: "ok" as const, dot: "signal" };
}

function cloudBadge(h: PiHealth["cloud"]) {
  if (h.state === "synced") return { label: "synced", cls: "ok" as const, dot: "accent" };
  if (h.state === "syncing") return { label: `syncing · ${h.pending} pending`, cls: "warn" as const, dot: "warn" };
  return { label: `offline · ${h.pending} pending`, cls: "err" as const, dot: "err" };
}

export function PiHealthPanel({ health }: { health: PiHealth }) {
  const cpu = pctClass(health.cpuPct, "cpu");
  const mem = pctClass(health.memPct, "mem");
  const disk = pctClass(health.diskPct, "disk");
  const temp = tempClass(health.tempC);
  const uplink = uplinkBadge(health.uplink);
  const cloud = cloudBadge(health.cloud);
  return (
    <div className="pi-health" aria-label="Pi system health">
      <div className="pi-head">Pi system</div>
      <Row k="cpu" cls={cpu} value={health.cpuPct.toString()} unit="%" />
      <Row k="mem" cls={mem} value={health.memPct.toString()} unit="%" />
      <Row k="disk" cls={disk} value={health.diskPct.toString()} unit="%" />
      <Row k="temp" cls={temp} value={health.tempC.toString()} unit="°C" />
      <Row k="uplink" cls={uplink.cls} value={uplink.label} dot={uplink.dot} />
      <Row k="cloud" cls={cloud.cls} value={cloud.label} dot={cloud.dot} />
    </div>
  );
}

function Row({
  k,
  cls,
  value,
  unit,
  dot,
}: {
  k: string;
  cls: "ok" | "warn" | "err";
  value: string;
  unit?: string;
  dot?: string;
}) {
  return (
    <div className="pi-row">
      <span className="k">{k}</span>
      <span className={`v ${cls}`}>
        {dot && <span className={`dot ${dot}`} />}
        <span>{value}</span>
        {unit && <span className="u">{unit}</span>}
      </span>
    </div>
  );
}
