import { useMemo, useState } from "react";
import {
  CloudSyncIndicator,
  Modal,
  PageHeader,
  PI_HEALTH,
  PI_NOTIFICATION_TYPES,
  PI_SYSTEM_INFO,
  SegmentedControl,
  TIMEZONES,
  WIFI_NETWORKS,
} from "@sporeprint/design";
import type { NotificationToggle, WifiNetwork } from "@sporeprint/design";

type TempUnit = "f" | "c";
type WeightUnit = "lb" | "kg";
type ClockFormat = "12h" | "24h";

type ConfirmAction = null | "mqtt" | "reboot" | "factory";

function formatBytes(gb: number): string {
  return `${gb.toFixed(1)} GB`;
}

export function SettingsPage() {
  // Hostname
  const [hostnameDraft, setHostnameDraft] = useState(PI_HEALTH.hostname);
  const hostnameDirty = hostnameDraft.trim() !== PI_HEALTH.hostname;

  // WiFi
  const [activeWifi, setActiveWifi] = useState<WifiNetwork>(
    () => WIFI_NETWORKS.find((n) => n.connected) ?? WIFI_NETWORKS[0]!,
  );
  const [pendingWifi, setPendingWifi] = useState<WifiNetwork | null>(null);
  const [wifiPassword, setWifiPassword] = useState("");
  const [wifiBusy, setWifiBusy] = useState(false);

  // Timezone
  const [timezone, setTimezone] = useState("America/Los_Angeles");

  // Units
  const [tempUnit, setTempUnit] = useState<TempUnit>("f");
  const [weightUnit, setWeightUnit] = useState<WeightUnit>("lb");
  const [clockFormat, setClockFormat] = useState<ClockFormat>("24h");

  // BYOK
  const [byokDraft, setByokDraft] = useState("");
  const [byokSaved, setByokSaved] = useState("sk-ant-…3e9f");
  const [byokTesting, setByokTesting] = useState(false);
  const [byokTestResult, setByokTestResult] = useState<null | "ok" | "err">(null);

  // OTA verify key — base64-encoded raw 32-byte Ed25519 public key.
  // Pasted by the operator after running scripts/generate-ota-keypair.py
  // on a release-signing host. Empty = OTA disabled (Pi fail-closed).
  const [otaKeyDraft, setOtaKeyDraft] = useState("");
  const [otaKeySaved, setOtaKeySaved] = useState("");
  const [otaKeyError, setOtaKeyError] = useState<string | null>(null);

  // ntfy
  const [ntfyDraft, setNtfyDraft] = useState("https://ntfy.sh/sporeprint-lab");
  const [ntfyOriginal] = useState("https://ntfy.sh/sporeprint-lab");
  const ntfyDirty = ntfyDraft !== ntfyOriginal;

  // Quiet hours
  const [quietStart, setQuietStart] = useState("22:00");
  const [quietEnd, setQuietEnd] = useState("06:30");
  const [criticalOptIn, setCriticalOptIn] = useState(false);

  // Per-notification toggles
  const [notifPrefs, setNotifPrefs] = useState<Record<string, boolean>>(() =>
    Object.fromEntries(PI_NOTIFICATION_TYPES.map((n) => [n.id, n.defaultOn])),
  );

  // Confirm dialog (destructive actions)
  const [confirm, setConfirm] = useState<ConfirmAction>(null);

  // Group notifications by category
  const notifGrouped = useMemo(() => {
    const out: Record<string, NotificationToggle[]> = {};
    PI_NOTIFICATION_TYPES.forEach((n) => {
      (out[n.category] ??= []).push(n);
    });
    return out;
  }, []);

  function saveHostname() {
    // Stub — would POST /settings/hostname
    void hostnameDraft;
  }

  function startWifiConnect(net: WifiNetwork) {
    if (net.ssid === activeWifi.ssid) return;
    setPendingWifi(net);
    setWifiPassword("");
  }

  function cancelWifiConnect() {
    setPendingWifi(null);
    setWifiPassword("");
  }

  function confirmWifiConnect() {
    if (!pendingWifi) return;
    setWifiBusy(true);
    // Stub: simulate handshake completion immediately for the demo path.
    setTimeout(() => {
      setActiveWifi({ ...pendingWifi, connected: true });
      setPendingWifi(null);
      setWifiPassword("");
      setWifiBusy(false);
    }, 250);
  }

  function saveByok() {
    if (!byokDraft.trim()) return;
    setByokSaved(`${byokDraft.slice(0, 6)}…${byokDraft.slice(-4)}`);
    setByokDraft("");
    setByokTestResult(null);
  }

  function testByok() {
    setByokTesting(true);
    setByokTestResult(null);
    setTimeout(() => {
      setByokTesting(false);
      setByokTestResult("ok");
    }, 350);
  }

  function clearByok() {
    setByokSaved("");
    setByokTestResult(null);
  }

  /** Validate an OTA pubkey before persisting — must decode as base64
   *  to exactly 32 raw Ed25519 bytes. Bad input is rejected with a
   *  user-readable message instead of silently saving garbage. */
  function saveOtaKey() {
    setOtaKeyError(null);
    const trimmed = otaKeyDraft.trim();
    if (!trimmed) {
      setOtaKeyError("paste the base64 public key first");
      return;
    }
    let decoded: Uint8Array;
    try {
      const bin = atob(trimmed);
      decoded = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) decoded[i] = bin.charCodeAt(i);
    } catch {
      setOtaKeyError("not valid base64");
      return;
    }
    if (decoded.length !== 32) {
      setOtaKeyError(`must decode to 32 bytes (got ${decoded.length})`);
      return;
    }
    setOtaKeySaved(trimmed);
    setOtaKeyDraft("");
  }

  function clearOtaKey() {
    setOtaKeySaved("");
    setOtaKeyError(null);
  }

  function downloadBackup() {
    // Stub — would assemble a JSON config bundle
  }

  function executeConfirm() {
    // Stub — would invoke POST /system/{action}
    setConfirm(null);
  }

  return (
    <>
      <div className="app-top no-brand">
        <nav className="bc" aria-label="breadcrumb">
          <span>system</span>
          <span className="sep">/</span>
          <b className="accent">settings</b>
        </nav>
        <div className="right">
          <span className="host-pill">
            {PI_HEALTH.hostname}
            <span className="mut">· {PI_HEALTH.ip}</span>
          </span>
          <CloudSyncIndicator cloud={PI_HEALTH.cloud} />
        </div>
      </div>

      <PageHeader
        eyebrow="System"
        title="Settings"
        italic={false}
        meta={
          <span>
            local Pi-only preferences · Pi {PI_SYSTEM_INFO.appVersion} · uptime {PI_SYSTEM_INFO.uptimeHuman}
          </span>
        }
      />

      <div className="shell-body single">
        <main className="stack-22">
          {/* ---------- Network ---------- */}
          <section className="settings-group" aria-label="Network">
            <div className="group-head">Network</div>

            <div className="settings-row">
              <span className="label">
                <span className="name">Hostname</span>
                <span className="desc">advertised over mDNS as {hostnameDraft}.local</span>
              </span>
              <div className="row-8">
                <input
                  className="t-input"
                  value={hostnameDraft}
                  onChange={(e) => setHostnameDraft(e.target.value)}
                  spellCheck={false}
                  style={{ width: 220 }}
                />
                <button
                  type="button"
                  className="t-btn-primary"
                  disabled={!hostnameDirty}
                  onClick={saveHostname}
                >
                  save
                </button>
              </div>
            </div>

            <div className="settings-row">
              <span className="label">
                <span className="name">IP address</span>
                <span className="desc">LAN address — falls back if mDNS misses</span>
              </span>
              <span className="value">{PI_HEALTH.ip}</span>
            </div>

            <div className="settings-row">
              <span className="label">
                <span className="name">WiFi networks</span>
                <span className="desc">
                  connected · <span className="accent">{activeWifi.ssid}</span> · {activeWifi.signal}%
                </span>
              </span>
              <span className="value">{activeWifi.secured ? "wpa2" : "open"}</span>
            </div>

            {/* WiFi list — embed within the settings group as a sub-card. */}
            <div style={{ padding: "0 22px 18px" }}>
              <div
                style={{
                  border: "1px solid var(--border-soft)",
                  borderRadius: "var(--r-md)",
                  overflow: "hidden",
                }}
              >
                {WIFI_NETWORKS.map((net, idx) => {
                  const isActive = net.ssid === activeWifi.ssid;
                  return (
                    <div
                      key={net.ssid}
                      style={{
                        display: "grid",
                        gridTemplateColumns: "1fr auto auto auto",
                        gap: 14,
                        alignItems: "center",
                        padding: "12px 16px",
                        borderTop: idx === 0 ? "none" : "1px solid var(--border-soft)",
                        background: isActive ? "var(--bg-2)" : "transparent",
                      }}
                    >
                      <span className="t-mono" style={{ color: isActive ? "var(--accent)" : "var(--text-1)" }}>
                        {net.ssid}
                      </span>
                      <span className="t-meta">{net.secured ? "wpa2" : "open"}</span>
                      <SignalBars signal={net.signal} />
                      {isActive ? (
                        <span className="status-pill signal">connected</span>
                      ) : (
                        <button
                          type="button"
                          className="t-link-mono"
                          onClick={() => startWifiConnect(net)}
                        >
                          connect
                        </button>
                      )}
                    </div>
                  );
                })}
              </div>

              <Modal
                open={!!pendingWifi}
                onClose={cancelWifiConnect}
                title={pendingWifi ? `connect · ${pendingWifi.ssid}` : "connect"}
              >
                {pendingWifi?.secured ? (
                  <input
                    className="t-input"
                    type="password"
                    autoFocus
                    placeholder="password"
                    value={wifiPassword}
                    onChange={(e) => setWifiPassword(e.target.value)}
                  />
                ) : (
                  <p className="t-body">open network · no password required</p>
                )}
                <div className="row-8">
                  <button
                    type="button"
                    className="t-btn-primary"
                    onClick={confirmWifiConnect}
                    disabled={wifiBusy || (!!pendingWifi?.secured && wifiPassword.length < 8)}
                  >
                    {wifiBusy ? "connecting…" : "connect"}
                  </button>
                  <button type="button" className="t-back-btn" onClick={cancelWifiConnect}>
                    cancel
                  </button>
                </div>
              </Modal>
            </div>

            <div className="settings-row">
              <span className="label">
                <span className="name">Cloud claim</span>
                <span className="desc">paired · brandon@brandonbianchi.com — manage in cloud app</span>
              </span>
              <span className="value">paired</span>
            </div>
          </section>

          {/* ---------- Display ---------- */}
          <section className="settings-group" aria-label="Display and units">
            <div className="group-head">Display</div>

            <div className="settings-row">
              <span className="label">
                <span className="name">Time zone</span>
                <span className="desc">used for cycle scheduling + event timestamps</span>
              </span>
              <select
                className="t-input"
                value={timezone}
                onChange={(e) => setTimezone(e.target.value)}
                style={{ width: 280 }}
              >
                {TIMEZONES.map((tz) => (
                  <option key={tz.id} value={tz.id}>
                    {tz.label}
                  </option>
                ))}
              </select>
            </div>

            <div className="settings-row">
              <span className="label">
                <span className="name">Temperature</span>
                <span className="desc">applies to all telemetry, history, and CSV exports</span>
              </span>
              <SegmentedToggle
                value={tempUnit}
                onChange={setTempUnit}
                options={[
                  { id: "f", label: "°F" },
                  { id: "c", label: "°C" },
                ]}
              />
            </div>

            <div className="settings-row">
              <span className="label">
                <span className="name">Weight</span>
                <span className="desc">harvest log + experiment yields</span>
              </span>
              <SegmentedToggle
                value={weightUnit}
                onChange={setWeightUnit}
                options={[
                  { id: "lb", label: "lb" },
                  { id: "kg", label: "kg" },
                ]}
              />
            </div>

            <div className="settings-row">
              <span className="label">
                <span className="name">Clock format</span>
                <span className="desc">timestamps and cycle schedules</span>
              </span>
              <SegmentedToggle
                value={clockFormat}
                onChange={setClockFormat}
                options={[
                  { id: "12h", label: "12-hour" },
                  { id: "24h", label: "24-hour" },
                ]}
              />
            </div>

            <ToggleRow
              name="Reduced motion"
              desc="cuts breathing gradient + tile pulse — kinder under fluorescent lab light"
            />
          </section>

          {/* ---------- Local AI ---------- */}
          <section className="settings-group" aria-label="Local AI keys">
            <div className="group-head">Local AI · BYOK</div>

            <div className="settings-row">
              <span className="label">
                <span className="name">Anthropic API key</span>
                <span className="desc">
                  unlimited Vision + Advisor calls without round-tripping cloud · key stays on this Pi
                </span>
              </span>
              <span className="value">{byokSaved || "—"}</span>
            </div>

            <div className="stack-10" style={{ padding: "0 22px 18px" }}>
              <input
                className="t-input"
                type="password"
                placeholder="sk-ant-……"
                value={byokDraft}
                onChange={(e) => setByokDraft(e.target.value)}
                spellCheck={false}
              />
              <div className="cluster">
                <button
                  type="button"
                  className="t-btn-primary"
                  onClick={saveByok}
                  disabled={!byokDraft.trim()}
                >
                  save key
                </button>
                <button
                  type="button"
                  className="t-back-btn"
                  onClick={testByok}
                  disabled={!byokSaved || byokTesting}
                >
                  {byokTesting ? "testing…" : "test connection"}
                </button>
                <button
                  type="button"
                  className="t-back-btn"
                  onClick={clearByok}
                  disabled={!byokSaved}
                >
                  remove
                </button>
                {byokTestResult === "ok" && (
                  <span className="status-pill signal" style={{ alignSelf: "center" }}>
                    ok · 220ms
                  </span>
                )}
                {byokTestResult === "err" && (
                  <span className="status-pill err" style={{ alignSelf: "center" }}>
                    failed · invalid key
                  </span>
                )}
              </div>
            </div>

            <ToggleRow
              name="On-Pi vision"
              desc="run contamination check locally instead of cloud"
              defaultChecked
            />
            <ToggleRow
              name="On-Pi advisor"
              desc="answer questions about chambers without cloud round-trip"
              defaultChecked
            />
          </section>

          {/* ---------- OTA verify key ---------- */}
          <section className="settings-group" aria-label="OTA verify key">
            <div className="group-head">OTA Updates</div>

            <div className="settings-row">
              <span className="label">
                <span className="name">OTA verify key</span>
                <span className="desc">
                  base64-encoded raw 32-byte Ed25519 public key · empty = OTA
                  disabled (fail-closed) · generate with{" "}
                  <span className="t-mono">scripts/generate-ota-keypair.py</span>
                </span>
              </span>
              <span
                className="value"
                style={{
                  fontFamily: "var(--f-mono)",
                  fontSize: 12,
                  wordBreak: "break-all",
                  maxWidth: 300,
                }}
              >
                {otaKeySaved || "—"}
              </span>
            </div>

            <div className="stack-10" style={{ padding: "0 22px 18px" }}>
              <input
                className="t-input"
                type="text"
                placeholder="paste base64 public key (44 chars)"
                value={otaKeyDraft}
                onChange={(e) => setOtaKeyDraft(e.target.value)}
                spellCheck={false}
                autoCorrect="off"
                style={{ fontFamily: "var(--f-mono)", fontSize: 12 }}
              />
              <div className="cluster">
                <button
                  type="button"
                  className="t-btn-primary"
                  onClick={saveOtaKey}
                  disabled={!otaKeyDraft.trim()}
                >
                  save key
                </button>
                <button
                  type="button"
                  className="t-back-btn"
                  onClick={clearOtaKey}
                  disabled={!otaKeySaved}
                >
                  remove
                </button>
                {otaKeyError && (
                  <span className="status-pill err" style={{ alignSelf: "center" }}>
                    {otaKeyError}
                  </span>
                )}
                {!otaKeyError && otaKeySaved && (
                  <span className="status-pill signal" style={{ alignSelf: "center" }}>
                    OTA enabled
                  </span>
                )}
                {!otaKeySaved && !otaKeyError && (
                  <span className="status-pill warn" style={{ alignSelf: "center" }}>
                    OTA disabled
                  </span>
                )}
              </div>
              <p className="t-mono-sm">
                Public keys are not secrets — paste the value generated by the
                signing-host ceremony. The matching private key signs every
                release bundle and must stay offline.
              </p>
            </div>
          </section>

          {/* ---------- Notifications ---------- */}
          <section className="settings-group" aria-label="Notifications">
            <div className="group-head">Notifications</div>

            <div className="settings-row">
              <span className="label">
                <span className="name">ntfy fallback URL</span>
                <span className="desc">Pi pushes here if cloud is offline — works on LAN-only Pis</span>
              </span>
              <div className="row-8">
                <input
                  className="t-input"
                  value={ntfyDraft}
                  onChange={(e) => setNtfyDraft(e.target.value)}
                  spellCheck={false}
                  style={{ width: 320 }}
                />
                <button
                  type="button"
                  className="t-btn-primary"
                  disabled={!ntfyDirty}
                  onClick={() => void 0}
                >
                  save
                </button>
              </div>
            </div>

            <div className="settings-row">
              <span className="label">
                <span className="name">Quiet hours</span>
                <span className="desc">no push, ntfy, or critical-channel alerts during this window</span>
              </span>
              <div className="row-8">
                <input
                  className="t-input"
                  type="time"
                  value={quietStart}
                  onChange={(e) => setQuietStart(e.target.value)}
                  style={{ width: 110 }}
                />
                <span className="t-meta">→</span>
                <input
                  className="t-input"
                  type="time"
                  value={quietEnd}
                  onChange={(e) => setQuietEnd(e.target.value)}
                  style={{ width: 110 }}
                />
              </div>
            </div>

            <ToggleRow
              name="Critical alerts opt-in"
              desc="bypasses quiet hours + Do-Not-Disturb on iOS for chamber-loss-risk events"
              checked={criticalOptIn}
              onChange={setCriticalOptIn}
            />

            <div style={{ padding: "0 22px 18px" }}>
              {Object.entries(notifGrouped).map(([cat, items]) => (
                <div key={cat} style={{ marginTop: 10 }}>
                  <div className="t-eyebrow" style={{ padding: "10px 0 6px" }}>
                    {cat}
                  </div>
                  <div
                    style={{
                      border: "1px solid var(--border-soft)",
                      borderRadius: "var(--r-md)",
                      overflow: "hidden",
                    }}
                  >
                    {items.map((n, idx) => (
                      <label
                        key={n.id}
                        className="settings-row"
                        style={{
                          borderTop: idx === 0 ? "none" : "1px solid var(--border-soft)",
                          padding: "14px 18px",
                          cursor: "pointer",
                        }}
                      >
                        <span className="label">
                          <span className="name">{n.label}</span>
                          <span className="desc">{n.description}</span>
                        </span>
                        <input
                          type="checkbox"
                          className="toggle"
                          checked={notifPrefs[n.id] ?? false}
                          onChange={(e) =>
                            setNotifPrefs((prev) => ({ ...prev, [n.id]: e.target.checked }))
                          }
                        />
                      </label>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* ---------- Backup / Restore ---------- */}
          <section className="settings-group" aria-label="Backup and restore">
            <div className="group-head">Backup · Restore</div>
            <div className="settings-row">
              <span className="label">
                <span className="name">Download config snapshot</span>
                <span className="desc">all Pi-local settings, automation rules, BYOK key (encrypted)</span>
              </span>
              <button type="button" className="t-btn-primary" onClick={downloadBackup}>
                download .json
              </button>
            </div>
            <div className="settings-row">
              <span className="label">
                <span className="name">Restore from snapshot</span>
                <span className="desc">overwrites current settings — chamber telemetry is preserved</span>
              </span>
              <label className="t-back-btn" style={{ cursor: "pointer" }}>
                <input type="file" accept="application/json" hidden />
                upload .json
              </label>
            </div>
          </section>

          {/* ---------- System ---------- */}
          <section className="settings-group" aria-label="System">
            <div className="group-head">System</div>
            <div className="settings-row">
              <span className="label">
                <span className="name">Restart MQTT broker</span>
                <span className="desc">useful after gateway changes · ESP32 nodes auto-reconnect</span>
              </span>
              <button type="button" className="t-back-btn" onClick={() => setConfirm("mqtt")}>
                restart broker
              </button>
            </div>
            <div className="settings-row">
              <span className="label">
                <span className="name">Restart Pi</span>
                <span className="desc">reboots the device · ~45s downtime · automation pauses then resumes</span>
              </span>
              <button
                type="button"
                className="t-back-btn t-warn"
                onClick={() => setConfirm("reboot")}
                style={{ borderColor: "var(--warn)" }}
              >
                reboot Pi
              </button>
            </div>
            <div className="settings-row">
              <span className="label">
                <span className="name">Factory reset</span>
                <span className="desc">erases all Pi-local config · paired chamber claims must be redone in cloud</span>
              </span>
              <button
                type="button"
                className="t-back-btn t-err"
                onClick={() => setConfirm("factory")}
                style={{ borderColor: "var(--err)" }}
              >
                factory reset
              </button>
            </div>
          </section>

          {/* ---------- About ---------- */}
          <section className="settings-group" aria-label="About">
            <div className="group-head">About</div>
            <KvRow name="Pi LAN UI version" value={PI_SYSTEM_INFO.appVersion} desc="this build" />
            <KvRow name="Firmware" value={`v${PI_HEALTH.firmwareVersion}`} desc="Pi-side service version" />
            <KvRow
              name="Hardware"
              value={PI_SYSTEM_INFO.hostHardware}
              desc={`serial ${PI_SYSTEM_INFO.serial}`}
            />
            <KvRow name="OS" value={PI_SYSTEM_INFO.os} desc={PI_SYSTEM_INFO.kernel} />
            <KvRow
              name="Runtime"
              value={`Python ${PI_SYSTEM_INFO.pythonVersion}`}
              desc={`Docker ${PI_SYSTEM_INFO.dockerVersion}`}
            />
            <KvRow
              name="Disk"
              value={`${formatBytes(PI_SYSTEM_INFO.diskUsedGb)} / ${formatBytes(PI_SYSTEM_INFO.diskTotalGb)}`}
            />
            <KvRow name="First boot" value={PI_SYSTEM_INFO.firstBoot.replace("T", " ").replace("Z", " UTC")} />
            <KvRow name="Last reboot" value={PI_SYSTEM_INFO.lastReboot.replace("T", " ").replace("Z", " UTC")} />
            <KvRow name="Uptime" value={PI_SYSTEM_INFO.uptimeHuman} />
          </section>
        </main>
      </div>

      {/* ---------- Confirm dialog (destructive ops) ---------- */}
      {confirm && (
        <ConfirmDialog action={confirm} onCancel={() => setConfirm(null)} onConfirm={executeConfirm} />
      )}
    </>
  );
}

// ---------- Helpers ----------

function ToggleRow({
  name,
  desc,
  defaultChecked,
  checked,
  onChange,
}: {
  name: string;
  desc?: string;
  defaultChecked?: boolean;
  checked?: boolean;
  onChange?: (next: boolean) => void;
}) {
  return (
    <label className="settings-row" style={{ cursor: "pointer" }}>
      <span className="label">
        <span className="name">{name}</span>
        {desc && <span className="desc">{desc}</span>}
      </span>
      {onChange ? (
        <input
          type="checkbox"
          className="toggle"
          checked={checked ?? false}
          onChange={(e) => onChange(e.target.checked)}
        />
      ) : (
        <input type="checkbox" className="toggle" defaultChecked={defaultChecked} />
      )}
    </label>
  );
}

function KvRow({ name, value, desc }: { name: string; value: string; desc?: string }) {
  return (
    <div className="settings-row">
      <span className="label">
        <span className="name">{name}</span>
        {desc && <span className="desc">{desc}</span>}
      </span>
      <span className="value">{value}</span>
    </div>
  );
}

function SegmentedToggle<T extends string>({
  value,
  onChange,
  options,
}: {
  value: T;
  onChange: (next: T) => void;
  options: Array<{ id: T; label: string }>;
}) {
  return (
    <SegmentedControl
      value={value}
      onChange={onChange}
      options={options.map((o) => ({ value: o.id, label: o.label }))}
    />
  );
}

function SignalBars({ signal }: { signal: number }) {
  const bars = [1, 2, 3, 4];
  const lit = Math.ceil((signal / 100) * 4);
  return (
    <span style={{ display: "inline-flex", alignItems: "flex-end", gap: 2 }} aria-label={`signal ${signal}%`}>
      {bars.map((b) => (
        <span
          key={b}
          style={{
            display: "inline-block",
            width: 3,
            height: 4 + b * 2,
            background: b <= lit ? "var(--signal)" : "var(--text-3)",
            opacity: b <= lit ? 1 : 0.4,
            borderRadius: 1,
          }}
        />
      ))}
      <span className="t-meta" style={{ marginLeft: 6 }}>
        {signal}%
      </span>
    </span>
  );
}

function ConfirmDialog({
  action,
  onCancel,
  onConfirm,
}: {
  action: ConfirmAction;
  onCancel: () => void;
  onConfirm: () => void;
}) {
  const copy = action ? {
    mqtt: {
      title: "Restart MQTT broker?",
      body: "Chambers reconnect within ~5 seconds. Cycles in flight may pause briefly.",
      verb: "restart broker",
      btnTone: "var(--accent)",
    },
    reboot: {
      title: "Reboot Pi?",
      body: "About 45 seconds of downtime. Automation rules resume on boot.",
      verb: "reboot",
      btnTone: "var(--warn)",
    },
    factory: {
      title: "Factory reset this Pi?",
      body: "Wipes hostname, WiFi, BYOK key, automation rules, and pairing claims. Telemetry history is preserved on disk but the cloud will need to re-pair this Pi. There is no undo.",
      verb: "factory reset",
      btnTone: "var(--err)",
    },
  }[action] : null;

  return (
    <Modal
      open={!!action && !!copy}
      onClose={onCancel}
      title={copy?.title ?? ""}
    >
      {copy && (
        <>
          <p className="t-body">{copy.body}</p>
          <div className="row-8" style={{ justifyContent: "flex-end" }}>
            <button type="button" className="t-back-btn" onClick={onCancel}>
              cancel
            </button>
            <button
              type="button"
              className="t-btn-primary"
              onClick={onConfirm}
              style={{
                background: action === "factory" ? "rgba(184, 100, 92, 0.15)" : undefined,
                borderColor: copy.btnTone,
                color: copy.btnTone,
              }}
            >
              {copy.verb}
            </button>
          </div>
        </>
      )}
    </Modal>
  );
}
